# ===================== DATABASE CONFIG =====================
# For Railway/cloud deployment - uses PostgreSQL for permanent storage
# Set DATABASE_URL environment variable to enable database mode
DATABASE_URL = os.environ.get("DATABASE_URL")
db_pool = None  # Global database connection pool
USE_DATABASE = False  # Will be set to True if database connects successfully.


async def init_database():
    """Initialize PostgreSQL database connection and create tables"""
    global db_pool, USE_DATABASE
    
    print(f"[DB] DATABASE_URL present: {bool(DATABASE_URL)}")
    print(f"[DB] asyncpg installed: {HAS_ASYNCPG}")
    
    if not DATABASE_URL or not HAS_ASYNCPG:
        print("[DB] No DATABASE_URL or asyncpg not installed - using file storage")
        return False
    
    try:
        # Create connection pool (Railway Postgres often has strict connection caps).
        # Use conservative defaults and allow overrides via env vars.
        pool_min = int(os.environ.get("DB_POOL_MIN_SIZE", "1"))
        pool_max = int(os.environ.get("DB_POOL_MAX_SIZE", "10"))
        if pool_min < 0:
            pool_min = 0
        if pool_max < 1:
            pool_max = 1
        if pool_min > pool_max:
            pool_min = pool_max

        db_pool = await asyncpg.create_pool(
            DATABASE_URL, 
            min_size=pool_min,
            max_size=pool_max,
            command_timeout=float(os.environ.get("DB_COMMAND_TIMEOUT", "20")),
            max_inactive_connection_lifetime=float(os.environ.get("DB_MAX_INACTIVE_CONNECTION_LIFETIME", "120")),
        )
        
        # Create tables if they don't exist
        async with db_pool.acquire(timeout=10) as conn:
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS users (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT UNIQUE NOT NULL,
                    is_approved BOOLEAN DEFAULT FALSE,
                    is_pending BOOLEAN DEFAULT FALSE,
                    is_admin BOOLEAN DEFAULT FALSE,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS shopify_sites (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    site_url TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW(),
                    UNIQUE(user_id, site_url)
                )
            ''')
            await conn.execute("CREATE INDEX IF NOT EXISTS shopify_sites_user_idx ON shopify_sites(user_id)")
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS razorpay_sites (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    site_url TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW(),
                    UNIQUE(user_id, site_url)
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS proxies (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    proxy_data JSONB NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS hits (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    gateway TEXT NOT NULL,
                    card_data TEXT NOT NULL,
                    result TEXT NOT NULL,
                    details JSONB,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')

            # Ensure we can de-duplicate hits safely (prevents double inserts from retries/parallelism)
            await conn.execute("ALTER TABLE hits ADD COLUMN IF NOT EXISTS dedup_key TEXT")
            await conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS hits_dedup_key_uidx ON hits(dedup_key)")
            await conn.execute("CREATE INDEX IF NOT EXISTS hits_user_time_idx ON hits(user_id, created_at DESC)")
            await conn.execute("CREATE INDEX IF NOT EXISTS hits_gateway_result_time_idx ON hits(gateway, result, created_at DESC)")

            # Hitkey storage (so hitkeys survive restarts / Railway ephemeral disk)
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS hitkeys (
                    hitkey TEXT PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    hits JSONB NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')
            await conn.execute("CREATE INDEX IF NOT EXISTS hitkeys_user_time_idx ON hitkeys(user_id, created_at DESC)")
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS user_settings (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    key TEXT NOT NULL,
                    value JSONB,
                    UNIQUE(user_id, key)
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS shopify_extra_sites (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    site_url TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW(),
                    UNIQUE(user_id, site_url)
                )
            ''')
            await conn.execute("CREATE INDEX IF NOT EXISTS shopify_extra_sites_user_idx ON shopify_extra_sites(user_id)")
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS cards (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    card_data TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')

            # New efficient queue storage (prevents sequence exhaustion & massive delete/reinsert churn)
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS card_queues (
                    user_id BIGINT PRIMARY KEY,
                    cards JSONB NOT NULL,
                    updated_at TIMESTAMP DEFAULT NOW()
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS paypal_sites (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    site_data JSONB NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')
            
            await conn.execute('''
                CREATE TABLE IF NOT EXISTS woo_sites (
                    id SERIAL PRIMARY KEY,
                    user_id BIGINT NOT NULL,
                    site_data JSONB NOT NULL,
                    created_at TIMESTAMP DEFAULT NOW()
                )
            ''')
        
        USE_DATABASE = True
        print("[DB] PostgreSQL connected and tables created successfully!")
        return True
        
    except Exception as e:
        print(f"[DB] Database connection failed: {e} - using file storage")
        USE_DATABASE = False
        return False


