# In-memory cache for Shopify sites (reduces DB load)
_shopify_sites_cache = {}  # {user_id: {"sites": [...], "expires": timestamp}}
_SHOPIFY_CACHE_TTL = 60  # Cache for 60 seconds

async def db_get_user_shopify_sites(user_id):
    """Get user's Shopify sites from database with caching"""
    if not USE_DATABASE:
        return None
    
    # Check cache first
    cache_key = user_id
    if cache_key in _shopify_sites_cache:
        cached = _shopify_sites_cache[cache_key]
        if time.time() < cached.get("expires", 0):
            return cached.get("sites", [])
    
    # Retry logic for reliability
    for attempt in range(3):
        try:
            async with db_pool.acquire(timeout=15) as conn:
                # Stable ordering so UI numbering matches /removesh indices.
                rows = await conn.fetch(
                    "SELECT site_url FROM shopify_sites WHERE user_id = $1 ORDER BY created_at ASC, id ASC",
                    user_id,
                )
                sites = [row['site_url'] for row in rows]
                # Cache the result
                _shopify_sites_cache[cache_key] = {"sites": sites, "expires": time.time() + _SHOPIFY_CACHE_TTL}
                return sites
        except asyncio.TimeoutError:
            print(f"[DB] Timeout getting shopify sites for {user_id}, attempt {attempt+1}/3")
            if attempt < 2:
                await asyncio.sleep(0.5)
        except Exception as e:
            print(f"[DB] Error getting shopify sites: {e}")
            break
    
    # On failure, return cached data if available (even if expired)
    if cache_key in _shopify_sites_cache:
        return _shopify_sites_cache[cache_key].get("sites", [])
    return None


async def db_save_user_shopify_sites(user_id, sites):
    """Save user's Shopify sites to database with retry and cache update"""
    if not USE_DATABASE:
        return False
    
    # Update cache immediately (optimistic update)
    _shopify_sites_cache[user_id] = {"sites": list(sites), "expires": time.time() + _SHOPIFY_CACHE_TTL}
    
    # Retry logic for reliability
    for attempt in range(3):
        try:
            async with db_pool.acquire(timeout=15) as conn:
                async with conn.transaction():
                    # Reconcile instead of destructive rewrite:
                    # - preserves created_at/id for existing rows
                    # - avoids full-table churn that makes /addsh and /removesh slow/unreliable
                    seen = set()
                    sites_list = []
                    for s in (sites or []):
                        if not isinstance(s, str):
                            continue
                        ss = s.strip()
                        if not ss:
                            continue
                        if ss in seen:
                            continue
                        seen.add(ss)
                        sites_list.append(ss)
                    if not sites_list:
                        await conn.execute("DELETE FROM shopify_sites WHERE user_id = $1", user_id)
                    else:
                        await conn.execute(
                            "DELETE FROM shopify_sites WHERE user_id = $1 AND NOT (site_url = ANY($2::text[]))",
                            user_id,
                            sites_list,
                        )
                        await conn.execute(
                            """
                            INSERT INTO shopify_sites (user_id, site_url)
                            SELECT $1, x FROM unnest($2::text[]) AS x
                            ON CONFLICT (user_id, site_url) DO NOTHING
                            """,
                            user_id,
                            sites_list,
                        )
            return True
        except asyncio.TimeoutError:
            print(f"[DB] Timeout saving shopify sites for {user_id}, attempt {attempt+1}/3")
            if attempt < 2:
                await asyncio.sleep(0.5)
        except Exception as e:
            print(f"[DB] Error saving shopify sites: {e}")
            break
    
    # Keep cache even on failure (data is still in memory)
    return False


