# In-memory cache for proxies (reduces DB load)
_proxies_cache = {}  # {user_id: {"proxies": [...], "expires": timestamp}}
_PROXIES_CACHE_TTL = 60  # Cache for 60 seconds

async def db_get_user_proxies(user_id):
    """Get user's proxies from database with caching"""
    if not USE_DATABASE:
        return None
    
    # Check cache first
    cache_key = user_id
    if cache_key in _proxies_cache:
        cached = _proxies_cache[cache_key]
        if time.time() < cached.get("expires", 0):
            return cached.get("proxies", [])
    
    # Retry logic
    for attempt in range(3):
        try:
            async with db_pool.acquire(timeout=15) as conn:
                rows = await conn.fetch("SELECT proxy_data FROM proxies WHERE user_id = $1", user_id)
                result = []
                for row in rows:
                    data = row['proxy_data']
                    if isinstance(data, str):
                        result.append(json.loads(data))
                    else:
                        result.append(data)
                # Cache the result
                _proxies_cache[cache_key] = {"proxies": result, "expires": time.time() + _PROXIES_CACHE_TTL}
                return result
        except asyncio.TimeoutError:
            print(f"[DB] Timeout getting proxies for {user_id}, attempt {attempt+1}/3")
            if attempt < 2:
                await asyncio.sleep(0.5)
        except Exception as e:
            print(f"[DB] Error getting proxies: {e}")
            break
    
    # Return cached data on failure
    if cache_key in _proxies_cache:
        return _proxies_cache[cache_key].get("proxies", [])
    return None


