def _make_hit_dedup_key(*parts: str) -> str:
    """Stable key to deduplicate hit inserts across retries/parallelism."""
    raw = "|".join([p or "" for p in parts])
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


def normalize_shopify_result(result_type: str, reason: Optional[str]) -> Tuple[str, str]:
    """
    Defensive normalization for Shopify classification.
    Prevents mis-bucketing where 3DS/insufficient gets stored as CHARGED.
    Returns (normalized_type, normalized_reason).
    """
    rt = (result_type or "").strip()
    rsn = (reason or "").strip()
    rt_upper = rt.upper()
    rsn_upper = rsn.upper()

    # Any obvious 3DS/SCA marker should NEVER be treated as Charged.
    # IMPORTANT: avoid false "Approved" when the text is actually an auth failure.
    is_3ds = any(k in rsn_upper for k in ["3DS", "3-D", "SCA", "ACTIONREQUIRED", "ACTION_REQUIRED", "CHALLENGE", "AUTHENTICATION"])
    if is_3ds:
        if any(k in rsn_upper for k in ["FAILED", "FAIL", "DECLINED", "DENIED", "REJECT"]):
            return ("Declined", rsn if rsn else "3DS_FAILED")
        return ("Approved", rsn if rsn else "3DS")

    # Any obvious insufficient marker should never be treated as Charged.
    is_insufficient = any(k in rsn_upper for k in ["INSUFFICIENT", "FUNDS", "LOW BALANCE", "NOT_ENOUGH", "BALANCE"])
    if is_insufficient:
        return ("Insufficient", rsn if rsn else "INSUFFICIENT")

    # Some gateways sometimes embed the true status in reason text.
    if rt_upper == "CHARGED":
        # Safety: if reason explicitly says approved/ccn/insufficient, honor it.
        if "APPROVED" in rsn_upper:
            return ("Approved", rsn)
        if "CCN" in rsn_upper or "CVV" in rsn_upper or "CVC" in rsn_upper:
            return ("CCN", rsn)
        if "INSUFFICIENT" in rsn_upper:
            return ("Insufficient", rsn)

    return (rt, rsn)


def get_bin_details_fast(card_line: str) -> dict:
    """
    Fast BIN details without network calls. Uses local BIN DB/cache only.
    Safe to call in hot paths (hit recording).
    """
    try:
        parts = (card_line or "").replace("|", "/").split("/")
        cc_num = "".join([c for c in (parts[0] if parts else "") if c.isdigit()])
        if len(cc_num) < 6:
            return {}
        bin6 = cc_num[:6].zfill(6)
        info = BIN_DATABASE.get(bin6) or BIN_CACHE.get(bin6) or {}
        out = {
            "bin6": bin6,
            "bank": info.get("bank"),
            "country": info.get("country"),
            "country_name": info.get("country_name"),
            "brand": info.get("brand"),
            "type": info.get("type"),
        }
        return {k: v for k, v in out.items() if v}
    except Exception:
        return {}


async def db_add_hit(user_id: int, gateway: str, result: str, card_data: str, details: Optional[dict] = None) -> bool:
    """Insert a hit into DB (deduplicated)."""
    if not USE_DATABASE:
        return False
    try:
        # Normalize
        gateway_n = (gateway or "").lower()
        result_n = (result or "").upper()
        card_n = (card_data or "").strip()
        if not gateway_n or not result_n or not card_n:
            return False

        dedup_key = _make_hit_dedup_key(str(user_id), gateway_n, result_n, card_n)
        async with db_pool.acquire(timeout=10) as conn:
            await conn.execute(
                """
                INSERT INTO hits (user_id, gateway, card_data, result, details, dedup_key)
                VALUES ($1, $2, $3, $4, $5::jsonb, $6)
                ON CONFLICT (dedup_key) DO NOTHING
                """,
                int(user_id),
                gateway_n,
                card_n,
                result_n,
                json.dumps(details) if details is not None else None,
                dedup_key,
            )
        return True
    except Exception as e:
        # Non-fatal: do not crash check loops
        try:
            print(f"[DB] Error inserting hit: {e}")
        except Exception:
            pass
        record_event("db_error", str(e)[:200], user_id=user_id, extra={"op": "db_add_hit"})
        return False


async def db_fetch_hits(
    *,
    user_id: Optional[int] = None,
    gateway: Optional[str] = None,
    result: Optional[str] = None,
    limit: int = 50000,
) -> Optional[list]:
    """Fetch hits with optional filters. Returns list[dict] newest-first."""
    if not USE_DATABASE:
        return None
    try:
        clauses = []
        args = []
        if user_id is not None:
            clauses.append(f"user_id = ${len(args) + 1}")
            args.append(int(user_id))
        if gateway:
            clauses.append(f"gateway = ${len(args) + 1}")
            args.append(str(gateway).lower())
        if result:
            clauses.append(f"result = ${len(args) + 1}")
            args.append(str(result).upper())

        where_sql = ("WHERE " + " AND ".join(clauses)) if clauses else ""
        args.append(int(limit))

        async with db_pool.acquire(timeout=10) as conn:
            rows = await conn.fetch(
                f"SELECT user_id, gateway, card_data, result, created_at FROM hits {where_sql} ORDER BY created_at DESC LIMIT ${len(args)}",
                *args,
            )
        return [dict(r) for r in rows]
    except Exception as e:
        try:
            print(f"[DB] Error fetching hits: {e}")
        except Exception:
            pass
        record_event("db_error", str(e)[:200], extra={"op": "db_fetch_hits"})
        return None


