async def db_save_user_extra_sites(user_id, sites):
    """Save user's extra Shopify sites to database - optimized bulk insert"""
    if not USE_DATABASE:
        return False
    try:
        async with db_pool.acquire(timeout=10) as conn:
            async with conn.transaction():
                seen = set()
                sites_list = []
                for s in (sites or []):
                    if not isinstance(s, str):
                        continue
                    ss = s.strip()
                    if not ss:
                        continue
                    if ss in seen:
                        continue
                    seen.add(ss)
                    sites_list.append(ss)
                if not sites_list:
                    await conn.execute("DELETE FROM shopify_extra_sites WHERE user_id = $1", user_id)
                else:
                    await conn.execute(
                        "DELETE FROM shopify_extra_sites WHERE user_id = $1 AND NOT (site_url = ANY($2::text[]))",
                        user_id,
                        sites_list,
                    )
                    await conn.execute(
                        """
                        INSERT INTO shopify_extra_sites (user_id, site_url)
                        SELECT $1, x FROM unnest($2::text[]) AS x
                        ON CONFLICT (user_id, site_url) DO NOTHING
                        """,
                        user_id,
                        sites_list,
                    )
        return True
    except Exception as e:
        print(f"[DB] Error saving extra shopify sites: {e}")
        return False


# In-memory cache for cards queue (very frequently accessed during checks)
_cards_cache = {}  # {user_id: {"cards": [...], "expires": timestamp}}
_CARDS_CACHE_TTL = 30  # Shorter TTL for cards (they change frequently)

async def db_get_user_cards(user_id):
    """Get user's cards from database with caching"""
    if not USE_DATABASE:
        return None
    
    # Check cache first
    cache_key = user_id
    if cache_key in _cards_cache:
        cached = _cards_cache[cache_key]
        if time.time() < cached.get("expires", 0):
            return list(cached.get("cards", []))  # Return copy to avoid mutation issues
    
    # Retry logic
    for attempt in range(3):
        try:
            async with db_pool.acquire(timeout=15) as conn:
                row = await conn.fetchrow("SELECT cards FROM card_queues WHERE user_id = $1", user_id)
                if not row:
                    cards = []
                else:
                    data = row.get("cards")
                    if isinstance(data, str):
                        data = json.loads(data) if data else []
                    cards = list(data) if isinstance(data, list) else []
                
                # Cache the result
                _cards_cache[cache_key] = {"cards": cards, "expires": time.time() + _CARDS_CACHE_TTL}
                return cards
        except asyncio.TimeoutError:
            print(f"[DB] Timeout getting cards for {user_id}, attempt {attempt+1}/3")
            if attempt < 2:
                await asyncio.sleep(0.5)
        except Exception as e:
            print(f"[DB] Error getting cards: {e}")
            break
    
    # Return cached data on failure
    if cache_key in _cards_cache:
        return list(_cards_cache[cache_key].get("cards", []))
    return None


async def db_save_user_cards(user_id, cards):
    """Save user's cards to database with cache update"""
    if not USE_DATABASE:
        return False
    
    # Update cache immediately (optimistic update)
    cards_list = list(cards) if cards else []
    _cards_cache[user_id] = {"cards": cards_list, "expires": time.time() + _CARDS_CACHE_TTL}
    
    # Retry logic
    for attempt in range(3):
        try:
            async with db_pool.acquire(timeout=10) as conn:
                await conn.execute(
                    """
                    INSERT INTO card_queues (user_id, cards, updated_at)
                    VALUES ($1, $2, NOW())
                    ON CONFLICT (user_id) DO UPDATE
                    SET cards = EXCLUDED.cards, updated_at = NOW()
                    """,
                    int(user_id),
                    json.dumps(cards_list),
                )
            return True
        except asyncio.TimeoutError:
            print(f"[DB] Timeout saving cards for {user_id}, attempt {attempt+1}/3")
            if attempt < 2:
                await asyncio.sleep(0.3)
        except Exception as e:
            print(f"[DB] Error saving cards: {e}")
            break
    
    return False


