# ==================== CONCURRENT JOB TRACKING ====================
# Multi-job support: allow many concurrent checks per user & per gateway.
@dataclass
class CheckJob:
    job_id: str
    user_id: int
    chat_id: int
    gateway: str  # "paypal" | "shopify" | "razorpay" | etc.
    cancel_event: asyncio.Event = field(default_factory=asyncio.Event)
    task: Optional[asyncio.Task] = None
    created_at: float = field(default_factory=time.time)


JOBS_LOCK = asyncio.Lock()
JOBS_BY_USER: Dict[int, Dict[str, CheckJob]] = defaultdict(dict)  # user_id -> job_id -> job


def _new_job_id(gateway: str) -> str:
    # Short, log-friendly unique id
    return f"{gateway}_{int(time.time() * 1000)}_{uuid.uuid4().hex[:6]}"


async def start_check_job(
    *,
    user_id: int,
    chat_id: int,
    gateway: str,
    runner: Callable[[asyncio.Event, str], Awaitable[None]],
) -> str:
    """Start a check job in background without blocking handler."""
    job_id = _new_job_id(gateway)
    job = CheckJob(job_id=job_id, user_id=user_id, chat_id=chat_id, gateway=gateway)

    async with JOBS_LOCK:
        JOBS_BY_USER[user_id][job_id] = job

    async def _wrap() -> None:
        try:
            await runner(job.cancel_event, job_id)
        except asyncio.CancelledError:
            # Best-effort cancellation
            pass
        except Exception as e:
            log(f"[JOB {job_id}] crashed: {e}", "ERROR")
            try:
                await safe_send_message(chat_id, f"❌ {gateway.title()} job crashed: `{str(e)[:200]}`", parse_mode="Markdown")
            except Exception:
                pass
        finally:
            async with JOBS_LOCK:
                JOBS_BY_USER.get(user_id, {}).pop(job_id, None)
                if not JOBS_BY_USER.get(user_id):
                    JOBS_BY_USER.pop(user_id, None)

    job.task = asyncio.create_task(_wrap())
    return job_id


async def stop_user_jobs(user_id: int, gateway: Optional[str] = None) -> int:
    """Signal cancellation for all jobs for a user (optionally by gateway)."""
    async with JOBS_LOCK:
        jobs = list(JOBS_BY_USER.get(user_id, {}).values())
    count = 0
    for job in jobs:
        if gateway and job.gateway != gateway:
            continue
        job.cancel_event.set()
        count += 1
    return count


async def count_user_jobs(user_id: int, gateway: Optional[str] = None) -> int:
    async with JOBS_LOCK:
        jobs = JOBS_BY_USER.get(user_id, {})
        if not gateway:
            return len(jobs)
        return sum(1 for j in jobs.values() if j.gateway == gateway)


def create_inline_keyboard(buttons):
    """
    Create inline keyboard from button list.
    buttons: list of (text, callback_data) tuples or list of lists for rows
    """
    markup = InlineKeyboardMarkup()
    for row in buttons:
        if isinstance(row, list):
            markup.row(*[InlineKeyboardButton(text=btn[0], callback_data=btn[1]) for btn in row])
        else:
            markup.add(InlineKeyboardButton(text=row[0], callback_data=row[1]))
    return markup


# ==================== UI HELPER FUNCTIONS ====================

async def get_user_identity(user_id):
    """Get user's @username and name, with caching"""
    global username_cache
    
    # Check cache (valid for 1 hour)
    if user_id in username_cache:
        cached = username_cache[user_id]
        if (datetime.now() - cached.get("cached_at", datetime.min)).total_seconds() < 3600:
            return cached
    
    # Fetch from Telegram
    try:
        chat = await bot.get_chat(user_id)
        identity = {
            "username": f"@{chat.username}" if chat.username else None,
            "name": chat.first_name or "Unknown",
            "full_name": f"{chat.first_name or ''} {chat.last_name or ''}".strip() or "Unknown",
            "cached_at": datetime.now()
        }
        username_cache[user_id] = identity
        return identity
    except:
        return {"username": None, "name": "Unknown", "full_name": "Unknown", "cached_at": datetime.now()}


def format_user_display(user_id, identity=None):
    """Format user display as: @username (ID) or Name (ID)"""
    if identity:
        if identity.get("username"):
            return f"{identity['username']} (`{user_id}`)"
        return f"{identity.get('name', 'User')} (`{user_id}`)"
    return f"`{user_id}`"


async def safe_send_message(chat_id, text, parse_mode=None):
    """Safely send message to Telegram"""
    try:
        await tg_send_message(chat_id, text, parse_mode=parse_mode)
        return True
    except Exception as e:
        log(f"Failed to send message: {str(e)[:50]}", "WARNING")
        record_event("tg_send_error", str(e)[:200], chat_id=chat_id)
        return False


async def safe_reply(message, text, parse_mode=None, reply_markup=None, disable_web_page_preview=None):
    """Reply when message_id exists, else send normally (supports FakeMessage)."""
    try:
        chat_id = message.chat.id
        reply_to_id = getattr(message, "message_id", None)
        kwargs = {}
        if parse_mode is not None:
            kwargs["parse_mode"] = parse_mode
        if reply_markup is not None:
            kwargs["reply_markup"] = reply_markup
        if disable_web_page_preview is not None:
            kwargs["disable_web_page_preview"] = disable_web_page_preview

        if reply_to_id:
            kwargs["reply_to_message_id"] = reply_to_id
        return await tg_send_message(chat_id, text, **kwargs)
    except Exception as e:
        log(f"Failed to safe_reply: {str(e)[:50]}", "WARNING")
        record_event("tg_send_error", str(e)[:200], chat_id=getattr(message.chat, "id", None))
        return None


# ==================== MONITORING / ALERTS / TELEGRAM BACKOFF ====================

EVENT_LOG_MAX = int(os.environ.get("EVENT_LOG_MAX", "500"))
EVENT_WINDOW_SECONDS = int(os.environ.get("EVENT_WINDOW_SECONDS", "300"))  # 5 minutes
ALERT_COOLDOWN_SECONDS = int(os.environ.get("ALERT_COOLDOWN_SECONDS", "300"))  # 5 minutes
ALERT_WEBHOOK_URL = os.environ.get("ALERT_WEBHOOK_URL")  # optional external webhook

# Spike thresholds within EVENT_WINDOW_SECONDS
ALERT_THRESHOLDS = {
    "tg_429": int(os.environ.get("ALERT_TG_429_THRESHOLD", "5")),
    "db_error": int(os.environ.get("ALERT_DB_ERROR_THRESHOLD", "3")),
    "checker_error": int(os.environ.get("ALERT_CHECKER_ERROR_THRESHOLD", "20")),
}

_EVENT_LOG = deque(maxlen=EVENT_LOG_MAX)
_EVENT_COUNTS = defaultdict(deque)  # kind -> deque[timestamps]
_LAST_ALERT_AT = defaultdict(float)  # kind -> ts


def record_event(kind: str, msg: str = "", *, chat_id: Optional[int] = None, user_id: Optional[int] = None, extra: Optional[dict] = None) -> None:
    """Record an operational event for dashboards/alerts."""
    try:
        ts = time.time()
        kind = (kind or "event").strip()
        entry = {
            "ts": ts,
            "kind": kind,
            "msg": (msg or "")[:300],
            "chat_id": chat_id,
            "user_id": user_id,
            "extra": extra or {},
        }
        _EVENT_LOG.append(entry)
        dq = _EVENT_COUNTS[kind]
        dq.append(ts)
        # prune
        cutoff = ts - EVENT_WINDOW_SECONDS
        while dq and dq[0] < cutoff:
            dq.popleft()
    except Exception:
        pass


def _extract_retry_after_seconds(err_text: str) -> Optional[int]:
    """Best-effort parse of Telegram 429 retry-after."""
    if not err_text:
        return None
    s = err_text.lower()
    # Typical: "Too Many Requests: retry after X"
    m = re.search(r"retry after (\d+)", s)
    if m:
        try:
            return int(m.group(1))
        except Exception:
            return None
    # Sometimes: "Retry in X"
    m = re.search(r"retry in (\d+)", s)
    if m:
        try:
            return int(m.group(1))
        except Exception:
            return None
    return None


async def _post_alert_webhook(payload: dict) -> None:
    if not ALERT_WEBHOOK_URL:
        return
    try:
        async with aiohttp.ClientSession() as session:
            async with session.post(ALERT_WEBHOOK_URL, json=payload, timeout=aiohttp.ClientTimeout(total=8)) as resp:
                _ = resp.status
    except Exception:
        pass


async def maybe_send_alert(kind: str, count: int) -> None:
    """Send a spike alert to OWNER_ID (and optional webhook) with cooldown."""
    try:
        now = time.time()
        last = _LAST_ALERT_AT.get(kind, 0)
        if now - last < ALERT_COOLDOWN_SECONDS:
            return
        _LAST_ALERT_AT[kind] = now

        text = f"⚠️ *ALERT*: `{kind}` spike\n• Window: {EVENT_WINDOW_SECONDS}s\n• Count: *{count}*"
        await tg_send_message(OWNER_ID, text, parse_mode="Markdown")
        await _post_alert_webhook({"kind": kind, "count": count, "window_seconds": EVENT_WINDOW_SECONDS, "ts": now})
    except Exception:
        pass


async def evaluate_alerts_loop() -> None:
    """Background loop that checks event spikes."""
    while True:
        try:
            for kind, threshold in ALERT_THRESHOLDS.items():
                dq = _EVENT_COUNTS.get(kind)
                if not dq:
                    continue
                # prune globally
                cutoff = time.time() - EVENT_WINDOW_SECONDS
                while dq and dq[0] < cutoff:
                    dq.popleft()
                if len(dq) >= threshold:
                    await maybe_send_alert(kind, len(dq))
        except Exception:
            pass
        await asyncio.sleep(30)


async def tg_send_message(chat_id, text, **kwargs):
    """Telegram send_message with 429 backoff + global semaphore."""
    max_attempts = 5
    for attempt in range(max_attempts):
        try:
            async with TG_API_SEMAPHORE:
                return await bot.send_message(chat_id, text, **kwargs)
        except Exception as e:
            err_text = str(e)
            # detect 429
            if "429" in err_text or "too many requests" in err_text.lower():
                record_event("tg_429", err_text[:200], chat_id=chat_id)
                retry_after = _extract_retry_after_seconds(err_text) or (2 + attempt * 2)
                await asyncio.sleep(min(30, max(1, retry_after)))
                continue
            # transient network-ish errors: small backoff
            if attempt < max_attempts - 1 and any(x in err_text.lower() for x in ["timed out", "timeout", "connection", "network", "bad gateway", "gateway timeout"]):
                await asyncio.sleep(1 + attempt)
                continue
            raise


async def tg_edit_message_text(text, *, chat_id: int, message_id: int, **kwargs):
    """Telegram edit_message_text with 429 backoff."""
    max_attempts = 5
    for attempt in range(max_attempts):
        try:
            async with TG_API_SEMAPHORE:
                return await bot.edit_message_text(text, chat_id=chat_id, message_id=message_id, **kwargs)
        except Exception as e:
            err_text = str(e)
            if "message is not modified" in err_text.lower():
                return None
            if "429" in err_text or "too many requests" in err_text.lower():
                record_event("tg_429", err_text[:200], chat_id=chat_id)
                retry_after = _extract_retry_after_seconds(err_text) or (2 + attempt * 2)
                await asyncio.sleep(min(30, max(1, retry_after)))
                continue
            if attempt < max_attempts - 1 and any(x in err_text.lower() for x in ["timed out", "timeout", "connection", "network"]):
                await asyncio.sleep(1 + attempt)
                continue
            raise


