async def edit_or_send(chat_id, user_id, text, markup=None, parse_mode='Markdown'):
    """Edit existing menu message or send new one"""
    global user_menu_messages
    
    try:
        # Try to edit existing message
        if user_id in user_menu_messages:
            msg_data = user_menu_messages[user_id]
            if msg_data.get("chat_id") == chat_id:
                try:
                    await tg_edit_message_text(
                        text,
                        chat_id=chat_id,
                        message_id=msg_data["message_id"],
                        parse_mode=parse_mode,
                        reply_markup=markup,
                    )
                    return msg_data["message_id"]
                except Exception as e:
                    # Message might be too old or deleted, send new one
                    if "message is not modified" in str(e).lower():
                        return msg_data["message_id"]
                    pass
        
        # Send new message
        msg = await tg_send_message(chat_id, text, parse_mode=parse_mode, reply_markup=markup)
        user_menu_messages[user_id] = {"message_id": msg.message_id, "chat_id": chat_id}
        return msg.message_id
    except Exception as e:
        # Fallback to simple send
        msg = await tg_send_message(chat_id, text, parse_mode=parse_mode, reply_markup=markup)
        return msg.message_id


async def delete_menu_message(chat_id, user_id):
    """Delete the current menu message"""
    global user_menu_messages
    
    if user_id in user_menu_messages:
        try:
            await bot.delete_message(chat_id, user_menu_messages[user_id]["message_id"])
        except:
            pass
        del user_menu_messages[user_id]


