def bold_sans(text):
    """Convert text to bold sans-serif Unicode (𝗕𝗼𝗹𝗱)"""
    return ''.join(BOLD_SANS.get(c, c) for c in str(text))

def bold_serif(text):
    """Convert text to bold serif Unicode (𝐁𝐨𝐥𝐝)"""
    return ''.join(BOLD_SERIF.get(c, c) for c in str(text))

def mask_password(password, visible_chars=0):
    """Mask password with bullet characters"""
    if not password:
        return ""
    return "⦁" * len(password)

def format_proxy_display(proxy_str, mask_pass=True):
    """Format proxy for display with optional password masking"""
    parts = proxy_str.split(":")
    if len(parts) >= 4 and mask_pass:
        host, port = parts[0], parts[1]
        user = parts[2] if len(parts) > 2 else ""
        passwd = mask_password(parts[3]) if len(parts) > 3 else ""
        return f"{host}:{port}:{user}:{passwd}"
    return proxy_str


