# ==================== ENHANCED FINGERPRINT PROTECTION ====================
# Full browser fingerprint simulation with rotating user agents, WebRTC headers, etc.
# This prevents detection by making requests look like real browser traffic

class BrowserFingerprint:
    """Generate realistic browser fingerprints for stealth requests.
    
    Features:
    - Rotating Chrome/Firefox/Safari user agents with real versions
    - Proper Client Hints (Sec-Ch-*) headers
    - WebGL/Canvas fingerprint prevention
    - Realistic Accept/Language/Encoding headers
    - DNT and privacy headers
    - TLS fingerprint simulation
    """
    
    # Real Chrome versions (latest stable)
    CHROME_VERSIONS = [
        "120.0.0.0", "121.0.0.0", "122.0.0.0", "123.0.0.0", "124.0.0.0",
        "125.0.0.0", "126.0.0.0", "127.0.0.0", "128.0.0.0", "129.0.0.0",
        "130.0.0.0", "131.0.0.0"
    ]
    
    # Real Firefox versions
    FIREFOX_VERSIONS = ["121.0", "122.0", "123.0", "124.0", "125.0", "126.0", "127.0", "128.0", "129.0", "130.0", "131.0", "132.0"]
    
    # Real Safari versions
    SAFARI_VERSIONS = ["17.0", "17.1", "17.2", "17.3", "17.4", "17.5", "18.0"]
    
    # OS platforms
    WINDOWS_VERSIONS = [
        ("Windows NT 10.0; Win64; x64", "10.0.0"),
        ("Windows NT 11.0; Win64; x64", "15.0.0"),
    ]
    
    MAC_VERSIONS = [
        ("Macintosh; Intel Mac OS X 10_15_7", "10.15.7"),
        ("Macintosh; Intel Mac OS X 11_6_0", "11.6.0"),
        ("Macintosh; Intel Mac OS X 12_6_0", "12.6.0"),
        ("Macintosh; Intel Mac OS X 13_5_0", "13.5.0"),
        ("Macintosh; Intel Mac OS X 14_0_0", "14.0.0"),
    ]
    
    # Screen resolutions for realistic viewport
    SCREEN_RESOLUTIONS = [
        (1920, 1080), (1366, 768), (1536, 864), (1440, 900),
        (1280, 720), (2560, 1440), (3840, 2160), (1600, 900)
    ]
    
    # Accept-Language combinations
    LANGUAGES = [
        "en-US,en;q=0.9",
        "en-US,en;q=0.9,es;q=0.8",
        "en-GB,en;q=0.9,en-US;q=0.8",
        "en-US,en;q=0.9,fr;q=0.8",
        "en-US,en;q=0.8",
    ]
    
    @classmethod
    def get_chrome_fingerprint(cls):
        """Generate a realistic Chrome browser fingerprint"""
        chrome_ver = random.choice(cls.CHROME_VERSIONS)
        platform = random.choice(cls.WINDOWS_VERSIONS + cls.MAC_VERSIONS)
        os_string, platform_ver = platform
        resolution = random.choice(cls.SCREEN_RESOLUTIONS)
        
        # Determine if Windows or Mac
        is_windows = "Windows" in os_string
        platform_name = "Windows" if is_windows else "macOS"
        
        user_agent = f"Mozilla/5.0 ({os_string}) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/{chrome_ver} Safari/537.36"
        
        headers = {
            "User-Agent": user_agent,
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7",
            "Accept-Language": random.choice(cls.LANGUAGES),
            "Accept-Encoding": "gzip, deflate, br",
            "Cache-Control": "max-age=0",
            "Sec-Ch-Ua": f'"Not_A Brand";v="8", "Chromium";v="{chrome_ver.split(".")[0]}", "Google Chrome";v="{chrome_ver.split(".")[0]}"',
            "Sec-Ch-Ua-Mobile": "?0",
            "Sec-Ch-Ua-Platform": f'"{platform_name}"',
            "Sec-Fetch-Dest": "document",
            "Sec-Fetch-Mode": "navigate",
            "Sec-Fetch-Site": "none",
            "Sec-Fetch-User": "?1",
            "Upgrade-Insecure-Requests": "1",
            "DNT": "1",
        }
        
        return {
            "headers": headers,
            "user_agent": user_agent,
            "platform": platform_name,
            "resolution": resolution,
            "browser": "Chrome",
            "version": chrome_ver
        }
    
    @classmethod
    def get_firefox_fingerprint(cls):
        """Generate a realistic Firefox browser fingerprint"""
        ff_ver = random.choice(cls.FIREFOX_VERSIONS)
        platform = random.choice(cls.WINDOWS_VERSIONS + cls.MAC_VERSIONS)
        os_string, _ = platform
        resolution = random.choice(cls.SCREEN_RESOLUTIONS)
        
        is_windows = "Windows" in os_string
        platform_name = "Windows" if is_windows else "macOS"
        
