async def load_json_file(filepath, default=None):
    """Load JSON file safely with backup recovery"""
    if default is None:
        default = {}
    
    backup_path = filepath + ".backup"
    
    # Try main file first
    if os.path.exists(filepath):
        try:
            async with aiofiles.open(filepath, 'r', encoding='utf-8') as f:
                content = await f.read()
                if content.strip():
                    data = json.loads(content)
                    # Validate it's the expected type
                    if isinstance(data, (dict, list)):
                        return data
        except (json.JSONDecodeError, Exception) as e:
            log(f"JSON load error for {filepath}: {e}, trying backup", "WARN")
    
    # Try backup file if main failed
    if os.path.exists(backup_path):
        try:
            async with aiofiles.open(backup_path, 'r', encoding='utf-8') as f:
                content = await f.read()
                if content.strip():
                    data = json.loads(content)
                    if isinstance(data, (dict, list)):
                        log(f"Recovered {filepath} from backup", "INFO")
                        # Restore the main file from backup
                        async with aiofiles.open(filepath, 'w', encoding='utf-8') as fw:
                            await fw.write(json.dumps(data, indent=2))
                        return data
        except Exception as e:
            log(f"Backup recovery failed for {filepath}: {e}", "WARN")
    
    return default


async def save_json_file(filepath, data):
    """Save JSON file safely with atomic write and backup"""
    import uuid

    backup_path = filepath + ".backup"
    dirpath = os.path.dirname(filepath) if os.path.dirname(filepath) else "."

    # Serialize writes per-file to avoid temp-file races across concurrent tasks.
    try:
        global _JSON_FILE_LOCKS
        _JSON_FILE_LOCKS
    except NameError:
        _JSON_FILE_LOCKS = defaultdict(asyncio.Lock)
    lock = _JSON_FILE_LOCKS[filepath]

    async with lock:
        # Unique temp file per write (prevents `.tmp` collisions).
        temp_path = f"{filepath}.tmp.{uuid.uuid4().hex}"
        try:
            # Ensure directory exists
            os.makedirs(dirpath, exist_ok=True)

            # Write to temp file first (atomic preparation)
            json_content = json.dumps(data, indent=2)
            async with aiofiles.open(temp_path, 'w', encoding='utf-8') as f:
                await f.write(json_content)
                try:
                    await f.flush()
                except Exception:
                    pass

            # Backup existing file if it exists and has content
            if os.path.exists(filepath):
                try:
                    async with aiofiles.open(filepath, 'r', encoding='utf-8') as f:
                        existing = await f.read()
                        if existing.strip() and len(existing) > 2:  # More than just "{}"
                            async with aiofiles.open(backup_path, 'w', encoding='utf-8') as fb:
                                await fb.write(existing)
                except Exception:
                    pass

            # Atomic replace (this is the key - replace is atomic on most filesystems)
            os.replace(temp_path, filepath)

        except Exception as e:
            log(f"Save JSON error for {filepath}: {e}", "ERROR")
            # Clean up temp file if it exists
            if os.path.exists(temp_path):
                try:
                    os.remove(temp_path)
                except Exception:
                    pass
            raise


