async def load_user_daily_stats(user_id):
    """Load user's Razorpay daily/weekly/all-time stats from file"""
    filepath = get_user_file(user_id, RZ_DAILY_STATS_FILE)
    default_stats = {
        "today": {"date": datetime.now().strftime("%Y-%m-%d"), "charged": 0, "declined": 0, "insufficient": 0},
        "week": {"week_start": datetime.now().strftime("%Y-%m-%d"), "charged": 0, "declined": 0, "insufficient": 0},
        "all_time": {"charged": 0, "declined": 0, "insufficient": 0}
    }
    return await load_json_file(filepath, default_stats)


async def save_user_daily_stats(user_id, stats):
    """Save user's Razorpay daily/weekly/all-time stats to file"""
    filepath = get_user_file(user_id, RZ_DAILY_STATS_FILE)
    await save_json_file(filepath, stats)


async def increment_rz_daily_stat(user_id, stat_type):
    """Increment daily/weekly/all-time stat counters with date rollover handling.
    stat_type: 'charged', 'declined', or 'insufficient'
    """
    stats = await load_user_daily_stats(user_id)
    today = datetime.now().strftime("%Y-%m-%d")
    
    # Handle daily rollover
    if stats["today"].get("date") != today:
        stats["today"] = {"date": today, "charged": 0, "declined": 0, "insufficient": 0}
    
    # Handle weekly rollover (reset if more than 7 days since week_start)
    try:
        week_start = datetime.strptime(stats["week"].get("week_start", today), "%Y-%m-%d")
        if (datetime.now() - week_start).days >= 7:
            stats["week"] = {"week_start": today, "charged": 0, "declined": 0, "insufficient": 0}
    except:
        stats["week"] = {"week_start": today, "charged": 0, "declined": 0, "insufficient": 0}
    
    # Increment counters
    if stat_type in ["charged", "declined", "insufficient"]:
        stats["today"][stat_type] = stats["today"].get(stat_type, 0) + 1
        stats["week"][stat_type] = stats["week"].get(stat_type, 0) + 1
        stats["all_time"][stat_type] = stats["all_time"].get(stat_type, 0) + 1
    
    await save_user_daily_stats(user_id, stats)
    return stats


