# ==================== SITE QUALITY TRACKER ====================
# Tracks which Shopify sites work reliably vs have timing errors
# Sites with persistent timing errors get auto-blacklisted

class SiteQualityTracker:
    """
    Tracks site quality to learn which sites work reliably.
    Auto-blacklists sites with persistent timing errors.
    """
    
    TIMING_ERRORS = ["DELIVERY_TIMING", "DELIVERY_CHANGED", "PRICE_CHANGED", "CONFIRM_CHANGE", 
                     "DELIVERY_DELIVERY_LINE_DETAIL_CHANGED", "PAYMENTS_UNACCEPTABLE_PAYMENT_AMOUNT"]
    
    def __init__(self, user_id):
        self.user_id = user_id
        self.filepath = get_user_file(user_id, "site_quality.json")
        self.data = {}
    
    async def load(self):
        """Load site quality data from file"""
        self.data = await load_json_file(self.filepath, {"sites": {}})
        return self
    
    async def save(self):
        """Save site quality data to file"""
        await save_json_file(self.filepath, self.data)
    
    def get_site_stats(self, site_url):
        """Get stats for a specific site"""
        site_key = site_url.replace("https://", "").replace("http://", "").strip("/")
        if site_key not in self.data.get("sites", {}):
            self.data.setdefault("sites", {})[site_key] = {
                "attempts": 0,
                "timing_errors": 0,
                "card_results": 0,  # Real card results (not timing errors)
                "consecutive_timing": 0,  # Consecutive timing errors
                "status": "candidate",  # candidate, verified, blacklisted
                "last_success": None,
                "last_error": None
            }
        return self.data["sites"][site_key]
    
    async def record_timing_error(self, site_url, error_code):
        """Record a timing error for a site"""
        stats = self.get_site_stats(site_url)
        stats["attempts"] += 1
        stats["timing_errors"] += 1
        stats["consecutive_timing"] += 1
        stats["last_error"] = error_code
        
        # Auto-blacklist after 3 consecutive timing errors
        if stats["consecutive_timing"] >= 3:
            stats["status"] = "blacklisted"
            log(f"[QUALITY] 🚫 Site BLACKLISTED (3+ timing errors): {site_url}", "WARNING")
        
        await self.save()
    
    async def record_card_result(self, site_url, result_type):
        """Record a real card result (success or decline)"""
        stats = self.get_site_stats(site_url)
        stats["attempts"] += 1
        stats["card_results"] += 1
        stats["consecutive_timing"] = 0  # Reset consecutive timing errors
        stats["last_success"] = datetime.now().isoformat()
        
        # Promote to verified after 2+ successful card results with low error rate
        if stats["card_results"] >= 2:
            error_rate = stats["timing_errors"] / max(stats["attempts"], 1)
            if error_rate < 0.3:  # Less than 30% timing errors
                stats["status"] = "verified"
                log(f"[QUALITY] ✅ Site VERIFIED (reliable): {site_url}", "SUCCESS")
        
        await self.save()
    
    async def record_critical_error(self, site_url, error_code):
        """Record a critical error (site should be removed)"""
        stats = self.get_site_stats(site_url)
        stats["status"] = "blacklisted"
        stats["last_error"] = error_code
        log(f"[QUALITY] 🚫 Site BLACKLISTED (critical error {error_code}): {site_url}", "WARNING")
        await self.save()
    
    def is_blacklisted(self, site_url):
        """Check if site is blacklisted"""
        stats = self.get_site_stats(site_url)
        return stats["status"] == "blacklisted"
    
    def is_verified(self, site_url):
        """Check if site is verified"""
        stats = self.get_site_stats(site_url)
        return stats["status"] == "verified"
    
    def get_sorted_sites(self, sites_list):
        """Sort sites: verified first, then candidates, exclude blacklisted"""
        verified = []
        candidates = []
        blacklisted_count = 0
        
        for site in sites_list:
            site_url = site if isinstance(site, str) else site.get("url", "")
            stats = self.get_site_stats(site_url)
            
            if stats["status"] == "blacklisted":
                blacklisted_count += 1
                continue
            elif stats["status"] == "verified":
                verified.append(site)
            else:
                candidates.append(site)
        
        if blacklisted_count > 0:
            log(f"[QUALITY] Skipping {blacklisted_count} blacklisted sites", "INFO")
        
        # Return verified first, then candidates
        return verified + candidates
    
    def get_quality_summary(self):
        """Get summary of site quality stats"""
        sites = self.data.get("sites", {})
        verified = sum(1 for s in sites.values() if s["status"] == "verified")
        blacklisted = sum(1 for s in sites.values() if s["status"] == "blacklisted")
        candidates = sum(1 for s in sites.values() if s["status"] == "candidate")
        return {"verified": verified, "blacklisted": blacklisted, "candidates": candidates}


async def get_site_quality_tracker(user_id):
    """Get or create site quality tracker for user"""
    tracker = SiteQualityTracker(user_id)
    await tracker.load()
    return tracker


# ==================== SHOPIFY SITE VALIDATION ====================

# Test BINs for site validation - try payment to detect captcha
SHOPIFY_VALIDATION_TEST_BINS = ["420767", "434769", "411111", "424242"]

async def validate_shopify_site(site_url, proxy_url=None, test_bin: Optional[str] = None):
    """
    Validate a Shopify site by attempting a FULL checkout flow INCLUDING payment submission.
    This detects sites with captcha required at payment step (not just at checkout).
    Returns: (is_valid, status, details)
    - is_valid: True if site can be used for checking
    - status: "ok", "dead", "captcha", "blocked", "no_products", "error"
    - details: Human-readable explanation
    """
    # Ensure URL has protocol
    if not site_url.startswith("http"):
        site_url = f"https://{site_url}"
    
    # Clean URL
    site_url = site_url.rstrip("/")
    
    # Support BOTH SOCKS and HTTP proxies for validation.
    http_proxy = None
    proxy_auth = None
    try:
        if proxy_url and not str(proxy_url).lower().startswith("socks"):
            pd = parse_proxy(str(proxy_url))
            http_proxy = get_simple_proxy_url(pd)
            proxy_auth = get_proxy_auth(pd)
    except Exception:
        http_proxy = None
        proxy_auth = None

    rotator = ShopifyGateRotator(proxy_url=proxy_url, http_proxy=http_proxy, proxy_auth=proxy_auth)
    
    try:
        connector = rotator.get_connector()
        cookie_jar = aiohttp.CookieJar()
        timeout = aiohttp.ClientTimeout(total=60)  # Increased timeout for full payment flow
        
        async with aiohttp.ClientSession(connector=connector, cookie_jar=cookie_jar, timeout=timeout) as session:
            # Step 1: Fetch products
            product, error = await rotator.fetch_cheapest_product(site_url, session)
            
            if error:
                if "404" in str(error) or "403" in str(error):
                    return False, "dead", f"Site unreachable ({error})"
                if "No products" in str(error):
                    return False, "no_products", "No available products found"
                return False, "error", f"Product fetch failed: {error}"
            
            if not product:
                return False, "no_products", "No valid products found"
            
            # Step 2: Add to cart
            cart_result, error = await rotator.add_to_cart(
                site_url, product['variant_id'], product['product_id'], session
            )
            
            if error:
                if "403" in str(error) or "blocked" in str(error).lower():
                    return False, "blocked", f"Site blocked access: {error}"
                return False, "error", f"Cart failed: {error}"
            
            # Step 3: Navigate to checkout (this is where captcha/blocklist shows)
            checkout_data, error = await rotator.navigate_to_checkout(site_url, session)
            
            if error:
                error_upper = str(error).upper()
                if "CAPTCHA" in error_upper:
                    hc_ck = get_saved_cookie()
                    if hc_ck:
                        return True, "ok", "hCaptcha detected but accessibility cookie available — will auto-solve"
                    return False, "captcha", "hCaptcha protection detected at checkout (no cookie set — use /hcaptcha)"
                if "MISSING_SESSION" in error_upper or "NO CHECKOUT" in error_upper:
                    return False, "blocked", "Checkout blocked or invalid"
                if "403" in str(error) or "blocked" in str(error).lower():
                    return False, "blocked", "Site blocked checkout access"
                return False, "error", f"Checkout failed: {error}"
            
            if not checkout_data:
                return True, "ok", "OK (products found, checkout skipped validation)"
            
            # Step 4: Create payment session with a test card
            # Use configurable BINs - prioritize 420767, 434769 (agen cards)
            chosen_bin = (str(test_bin or os.environ.get("SHOPIFY_SITE_TEST_BIN", ""))).strip()
            if not chosen_bin or not chosen_bin.isdigit() or len(chosen_bin) < 6:
                chosen_bin = random.choice(SHOPIFY_VALIDATION_TEST_BINS)
            chosen_bin = chosen_bin[:6]
            
            test_cards = generate_cards_from_bin(chosen_bin, 1)
            if not test_cards:
                return False, "error", "Could not generate test card"
            
            test_card = test_cards[0]
            cc, mm, yy, cvv = test_card.split("|")
            
            first_name = names.get_first_name()
            last_name = names.get_last_name()
            user_data = {
                "first_name": first_name,
                "last_name": last_name,
                "email": f"{first_name.lower()}{random.randint(1,999)}@gmail.com",
                "phone": f"+1{random.randint(2000000000, 9999999999)}",
                "address": {'address1': '1600 Amphitheatre Parkway', 'city': 'Mountain View', 'state': 'CA', 'zip': '94043'},
                "user_agent": rotator.user_agents[0]
            }
            
            session_id, error = await rotator.create_payment_session(
                site_url, checkout_data, cc, mm, yy, cvv, user_data, session
            )
            
            if error:
                err_upper = str(error).upper()
                if "CAPTCHA" in err_upper or "CAPTCHA_METADATA_MISSING" in err_upper:
                    return False, "captcha", f"Captcha blocked at payment session ({str(error)[:80]})"
                if "429" in err_upper or "RATE" in err_upper:
                    return False, "blocked", f"Rate limited at payment session ({str(error)[:80]})"
                if "blocked" in str(error).lower() or "403" in str(error):
                    return False, "blocked", "Payment session blocked"
                # Continue anyway - some errors at session creation are recoverable
                log(f"[VALIDATE] Payment session warning (continuing): {error}", "DEBUG")
            
            if not session_id:
                return True, "ok", f"OK (checkout reachable, payment session issue: {str(error)[:40]})"
            
            # Step 5: Send proposal to get shipping options (required before payment)
            proposal_result, error = await rotator.send_proposal(
                site_url, checkout_data, session_id, user_data, product, session
            )
            
            if error:
                err_upper = str(error).upper()
                if "CAPTCHA" in err_upper:
                    return False, "captcha", f"Captcha blocked at proposal ({str(error)[:80]})"
                # Some proposal errors are OK - we try to continue
                log(f"[VALIDATE] Proposal warning: {error}", "DEBUG")
            
            if not proposal_result:
                return True, "ok", f"OK (checkout + payment reachable, shipping issue: {str(error)[:40]})"
            
            # Parse proposal for shipping
            try:
                seller = proposal_result.get('data', {}).get('session', {}).get('negotiate', {}).get('result', {}).get('sellerProposal', {})
                delivery = seller.get('delivery', {})
                new_queue_token = proposal_result.get('data', {}).get('session', {}).get('negotiate', {}).get('result', {}).get('queueToken')
                
                # Check for pending delivery - wait briefly
                if delivery.get('__typename') == 'PendingTerms':
                    await asyncio.sleep(0.5)
                    proposal_result, _ = await rotator.send_proposal(site_url, checkout_data, session_id, user_data, product, session)
                    if proposal_result:
                        seller = proposal_result.get('data', {}).get('session', {}).get('negotiate', {}).get('result', {}).get('sellerProposal', {})
                        delivery = seller.get('delivery', {})
                        new_queue_token = proposal_result.get('data', {}).get('session', {}).get('negotiate', {}).get('result', {}).get('queueToken')
                
                delivery_lines = delivery.get('deliveryLines', [])
                if not delivery_lines:
                    return True, "ok", f"OK (checkout works, no delivery lines) - Product: {product['title'][:25]} (${product['price']})"
                
                strategies = delivery_lines[0].get('availableDeliveryStrategies', [])
                selected = delivery_lines[0].get('selectedDeliveryStrategy', {}) if not strategies else None
                if not strategies and not selected:
                    return True, "ok", f"OK (checkout works, no shipping strategies) - Product: {product['title'][:25]} (${product['price']})"
                
                # Get cheapest shipping
                cheapest_shipping = min(strategies, key=lambda s: float(s.get('amount', {}).get('value', {}).get('amount', '999999')))
                shipping_handle = cheapest_shipping.get('handle')
                shipping_amount = cheapest_shipping.get('amount', {}).get('value', {}).get('amount', '0')
                
                # Get signed handle for delivery expectations
                delivery_exp = seller.get('deliveryExpectations', {})
                signed_handle = None
                if delivery_exp.get('__typename') == 'FilledDeliveryExpectationTerms':
                    exps = delivery_exp.get('deliveryExpectations', [])
                    if exps:
                        signed_handle = exps[0].get('signedHandle')
                
                final_total = seller.get('checkoutTotal', {}).get('value', {})
                
            except Exception as e:
                return False, "error", f"Could not parse shipping: {str(e)[:50]}"
            
            # Step 6: ACTUALLY TRY PAYMENT SUBMISSION - This is where captcha often triggers!
            log(f"[VALIDATE] Attempting payment submission on {site_url} with BIN {chosen_bin}", "DEBUG")
            
            submit_result, error = await rotator.submit_for_completion(
                site_url, checkout_data, session_id, user_data, product,
                shipping_handle, shipping_amount, signed_handle, final_total, new_queue_token, session
            )
            
            if error:
                err_upper = str(error).upper()
                if "CAPTCHA" in err_upper:
                    return False, "captcha", f"Captcha required at payment submission ({str(error)[:80]})"
                if "429" in err_upper or "RATE" in err_upper or "THROTTLE" in err_upper:
                    return False, "blocked", f"Rate limited at payment ({str(error)[:80]})"
                # Submit errors that aren't captcha/blocking are often OK (card declined is fine)
                log(f"[VALIDATE] Submit error (checking result): {error}", "DEBUG")
            
            if submit_result:
                # Check the response for captcha/blocking indicators
                submit_data = submit_result.get('data', {}).get('submitForCompletion', {})
                result_type = submit_data.get('__typename', '')
                
                # CheckpointDenied = Captcha/verification required
                if result_type == 'CheckpointDenied':
                    return False, "captcha", "Captcha/checkpoint required at payment submission"
                
                # TooManyAttempts = Rate limited
                if result_type == 'TooManyAttempts':
                    return False, "blocked", "Too many attempts - rate limited"
                
                # Throttled is also blocking
                if result_type == 'Throttled':
                    return False, "blocked", "Site throttled - rate limited"
                
                # SubmitRejected - check for captcha/site errors, but CARD DECLINES = VALID!
                if result_type == 'SubmitRejected':
                    errors = submit_data.get('errors', [])
                    has_site_error = False
                    decline_code = None
                    for err_obj in errors:
                        err_code = str(err_obj.get('code', '')).upper()
                        err_msg = str(err_obj.get('localizedMessage', '')).upper()
                        combined = f"{err_code} {err_msg}"
                        
                        # Captcha/checkpoint = blocked
                        if 'CAPTCHA' in combined or 'CHECKPOINT' in combined:
                            return False, "captcha", f"Captcha required: {err_obj.get('code', 'unknown')}"
                        
                        # Price/delivery errors = bad site config
                        if any(x in err_code for x in ['PRICE', 'DELIVERY', 'CART', 'MERCHANDISE', 'TOTAL']):
                            has_site_error = True
                            continue
                        
                        # Card decline errors = GOOD! Site is working properly
                        # Common decline codes: GENERIC_DECLINE, DO_NOT_HONOR, CARD_DECLINED, INSUFFICIENT_FUNDS, etc.
                        if any(x in combined for x in ['DECLINE', 'DO_NOT_HONOR', 'DONOTHONOR', 'INSUFFICIENT', 
                                                        'INVALID_CARD', 'CARD_NUMBER', 'EXPIRED', 'CVV', 'CVC',
                                                        'LOST_CARD', 'STOLEN', 'RESTRICTED', 'PICKUP', 'FRAUD',
                                                        'NOT_PERMITTED', 'EXCEEDS', 'LIMIT', 'TRY_AGAIN', 
                                                        'PROCESSING_ERROR', 'ISSUER', 'BANK', 'AUTHENTICATION',
                                                        'GENERIC_ERROR', 'GENERIC', 'ERROR', 'DISSATISFACTION',
                                                        'ARTIFACT', 'PAYMENT_METHOD', 'CALL_ISSUER']):
                            decline_code = err_obj.get('code', 'DECLINED')
                    
                    # If we found a card decline, site is VALID (properly rejected gen card)
                    if decline_code and not has_site_error:
                        return True, "ok", f"✅ VALID - Card DECLINED ({decline_code}) - Product: {product['title'][:25]} (${product['price']})"
                    
                    if has_site_error and not decline_code:
                        return True, "ok", f"OK (checkout works, price/config mismatch) - Product: {product['title'][:25]} (${product['price']})"
                    
                    # If errors exist but weren't recognized, still likely a decline = valid
                    if errors:
                        first_err = errors[0].get('code', 'UNKNOWN')
                        return True, "ok", f"✅ VALID - Rejected ({first_err}) - Product: {product['title'][:25]} (${product['price']})"
                
                # SubmitFailed - check reason, card declines = VALID!
                if result_type == 'SubmitFailed':
                    reason = str(submit_data.get('reason', '')).upper()
                    if 'CAPTCHA' in reason or 'CHECKPOINT' in reason:
                        return False, "captcha", f"Captcha required: {submit_data.get('reason', 'unknown')}"
                    # Price/delivery errors = bad site
                    if any(x in reason for x in ['PRICE', 'DELIVERY', 'CART', 'MERCHANDISE', 'TOTAL']):
                        return False, "error", f"Site config error: {submit_data.get('reason', 'unknown')}"
                    # Card decline reasons = site is valid (properly rejected gen card)
                    if any(x in reason for x in ['DECLINE', 'DO_NOT_HONOR', 'INSUFFICIENT', 'INVALID', 
                                                  'EXPIRED', 'CVV', 'FRAUD', 'BANK', 'ISSUER', 'CARD',
                                                  'PAYMENT_METHOD', 'PAYMENT_FAILED']):
                        return True, "ok", f"✅ VALID - Failed ({submit_data.get('reason', 'declined')}) - Product: {product['title'][:25]} (${product['price']})"
                    # Unknown reason but SubmitFailed often means card issue = likely valid
                    if reason:
                        return True, "ok", f"✅ VALID - SubmitFailed ({submit_data.get('reason', 'unknown')}) - Product: {product['title'][:25]} (${product['price']})"
                
                # =====================================================================
                # CRITICAL: Generated cards (BIN 420767, 434769) should ONLY be DECLINED
                # If site shows CHARGED/APPROVED, it's a FAKE/TEST store!
                # =====================================================================
                
                # Check nested receipt type
                receipt = submit_data.get('receipt', {})
                if receipt:
                    receipt_type = receipt.get('__typename', '')
                    
                    # ProcessedReceipt = CHARGED = FAKE SITE (gen cards can't be charged!)
                    if receipt_type == 'ProcessedReceipt':
                        return False, "fake", "❌ FAKE SITE - Shows CHARGED for generated card (impossible)"
                    
                    # ActionRequiredReceipt = 3DS/APPROVED = FAKE SITE (gen cards shouldn't trigger 3DS)
                    if receipt_type == 'ActionRequiredReceipt':
                        return False, "fake", "❌ FAKE SITE - Shows APPROVED/3DS for generated card (impossible)"
                    
                    # ProcessingReceipt = Still processing, poll for final result
                    if receipt_type == 'ProcessingReceipt':
                        # Wait and poll once
                        receipt_id = receipt.get('id')
                        session_token = receipt.get('purchaseOrder', {}).get('sessionToken', checkout_data.get('x_checkout_one_session_token', ''))
                        if receipt_id and session_token:
                            await asyncio.sleep(2)
                            final_receipt, _ = await rotator.poll_for_receipt(site_url, receipt_id, session_token, user_data['user_agent'], session)
                            if final_receipt:
                                final_type = final_receipt.get('__typename', '')
                                if final_type == 'ProcessedReceipt':
                                    return False, "fake", "❌ FAKE SITE - Shows CHARGED for generated card (impossible)"
                                if final_type == 'ActionRequiredReceipt':
                                    return False, "fake", "❌ FAKE SITE - Shows APPROVED/3DS for generated card (impossible)"
                                if final_type == 'FailedReceipt':
                                    # This is GOOD - card was properly DECLINED
                                    error_info = final_receipt.get('processingError', {})
                                    error_code = error_info.get('code', 'DECLINED')
                                    return True, "ok", f"✅ VALID - Card DECLINED ({error_code}) - Product: {product['title'][:25]} (${product['price']})"
                    
                    # FailedReceipt = DECLINED = GOOD! This is a real payment processor
                    if receipt_type == 'FailedReceipt':
                        error_info = receipt.get('processingError', {})
                        error_code = error_info.get('code', 'DECLINED')
                        error_msg = error_info.get('messageUntranslated', '')
                        
                        # Check for site errors vs card errors
                        combined = f"{error_code} {error_msg}".upper()
                        if any(x in combined for x in ['CAPTCHA', 'CHECKPOINT']):
                            return False, "captcha", f"Captcha in decline: {error_code}"
                        if any(x in combined for x in ['CART', 'PRICE', 'DELIVERY', 'MERCHANDISE', 'TOTAL_CHANGED']):
                            return False, "error", f"Site config error: {error_code}"
                        
                        # Card declined = GOOD! Site is valid
                        return True, "ok", f"✅ VALID - Card DECLINED ({error_code}) - Product: {product['title'][:25]} (${product['price']})"
                
                # SubmitSuccess/SubmittedForCompletion with receipt
                if result_type in ['SubmitSuccess', 'SubmittedForCompletion', 'SubmitAlreadyAccepted']:
                    receipt = submit_data.get('receipt', {})
                    receipt_type = receipt.get('__typename', '') if receipt else ''
                    
                    if receipt_type == 'ProcessedReceipt':
                        return False, "fake", "❌ FAKE SITE - Shows CHARGED for generated card (impossible)"
                    if receipt_type == 'ActionRequiredReceipt':
                        return False, "fake", "❌ FAKE SITE - Shows APPROVED/3DS for generated card (impossible)"
                    if receipt_type == 'FailedReceipt':
                        error_info = receipt.get('processingError', {})
                        error_code = error_info.get('code', 'DECLINED')
                        return True, "ok", f"✅ VALID - Card DECLINED ({error_code}) - Product: {product['title'][:25]} (${product['price']})"
                    # ProcessingReceipt or unknown receipt in Submit* = still processing, likely valid
                    if receipt_type == 'ProcessingReceipt' or receipt:
                        return True, "ok", f"✅ VALID - Payment submitted ({result_type}) - Product: {product['title'][:25]} (${product['price']})"
                
                # If we got a result_type and it's not explicitly bad, site likely works
                # We already checked: Throttled, TooManyAttempts, CheckpointDenied, SubmitRejected, SubmitFailed above
                if result_type and result_type not in ['CheckpointDenied', 'TooManyAttempts', 'Throttled']:
                    # Check if there's any error field that indicates captcha/blocking
                    errors = submit_data.get('errors', [])
                    for err in errors:
                        err_str = str(err).upper()
                        if 'CAPTCHA' in err_str or 'CHECKPOINT' in err_str:
                            return False, "captcha", f"Captcha in response: {result_type}"
                    # No blocking detected, site reached payment step = likely valid
                    return True, "ok", f"✅ VALID - Response ({result_type}) - Product: {product['title'][:25]} (${product['price']})"
            
            # No submit_result at all but we got to submit step = site works, payment gateway issue
            if not submit_result and not error:
                return True, "ok", f"✅ VALID - Reached payment step - Product: {product['title'][:25]} (${product['price']})"
            
            # If we got here with an error string but no submit_result, check the error
            if error:
                err_upper = str(error).upper()
                # Card decline errors in error string = site is valid
                if any(x in err_upper for x in ['DECLINE', 'DO_NOT_HONOR', 'INSUFFICIENT', 'INVALID', 'EXPIRED',
                                                  'CVV', 'FRAUD', 'BANK', 'ISSUER', 'CARD_NUMBER', 'PAYMENT_FAILED']):
                    return True, "ok", f"✅ VALID - Error indicates decline ({str(error)[:30]}) - Product: {product['title'][:25]} (${product['price']})"
            
            return True, "ok", f"OK (reached payment submit) - Product: {product['title'][:25]} (${product['price']})"
            
    except aiohttp.ClientError as e:
        return False, "dead", f"Connection failed: {str(e)[:50]}"
    except asyncio.TimeoutError:
        return False, "dead", "Site timed out"
    except Exception as e:
        return False, "error", f"Validation error: {str(e)[:50]}"


async def validate_shopify_site_on_add(site_url: str, proxy_data: Optional[dict] = None) -> Tuple[bool, str, str]:
    """
    Fast Shopify site validation for *adding* sites.
    Uses a lightweight products endpoint (no checkout/payment).
    Returns: (is_ok, status, details)
      status: ok | dead | blocked | captcha | no_products | error
    """
    try:
        if not site_url.startswith("http"):
            site_url = f"https://{site_url}"
        site_url = site_url.rstrip("/")

        # Setup proxy if provided
        proxy_url = get_proxy_url(proxy_data) if proxy_data else None
        http_proxy = get_simple_proxy_url(proxy_data) if proxy_data and proxy_url and not proxy_url.startswith("socks") else None
        proxy_auth = get_proxy_auth(proxy_data) if proxy_data and http_proxy else None

        # NOTE: force_close=True creates massive TIME_WAIT buildup under load and
        # will slow the bot over time. Use keep-alive connectors instead.
        connector = None
        if proxy_url and proxy_url.startswith("socks"):
            try:
                connector = ProxyConnector.from_url(proxy_url, limit=20, limit_per_host=10)
            except Exception:
                connector = aiohttp.TCPConnector(
                    limit=20,
                    limit_per_host=10,
                    force_close=False,
                    enable_cleanup_closed=True,
                    ttl_dns_cache=300,
                    keepalive_timeout=30,
                )
        else:
            connector = aiohttp.TCPConnector(
                limit=20,
                limit_per_host=10,
                force_close=False,
                enable_cleanup_closed=True,
                ttl_dns_cache=300,
                keepalive_timeout=30,
            )

        timeout = aiohttp.ClientTimeout(total=15, connect=7, sock_read=10)
        headers = {"User-Agent": "Mozilla/5.0", "Accept": "application/json,text/html,*/*"}

        async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
            # Shopify products endpoint (often accessible even when homepage is customized)
            url = f"{site_url}/products.json?limit=1"
            kwargs = {"headers": headers}
            if http_proxy:
                kwargs["proxy"] = http_proxy
                if proxy_auth:
                    kwargs["proxy_auth"] = proxy_auth
            async with session.get(url, **kwargs) as resp:
                text = await resp.text(errors="ignore")
                if resp.status == 200:
                    try:
                        data = json.loads(text)
                        products = data.get("products") if isinstance(data, dict) else None
                        if isinstance(products, list) and len(products) > 0:
                            title = products[0].get("title", "Product") if isinstance(products[0], dict) else "Product"
                            # Optional deep validation on add (checkout/captcha detection).
                            # Enabled by default; can be disabled via env SHOPIFY_DEEP_VALIDATE_ON_ADD=0
                            if os.environ.get("SHOPIFY_DEEP_VALIDATE_ON_ADD", "1") != "0":
                                deep_ok, deep_status, deep_details = await validate_shopify_site(
                                    site_url,
                                    proxy_url=get_proxy_url(proxy_data) if proxy_data else None,
                                    test_bin=os.environ.get("SHOPIFY_SITE_TEST_BIN", "420767"),
                                )
                                if not deep_ok:
                                    return False, deep_status, deep_details
                                return True, "ok", f"OK (checkout) • {title[:40]}"

                            return True, "ok", f"OK (products.json) • {title[:40]}"
                        return False, "no_products", "No products found"
                    except Exception:
                        # 200 but non-json: treat as suspicious but not dead
                        return False, "error", "Unexpected response format"

                # Captcha hints
                low = text.lower()
                if "captcha" in low or "hcaptcha" in low or "recaptcha" in low:
                    return False, "captcha", f"Captcha detected (HTTP {resp.status})"
                if resp.status in [401, 403]:
                    return False, "blocked", f"Blocked (HTTP {resp.status})"
                if resp.status == 429:
                    return False, "blocked", "Rate limited (HTTP 429)"
                if resp.status == 404:
                    # Not necessarily dead (some disable products.json), try homepage quickly
                    try:
                        async with session.get(site_url, **kwargs) as r2:
                            t2 = await r2.text(errors="ignore")
                            if r2.status in [200, 301, 302]:
                                if "captcha" in t2.lower() or "hcaptcha" in t2.lower() or "recaptcha" in t2.lower():
                                    return False, "captcha", "Captcha detected on homepage"
                                return True, "ok", "OK (homepage reachable)"
                            return False, "dead", f"Unreachable (HTTP {r2.status})"
                    except Exception:
                        return False, "dead", "Unreachable"

                return False, "error", f"HTTP {resp.status}"
    except asyncio.TimeoutError:
        return False, "dead", "Timed out"
    except aiohttp.ClientError as e:
        return False, "dead", f"Connection failed: {str(e)[:60]}"
    except Exception as e:
        return False, "error", f"Validation error: {str(e)[:60]}"


async def validate_multiple_sites(sites, proxy_url=None, progress_callback=None):
    """
    Validate multiple Shopify sites.
    Returns: dict with {valid: [], dead: [], captcha: [], blocked: [], errors: []}
    """
    results = {
        "valid": [],
        "dead": [],
        "captcha": [],
        "blocked": [],
        "no_products": [],
        "errors": []
    }
    
    for i, site in enumerate(sites):
        if progress_callback:
            await progress_callback(i + 1, len(sites), site)
        
        is_valid, status, details = await validate_shopify_site(site, proxy_url)
        
        site_info = {"url": site, "details": details}
        
        if is_valid:
            results["valid"].append(site_info)
        elif status == "dead":
            results["dead"].append(site_info)
        elif status == "captcha":
            results["captcha"].append(site_info)
        elif status == "blocked":
            results["blocked"].append(site_info)
        elif status == "no_products":
            results["no_products"].append(site_info)
        else:
            results["errors"].append(site_info)
        
        # Small delay between validations
        await asyncio.sleep(1)
    
    return results


# ==================== PROXY MANAGEMENT ====================
# SUPPORTED PROXY TYPES:
# - HTTP/HTTPS proxies (with/without authentication)
# - SOCKS4 proxies (with/without authentication)
# - SOCKS5 proxies (with/without authentication)
# - SOCKS5H proxies (DNS resolution through proxy)
#
# SUPPORTED FORMATS:
# - host:port
# - host:port:user:pass
# - host:port:user:pass:protocol (protocol at end)
# - user:pass@host:port
# - protocol://host:port
# - protocol://user:pass@host:port
# - protocol:host:port:user:pass (protocol at start without //)

# Invalid datacenter/CDN IP ranges that are NOT valid proxies
# These are often scraped from websites but are just CDN edge servers
INVALID_PROXY_IP_PREFIXES = [
    # Cloudflare ranges (these are CDN servers, not proxies)
    "104.16.", "104.17.", "104.18.", "104.19.", "104.20.", "104.21.", "104.22.", "104.23.",
    "104.24.", "104.25.", "104.26.", "104.27.", "104.28.", "104.29.", "104.30.", "104.31.",
    "172.64.", "172.65.", "172.66.", "172.67.", "172.68.", "172.69.", "172.70.", "172.71.",
    "162.158.", "162.159.",
    "141.101.",
    "190.93.",
    "197.234.",
    "198.41.",
    "173.245.",
    "103.21.", "103.22.", "103.31.",
    # Fastly ranges
    "151.101.",
    "199.232.",
    # Other CDNs commonly mistaken for proxies
    "23.227.",  # Shopify
    "13.224.", "13.225.", "13.226.", "13.227.",  # CloudFront
    "54.230.", "54.231.", "54.232.", "54.239.", "54.240.",  # AWS CloudFront
]


def is_invalid_datacenter_ip(ip_str):
    """
    Check if an IP address belongs to a known CDN/datacenter range that is NOT a valid proxy.
    These IPs are often scraped from websites but are CDN edge servers, not actual proxies.
    Returns True if the IP should be filtered out.
    """
    if not ip_str:
        return False
    
    # Check if it looks like an IP address (has dots and numbers)
    parts = ip_str.split('.')
    if len(parts) != 4:
        return False  # Not an IP, might be a domain - let it through
    
    try:
        # Validate it's actually an IP
        for part in parts:
            num = int(part)
            if num < 0 or num > 255:
                return False
    except:
        return False  # Not a valid IP format
    
    # Check against known invalid prefixes
    for prefix in INVALID_PROXY_IP_PREFIXES:
        if ip_str.startswith(prefix):
            return True
    
    return False


# Common ports used by FREE/SCRAPED proxy lists - these are usually dead or blocked
FREE_PROXY_PORTS = {80, 8080, 3128, 8888, 8118, 8000, 3129, 8081, 8008, 9999, 
                    1080, 4145, 9050, 9051, 8082, 8083, 8084, 8085, 8090, 
                    8443, 3124, 3127, 8899, 9998, 9090, 7890, 10809}

# Global tracker for scraped proxy warnings
scraped_proxy_users = {}  # {user_id: {"scraped": N, "suspect": N, "last_warned": ts, "proxies": [list], ...}}

# Admin notifications throttling (per user)
_SCRAPED_NOTIFY_COOLDOWN_SECONDS = int(os.environ.get("SCRAPED_PROXY_NOTIFY_COOLDOWN_SECONDS", "600"))  # 10 min

# Behavior test knobs (kept small to avoid slowing adds)
_SCRAPED_BEHAVIOR_TEST_TRIES = int(os.environ.get("SCRAPED_BEHAVIOR_TEST_TRIES", "3"))
_SCRAPED_BEHAVIOR_TIMEOUT = float(os.environ.get("SCRAPED_BEHAVIOR_TIMEOUT", "6"))


async def assess_proxy_public_risk(proxy_data: dict) -> Tuple[str, str, dict]:
    """Behavior-based proxy risk assessment.

    Returns: (level, reason, details)
      level: "scraped" | "suspect" | ""
    We only return "scraped" when the proxy is clearly unstable/unusable like public lists.
    """
    if not proxy_data:
        return "", "", {}

    # Never treat authenticated or rotating proxies as scraped.
    if proxy_data.get("username") and proxy_data.get("password"):
        return "", "", {}
    try:
        if is_rotating_proxy(proxy_data):
            return "", "", {}
    except Exception:
        pass

    scheme = (proxy_data.get("scheme") or "http").lower().strip()
    host = (proxy_data.get("host") or "").strip()
    port = str(proxy_data.get("port") or "").strip()

    # Only assess HTTP/HTTPS unauth proxies; we intentionally skip SOCKS to avoid false positives.
    if scheme not in ["http", "https", ""]:
        return "", "", {}
    if not host or not port.isdigit():
        return "", "", {}

    # Only run behavior tests for proxies that already look suspicious by shape (common ports).
    try:
        pnum = int(port)
    except Exception:
        return "", "", {}
    if pnum not in FREE_PROXY_PORTS:
        return "", "", {}

    proxy_url_simple = f"http://{host}:{port}"
    test_urls = [
        "http://api.ipify.org?format=json",
        "http://ip-api.com/json",
    ]

    ips = []
    ok = 0
    errors = 0
    latencies = []

    async def _one(url: str):
        nonlocal ok, errors
        t0 = time.time()
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(
                    url,
                    proxy=proxy_url_simple,
                    timeout=aiohttp.ClientTimeout(total=_SCRAPED_BEHAVIOR_TIMEOUT),
                    headers={"User-Agent": "Mozilla/5.0"},
                ) as resp:
                    if resp.status != 200:
                        errors += 1
                        return
                    data = await resp.json(content_type=None)
                    ip = None
                    if isinstance(data, dict):
                        ip = data.get("ip") or data.get("query")
                    if isinstance(ip, str) and ip:
                        ok += 1
                        ips.append(ip)
                        latencies.append(max(0.0, time.time() - t0))
                    else:
                        errors += 1
        except Exception:
            errors += 1

    tries = max(1, _SCRAPED_BEHAVIOR_TEST_TRIES)
    for _ in range(tries):
        await asyncio.gather(*[_one(u) for u in test_urls], return_exceptions=True)

    uniq_ips = len(set(ips))
    details = {
        "ok": ok,
        "errors": errors,
        "unique_ips": uniq_ips,
        "samples": ips[:5],
        "avg_latency": (sum(latencies) / len(latencies)) if latencies else None,
    }

    # Hard "scraped" signals: mostly failing / very unstable (typical public lists).
    total_attempts = tries * len(test_urls)
    if ok == 0:
        return "scraped", "Behavior test: 0 successes (proxy unusable / public list dead)", details
    if total_attempts >= 4 and ok / float(total_attempts) < 0.5:
        return "scraped", f"Behavior test: low success rate ({ok}/{total_attempts})", details

    # If it works but looks like a pool (multiple IPs) and has no auth, keep as suspect (not scraped).
    if uniq_ips >= 2:
        return "suspect", f"Behavior test: multiple exit IPs seen ({uniq_ips}) on unauth proxy", details

    return "", "", details


def classify_scraped_proxy(proxy_data) -> Tuple[str, str]:
    """
    Classify proxy as:
    - ("scraped", reason): high confidence public/free-list proxy
    - ("suspect", reason): unauthenticated proxy that *might* be public/free-list
    - ("", ""): no issue

    We avoid flagging verified rotating/paid proxies as scraped.
    """
    if not proxy_data:
        return "", ""
    
    has_auth = bool(proxy_data.get("username") and proxy_data.get("password"))
    port = proxy_data.get("port")
    scheme = (proxy_data.get("scheme") or "").lower().strip()
    host = (proxy_data.get("host") or "").strip()
    
    # If it has auth, it's almost never a public/free list proxy.
    if has_auth:
        return "", ""

    # If we've verified it rotates, don't call it scraped.
    try:
        if is_rotating_proxy(proxy_data):
            return "", ""
    except Exception:
        pass

    # Do NOT flag SOCKS proxies as scraped just because they're unauthenticated.
    if scheme in ["socks4", "socks5", "socks5h", "socks4a"]:
        return "", ""
    
    is_ip_host = bool(re.match(r'^(\d{1,3}\.){3}\d{1,3}$', host))
    try:
        port_num = int(port)
    except:
        return "", ""

    if scheme not in ["http", "https", ""]:
        return "", ""
    
    if port_num in FREE_PROXY_PORTS:
        # IMPORTANT: Do not escalate to "scraped" based only on string shape.
        # Many paid ISP/static proxies can be IP:port, even on common ports.
        # We only mark "scraped" after a behavior check (stability/IP tests).
        return "suspect", f"Unauthenticated proxy on common public-proxy port ({port_num})"

    return "", ""


def is_scraped_proxy(proxy_data):
    """Backward-compatible wrapper: True only for high-confidence scraped proxies."""
    level, reason = classify_scraped_proxy(proxy_data)
    return (level == "scraped"), reason


async def _notify_scraped_proxy_add(user_id: int, proxy_str: str, level: str, reason: str) -> None:
    """Notify owner/admins in near real-time (throttled)."""
    if level != "scraped":
        return
    try:
        global scraped_proxy_users
        now_ts = time.time()
        last = float(scraped_proxy_users.get(user_id, {}).get("notify_last", 0) or 0)
        if last and (now_ts - last) < _SCRAPED_NOTIFY_COOLDOWN_SECONDS:
            return
        if user_id not in scraped_proxy_users:
            scraped_proxy_users[user_id] = {}
        scraped_proxy_users[user_id]["notify_last"] = now_ts
    except Exception:
        pass

    # Mask proxy to avoid leaking credentials
    safe_proxy = proxy_str
    try:
        if "@" in safe_proxy:
            safe_proxy = safe_proxy.split("@")[-1]
        safe_proxy = safe_proxy.replace("http://", "").replace("https://", "").replace("socks5://", "").replace("socks4://", "")
    except Exception:
        pass

    identity = {}
    try:
        identity = await get_user_identity(user_id)
    except Exception:
        identity = {"name": str(user_id)}
    name = identity.get("name") or str(user_id)
    username = identity.get("username") or ""

    text = f"""🚨 *SCRAPED PROXY ADDED*
User: *{name}* {f"(@{username})" if username else ""} (`{user_id}`)
Proxy: `{safe_proxy[:80]}`
Reason: `{reason[:160]}`
Time: `{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}`
"""
    # Owner
    try:
        await tg_send_message(OWNER_ID, text, parse_mode="Markdown")
    except Exception:
        pass
    # Admins
    try:
        admins = await get_admins()
        for aid in admins:
            if int(aid) == int(OWNER_ID):
                continue
            try:
                await tg_send_message(int(aid), text, parse_mode="Markdown")
            except Exception:
                continue
    except Exception:
        pass


async def log_scraped_proxy_usage(user_id, proxy_str, reason, level: str = "scraped"):
    """Log when a user adds a scraped/suspect proxy"""
    global scraped_proxy_users
    
    if user_id not in scraped_proxy_users:
        scraped_proxy_users[user_id] = {
            "scraped": 0,
            "suspect": 0,
            "last_warned": 0,
            "proxies": [],
            "first_seen": time.time()
        }
    
    if level == "scraped":
        scraped_proxy_users[user_id]["scraped"] += 1
    elif level == "suspect":
        scraped_proxy_users[user_id]["suspect"] += 1
    scraped_proxy_users[user_id]["last_warned"] = time.time()
    scraped_proxy_users[user_id]["proxies"].append({
        "proxy": proxy_str[:50] + "..." if len(proxy_str) > 50 else proxy_str,
        "reason": reason,
        "level": level,
        "time": time.time()
    })
    # Keep only last 10 proxies
    scraped_proxy_users[user_id]["proxies"] = scraped_proxy_users[user_id]["proxies"][-10:]

    # Persist across restarts when DB is available (Railway restarts would otherwise wipe memory).
    # Stored under user_id=0 (global settings namespace), similar to HIT_CHANNEL.
    if USE_DATABASE:
        try:
            await db_set_user_setting(0, "scraped_proxy_users", scraped_proxy_users)
        except Exception:
            pass

    # Live notify owner/admins for high-confidence scraped proxies
    try:
        await _notify_scraped_proxy_add(int(user_id), str(proxy_str), str(level), str(reason))
    except Exception:
        pass


async def maybe_escalate_suspect_proxy(user_id: int, proxy_data: dict, raw_proxy: str) -> None:
    """Run behavior test for suspect proxies and escalate to scraped if clearly bad.

    This prevents false positives: we only escalate to "scraped" after instability is observed.
    """
    try:
        level, reason = classify_scraped_proxy(proxy_data)
        if level != "suspect":
            return
        assessed_level, assessed_reason, details = await assess_proxy_public_risk(proxy_data)
        if assessed_level == "scraped":
            extra = ""
            try:
                extra = f" (ok={details.get('ok')}, err={details.get('errors')}, ips={details.get('unique_ips')})"
            except Exception:
                extra = ""
            await log_scraped_proxy_usage(user_id, raw_proxy, assessed_reason + extra, level="scraped")
        elif assessed_level == "suspect":
            # Log as suspect (no owner/admin ping)
            await log_scraped_proxy_usage(user_id, raw_proxy, assessed_reason, level="suspect")
        else:
            # Looks fine; no log
            return
    except Exception:
        return


def get_scraped_proxy_warning():
    """Get detailed warning message for scraped proxy users"""
    return """⚠️ *POSSIBLE PUBLIC/FREE PROXY* ⚠️

This proxy looks like an unauthenticated *public/free-list* proxy (common free HTTP port).
Legit ISP proxies can also be `ip:port`, so this is a *best-effort* warning — not an auto-ban.

*Why this matters:*
❌ Already blocked by most Shopify sites
❌ Extremely slow & unreliable  
❌ Shared by thousands of users
❌ Will get YOUR sites blocked permanently
❌ Wastes your time and credits

*What to do:*
✅ Prefer authenticated residential/ISP proxies (user:pass) when possible
✅ Prefer rotating residential for best success
✅ If this is your private ISP proxy and it works, you can ignore this warning

_This event is logged for troubleshooting (false positives can happen). Owner/admins may be notified for high-confidence public proxies._"""


def parse_proxy(proxy_str):
    """
    Universal proxy parser - supports ALL common proxy formats.
    
    Supported formats:
    - host:port
    - host:port:user:pass
    - host:port:user:pass:socks5 (type at end)
    - user:pass@host:port
    - socks5://host:port
    - socks5://user:pass@host:port
    - socks5:host:port:user:pass (type prefix without //)
    - http://user:pass@host:port
    
    Supported types: http, https, socks4, socks5, socks5h
    
    Returns: dict with host, port, username, password, scheme, raw
    """
    proxy_str = proxy_str.strip()
    result = {
        "raw": proxy_str, 
        "host": None, 
        "port": None, 
        "username": None, 
        "password": None, 
        "scheme": "http"
    }
    
    working_str = proxy_str
    
    # Step 1: Extract protocol from URL format (protocol://...)
    for proto in ["socks5h://", "socks5://", "socks4://", "socks4a://", "https://", "http://"]:
        if working_str.lower().startswith(proto):
            scheme = proto.replace("://", "")
            if scheme == "socks5h":
                scheme = "socks5"  # Normalize
            if scheme == "socks4a":
                scheme = "socks4"  # Normalize
            result["scheme"] = scheme
            working_str = working_str[len(proto):]
            break
    
    # Step 2: Check for protocol prefix without :// (e.g., "socks5:host:port")
    lower_str = working_str.lower()
    for proto in ["socks5h:", "socks5:", "socks4:", "socks4a:", "http:", "https:"]:
        if lower_str.startswith(proto) and not lower_str.startswith(proto + "//"):
            scheme = proto.replace(":", "")
            if scheme in ["socks5h", "socks4a"]:
                scheme = scheme[:6]  # Normalize to socks5 or socks4
            result["scheme"] = scheme
            working_str = working_str[len(proto):]
            break
    
    # Step 3: Check for protocol at the end (e.g., "host:port:user:pass:socks5")
    parts_check = working_str.lower().split(":")
    if parts_check[-1] in ["socks5", "socks5h", "socks4", "socks4a", "http", "https"]:
        scheme = parts_check[-1]
        if scheme in ["socks5h", "socks4a"]:
            scheme = scheme[:6]
        result["scheme"] = scheme
        working_str = ":".join(working_str.split(":")[:-1])
    
    # Step 4: Parse the remaining string
    # Format: user:pass@host:port
    if "@" in working_str:
        auth_part, host_part = working_str.rsplit("@", 1)
        if ":" in auth_part:
            result["username"], result["password"] = auth_part.split(":", 1)
        if ":" in host_part:
            result["host"], port_str = host_part.rsplit(":", 1)
            try:
                result["port"] = int(port_str)
            except:
                pass
        else:
            result["host"] = host_part
    # Format: host:port:user:pass
    elif working_str.count(":") >= 3:
        parts = working_str.split(":")
        result["host"] = parts[0]
        try:
            result["port"] = int(parts[1])
        except:
            pass
        result["username"] = parts[2] if len(parts) > 2 else None
        result["password"] = ":".join(parts[3:]) if len(parts) > 3 else None  # Handle passwords with colons
    # Format: host:port
    elif ":" in working_str:
        parts = working_str.split(":")
        result["host"] = parts[0]
        try:
            result["port"] = int(parts[1])
        except:
            pass
    
    # Step 5: Auto-detect SOCKS proxies by common ports
    if result["scheme"] == "http" and result["port"]:
        socks_ports = {
            1080: "socks5", 1081: "socks4", 1082: "socks5",
            9050: "socks5", 9150: "socks5",  # Tor
            4145: "socks4", 4153: "socks4",
            10808: "socks5", 7890: "socks5",  # Common proxy apps
        }
        if result["port"] in socks_ports:
            result["scheme"] = socks_ports[result["port"]]
    
    return result


def get_proxy_url(proxy_data):
    """Convert proxy data to URL format for aiohttp-socks.
    
    Handles all proxy types:
    - HTTP/HTTPS proxies (with/without auth)
    - SOCKS4/SOCKS5 proxies
    - Rotating proxies (complex usernames with hyphens, special chars)
    """
    if not proxy_data.get("host") or not proxy_data.get("port"):
        return None
    
    scheme = proxy_data.get("scheme", "http")
    host = proxy_data["host"]
    port = proxy_data["port"]
    
    if proxy_data.get("username") and proxy_data.get("password"):
        from urllib.parse import quote
        # URL encode credentials - safe='' ensures all special chars are encoded
        # This handles rotating proxy usernames like "user-zone-US-session-abc123"
        username = quote(str(proxy_data['username']), safe='')
        password = quote(str(proxy_data['password']), safe='')
        return f"{scheme}://{username}:{password}@{host}:{port}"
    else:
        return f"{scheme}://{host}:{port}"


def get_proxy_auth(proxy_data):
    """Get aiohttp BasicAuth object for HTTP proxy authentication.
    Used as fallback when ProxyConnector fails with 407.
    """
    if proxy_data.get("username") and proxy_data.get("password"):
        return aiohttp.BasicAuth(
            str(proxy_data['username']), 
            str(proxy_data['password'])
        )
    return None


def get_simple_proxy_url(proxy_data):
    """Get proxy URL without credentials (for use with separate BasicAuth)."""
    if not proxy_data.get("host") or not proxy_data.get("port"):
        return None
    host = proxy_data["host"]
    port = proxy_data["port"]
    return f"http://{host}:{port}"


# Known rotating proxy provider hostnames and patterns
ROTATING_PROXY_PATTERNS = [
    # Major providers
    "smartproxy", "oxylabs", "brightdata", "brd.superproxy", "luminati",
    "proxyempire", "webshare", "iproyal", "proxy-seller", "packetstream",
    "soax", "netnut", "geosurf", "shifter", "stormproxies", "blazingseollc",
    # Common keywords in rotating proxy hostnames
    "gate.", "rotating", "residential", "mobile", "backconnect",
    "session", "sticky", "pool", "resi.", "res.", "rotate"
]

# Cache for verified rotating proxies: {proxy_key: {"rotating": bool, "ips": int, "verified_at": timestamp}}
verified_rotating_cache = {}


def get_proxy_cache_key(proxy_data):
    """Generate a unique cache key for a proxy"""
    if not proxy_data:
        return None
    host = proxy_data.get("host", "")
    port = proxy_data.get("port", "")
    user = proxy_data.get("username", "")
    return f"{host}:{port}:{user}"


def _persisted_rotating_status(proxy_data) -> Optional[bool]:
    """Return persisted rotating status if fresh enough, else None.

    We persist rotating detection on the proxy object so it survives restarts and
    doesn't rely only on in-memory caches.
    """
    if not proxy_data:
        return None
    val = proxy_data.get("rotating")
    if val is None:
        return None
    try:
        verified_at = float(proxy_data.get("rotating_verified_at") or 0)
    except Exception:
        verified_at = 0
    # If it's fresh (<= 7 days), trust it.
    if verified_at and (time.time() - verified_at) < (7 * 86400):
        return bool(val)
    # If explicitly false and recently verified (<= 24h), trust the negative too.
    if verified_at and (time.time() - verified_at) < 86400 and val is False:
        return False
    return None


async def quick_verify_rotating(proxy_data, num_checks=5):
    """Quick verification if proxy is rotating by checking IP diversity.
    
    Runs fewer checks than hqtest for speed. Returns (is_rotating, unique_ips, total_success)
    """
    if not proxy_data:
        return False, 0, 0
    
    ips_seen = set()
    successful = 0
    
    async def single_check():
        try:
            proxy_url = get_proxy_url(proxy_data)
            if not proxy_url:
                return None
            
            connector = ProxyConnector.from_url(proxy_url)
            async with aiohttp.ClientSession(connector=connector) as session:
                async with session.get(
                    "http://ip-api.com/json",
                    timeout=aiohttp.ClientTimeout(total=8)
                ) as resp:
                    if resp.status == 200:
                        data = await resp.json()
                        return data.get("query")
        except:
            pass
        return None
    
    # Run checks in parallel
    tasks = [single_check() for _ in range(num_checks)]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    
    for result in results:
        if isinstance(result, str) and result:
            successful += 1
            ips_seen.add(result)
    
    unique_ips = len(ips_seen)
    # If we see 2+ different IPs in 5 checks, it's rotating
    is_rotating = unique_ips >= 2
    
    return is_rotating, unique_ips, successful


async def verify_and_cache_rotating(proxy_data):
    """Verify if proxy is rotating and cache the result.
    
    Returns True if rotating, False if static/failed
    """
    cache_key = get_proxy_cache_key(proxy_data)
    if not cache_key:
        return False
    
    # Check cache first
    if cache_key in verified_rotating_cache:
        cached = verified_rotating_cache[cache_key]
        # Cache valid for 24 hours
        if time.time() - cached.get("verified_at", 0) < 86400:
            return cached.get("rotating", False)
    
    # Quick hostname check first (trusted providers / gateway endpoints)
    host = proxy_data.get("host", "").lower()
    trusted = [
        "smartproxy", "oxylabs", "brightdata", "brd.superproxy", "luminati",
        "iproyal", "soax", "netnut", "geosurf", "shifter", "proxyempire",
        "webshare", "packetstream",
        # common backconnect keywords
        "backconnect", "rotate", "rotating", "residential", "mobile", "pool", "gateway", "gate.",
    ]
    for pattern in trusted:
        if pattern in host:
            ts = time.time()
            verified_rotating_cache[cache_key] = {
                "rotating": True,
                "ips": 50,  # Assumed
                "verified_at": ts,
                "method": "hostname_hint"
            }
            # Persist onto the proxy object as well
            try:
                proxy_data["rotating"] = True
                proxy_data["rotating_ips"] = 50
                proxy_data["rotating_verified_at"] = ts
                proxy_data["rotating_method"] = "hostname_hint"
            except Exception:
                pass
            return True
    
    # Run quick verification
    is_rotating, unique_ips, successful = await quick_verify_rotating(proxy_data)
    
    ts = time.time()
    # Cache result
    verified_rotating_cache[cache_key] = {
        "rotating": is_rotating,
        "ips": unique_ips,
        "successful": successful,
        "verified_at": ts,
        "method": "verified"
    }
    # Persist onto the proxy object as well
    try:
        proxy_data["rotating"] = bool(is_rotating)
        proxy_data["rotating_ips"] = int(unique_ips)
        proxy_data["rotating_successful"] = int(successful)
        proxy_data["rotating_verified_at"] = ts
        proxy_data["rotating_method"] = "verified"
    except Exception:
        pass

    return is_rotating


def is_rotating_proxy(proxy_data):
    """Check if a proxy is rotating.
    
    Priority: 1) Verified cache, 2) Hostname patterns, 3) False
    """
    if not proxy_data:
        return False
    
    # Check persisted status first (survives restarts)
    persisted = _persisted_rotating_status(proxy_data)
    if persisted is not None:
        return persisted

    # Check verified cache next
    cache_key = get_proxy_cache_key(proxy_data)
    if cache_key and cache_key in verified_rotating_cache:
        cached = verified_rotating_cache[cache_key]
        # Cache valid for 24 hours
        if time.time() - cached.get("verified_at", 0) < 86400:
            return cached.get("rotating", False)
    
    # Fall back to hostname pattern detection
    host = proxy_data.get("host", "").lower()
    if not host:
        return False
    
    # Check against known patterns
    for pattern in ROTATING_PROXY_PATTERNS:
        if pattern in host:
            return True
    
    return False


async def is_rotating_proxy_async(proxy_data):
    """Async version that verifies and caches if needed"""
    if not proxy_data:
        return False

    # Prefer persisted status
    persisted = _persisted_rotating_status(proxy_data)
    if persisted is not None:
        return persisted
    
    cache_key = get_proxy_cache_key(proxy_data)
    
    # Check verified cache first
    if cache_key and cache_key in verified_rotating_cache:
        cached = verified_rotating_cache[cache_key]
        if time.time() - cached.get("verified_at", 0) < 86400:
            return cached.get("rotating", False)
    
    # Check hostname patterns (no async needed for trusted providers)
    host = proxy_data.get("host", "").lower()
    for pattern in ROTATING_PROXY_PATTERNS:
        if pattern in host:
            # Known pattern - verify async to confirm
            return await verify_and_cache_rotating(proxy_data)
    
    # Unknown hostname - verify to check if it rotates
    return await verify_and_cache_rotating(proxy_data)


async def background_verify_proxy_rotation(user_id: int, max_verify: int = 20) -> None:
    """Best-effort background rotation verification for a user's proxies.

    Used after bulk adds so true rotating proxies don't get miscounted as static.
    Persists results onto proxy dicts to survive restarts.
    """
    try:
        proxies = await get_user_proxies(user_id)
        if not proxies:
            return
        now_ts = time.time()

        # Prioritize likely-rotating (hostname patterns) and those missing/expired persisted flags.
        candidates = []
        for p in proxies:
            persisted = _persisted_rotating_status(p)
            if persisted is None:
                candidates.append(p)
                continue
            # If very old, refresh.
            try:
                ts = float(p.get("rotating_verified_at") or 0)
            except Exception:
                ts = 0
            if ts and (now_ts - ts) > (7 * 86400):
                candidates.append(p)

        if not candidates:
            return

        # Verify a limited number per run to avoid overloading providers.
        random.shuffle(candidates)
        candidates = candidates[: max(1, int(max_verify))]

        # Small parallelism (fast but safe)
        for i in range(0, len(candidates), 5):
            batch = candidates[i : i + 5]
            await asyncio.gather(*[verify_and_cache_rotating(p) for p in batch], return_exceptions=True)

        # Persist updated proxy dicts (rotating flags live on the objects)
        await save_user_proxies(user_id, proxies)
    except Exception:
        return


def expand_rotating_proxies(proxies, min_pool_size=50, user_id=None):
    """Smart proxy expansion for mixed proxy lists.
    
    AUTO-DETECTS rotating proxies and expands only those.
    Static proxies are kept as-is for normal round-robin usage.
    
    Args:
        proxies: List of proxy data dicts (mixed rotating + static)
        min_pool_size: Minimum pool size for parallel processing
        user_id: User ID (for future per-user settings)
    
    Returns:
        Expanded list with rotating proxies duplicated, static proxies as-is
    """
    if not proxies:
        return []
    
    # Separate rotating and static proxies
    rotating_proxies = []
    static_proxies = []
    
    for p in proxies:
        if is_rotating_proxy(p):
            rotating_proxies.append(p)
        else:
            static_proxies.append(p)
    
    # If no rotating proxies, return original list
    if not rotating_proxies:
        return proxies
    
    # Calculate how many copies we need of rotating proxies.
    # IMPORTANT: do NOT expand beyond a realistic concurrency per rotating endpoint,
    # otherwise you'll create many parallel requests through the same upstream and
    # get timeouts/429s (mass "Errors").
    static_count = len(static_proxies)
    rotating_slots = max(min_pool_size - static_count, min_pool_size // 2)
    # Cap by per-proxy safe concurrency (measured) or default limit.
    expanded_rotating_all = []
    for p in rotating_proxies:
        cap = int(p.get("safe_concurrency") or ROTATING_PROXY_CONNECTIONS)
        cap = max(1, min(cap, 50))
        expanded_rotating_all.extend([p] * cap)

    # If we couldn't build an expanded list, fall back.
    if not expanded_rotating_all:
        expanded_rotating_all = rotating_proxies

    max_rotating_slots = len(expanded_rotating_all)
    rotating_slots = min(rotating_slots, max_rotating_slots)

    random.shuffle(expanded_rotating_all)
    expanded_rotating = expanded_rotating_all[:rotating_slots]
    
    # Combine: expanded rotating + static
    combined = expanded_rotating + static_proxies
    
    # Log for debugging
    if len(rotating_proxies) > 0:
        log(f"[PROXY] Auto-detected {len(rotating_proxies)} rotating, {len(static_proxies)} static → expanded to {len(combined)} total", "INFO")
    
    return combined


async def _test_proxy_single_url(test_url, proxy_url_simple, auth, scheme, timeout):
    """Test a single URL with the proxy - helper for parallel testing"""
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(
                test_url,
                proxy=proxy_url_simple,
                proxy_auth=auth,
                timeout=aiohttp.ClientTimeout(total=timeout),
                headers={"User-Agent": "Mozilla/5.0"}
            ) as resp:
                if resp.status == 200:
                    return True, f"Alive ({scheme.upper()})"
                elif resp.status == 407:
                    return False, "Bad credentials"
                else:
                    return None, f"HTTP {resp.status}"
    except asyncio.TimeoutError:
        return None, "Timeout"
    except aiohttp.ClientProxyConnectionError:
        return False, "Proxy refused"
    except Exception as e:
        err = str(e).lower()
        if "407" in err:
            return False, "Bad credentials"
        elif "refused" in err or "reset" in err:
            return False, "Connection refused"
        return None, str(e)[:25]


async def _test_proxy_connector_url(test_url, proxy_url, scheme, timeout):
    """Test a single URL with ProxyConnector - helper for parallel testing"""
    try:
        connector = ProxyConnector.from_url(proxy_url)
        async with aiohttp.ClientSession(connector=connector) as session:
            async with session.get(
                test_url,
                timeout=aiohttp.ClientTimeout(total=timeout),
                headers={"User-Agent": "Mozilla/5.0"}
            ) as resp:
                if resp.status == 200:
                    return True, f"Alive ({scheme.upper()})"
                elif resp.status == 407:
                    return False, "Bad credentials"
                else:
                    return None, f"HTTP {resp.status}"
    except asyncio.TimeoutError:
        return None, "Timeout"
    except ProxyConnectionError:
        return False, "Connection refused"
    except Exception as e:
        err = str(e).lower()
        if "407" in err or "auth" in err:
            return False, "Bad credentials"
        elif "refused" in err or "reset" in err:
            return False, "Connection refused"
        return None, str(e)[:25]


async def check_proxy_alive(proxy_str, timeout=8):
    """
    FAST Universal proxy checker - supports HTTP, HTTPS, SOCKS4, SOCKS5.
    Tests multiple endpoints IN PARALLEL and returns on first success.
    """
    proxy_data = parse_proxy(proxy_str)
    
    if not proxy_data.get("host") or not proxy_data.get("port"):
        return False, "Invalid format"
    
    host = proxy_data["host"]
    port = proxy_data["port"]
    
    # Filter out invalid datacenter/CDN IPs (Cloudflare, etc.) - they're NOT proxies
    if is_invalid_datacenter_ip(host):
        return False, "CDN IP (not a proxy)"
    username = proxy_data.get("username")
    password = proxy_data.get("password")
    scheme = proxy_data.get("scheme", "http")
    
    # Test endpoints - fast and reliable
    test_urls = [
        "http://ip-api.com/json",
        "http://api.ipify.org?format=json",
    ]
    
    # Initialize last_error before conditionals
    last_error = "Connection failed"
    
    # METHOD 1: Native aiohttp proxy support (best for HTTP/HTTPS with auth) - PARALLEL
    if scheme in ["http", "https"]:
        proxy_url_simple = f"http://{host}:{port}"
        auth = aiohttp.BasicAuth(username, password) if username and password else None
        
        # Test all URLs in parallel, return on first success
        tasks = [_test_proxy_single_url(url, proxy_url_simple, auth, scheme, timeout) for url in test_urls]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple) and result[0] is True:
                return True, result[1]
            elif isinstance(result, tuple) and result[0] is False:
                return False, result[1]  # Definitive failure (bad auth, refused)
        
        # Get last error from results
        last_error = "Connection failed"
        for result in results:
            if isinstance(result, tuple) and result[1]:
                last_error = result[1]
    
    # METHOD 2: ProxyConnector (for SOCKS4/SOCKS5 and as HTTP fallback) - PARALLEL
    proxy_url = get_proxy_url(proxy_data)
    if proxy_url:
        tasks = [_test_proxy_connector_url(url, proxy_url, scheme, timeout) for url in test_urls]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple) and result[0] is True:
                return True, result[1]
            elif isinstance(result, tuple) and result[0] is False:
                return False, result[1]
        
        for result in results:
            if isinstance(result, tuple) and result[1]:
                last_error = result[1]
    
    return False, last_error


async def check_proxy_alive_lenient(proxy_str: str) -> Tuple[bool, str]:
    """
    Lenient proxy check for *adding* proxies:
    - retries once
    - uses longer timeouts to avoid false negatives from fast/overloaded checks
    """
    ok, reason = await check_proxy_alive(proxy_str, timeout=12)
    if ok:
        return True, reason
    # Retry only for non-definitive failures
    if any(x in (reason or "").lower() for x in ["timeout", "connection failed", "http", "poll"]):
        ok2, reason2 = await check_proxy_alive(proxy_str, timeout=18)
        if ok2:
            return True, reason2
        return False, reason2 or reason
    return False, reason


async def measure_proxy_max_concurrency(proxy_data, max_probe=None):
    """Estimate proxy max safe concurrency by probing parallel requests once.

    Stores *capacity*, not speed. This is a best-effort estimate and depends on provider limits.
    """
    if not proxy_data:
        return 1, 1

    max_probe = int(max_probe or PROXY_CONCURRENCY_MAX_PROBE)
    max_probe = max(1, min(max_probe, 50))

    proxy_url = get_proxy_url(proxy_data)
    if not proxy_url:
        return 1, 1

    scheme = (proxy_data.get("scheme") or "http").lower()
    username = proxy_data.get("username")
    password = proxy_data.get("password")

    # Candidate levels to probe (kept small to avoid long verification times)
    levels = [1, 2, 3, 4, 5, 6, 8, 10, 12, 15, 20, 25, 30, 40, 50]
    levels = [l for l in levels if l <= max_probe]
    if not levels:
        levels = [1]

    async def _one_request_http(session):
        try:
            proxy_simple = None
            proxy_auth = None
            if scheme in ["http", "https"]:
                proxy_simple = f"http://{proxy_data.get('host')}:{proxy_data.get('port')}"
                if username and password:
                    proxy_auth = aiohttp.BasicAuth(username, password)
            async with session.get(
                PROXY_CONCURRENCY_TEST_URL,
                proxy=proxy_simple,
                proxy_auth=proxy_auth,
                timeout=aiohttp.ClientTimeout(total=PROXY_CONCURRENCY_TIMEOUT),
                headers={"User-Agent": "Mozilla/5.0"},
            ) as resp:
                return resp.status == 200
        except Exception:
            return False

    async def _probe_level(level: int) -> float:
        """Return success rate for this concurrency level (0..1)."""
        ok = 0
        total = 0

        # SOCKS: use ProxyConnector; HTTP: native proxy params
        if scheme in ["socks4", "socks5", "socks5h"]:
            try:
                connector = ProxyConnector.from_url(proxy_url)
            except Exception:
                return 0.0
            timeout = aiohttp.ClientTimeout(total=PROXY_CONCURRENCY_TIMEOUT)
            async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
                for _ in range(max(1, PROXY_CONCURRENCY_TRIALS)):
                    tasks = [session.get(PROXY_CONCURRENCY_TEST_URL, headers={"User-Agent": "Mozilla/5.0"}) for _ in range(level)]
                    results = await asyncio.gather(*tasks, return_exceptions=True)
                    for r in results:
                        total += 1
                        if hasattr(r, "status") and getattr(r, "status", None) == 200:
                            ok += 1
                        else:
                            # If it's a response object we must close it
                            pass
                    # Close response bodies (avoid connector exhaustion)
                    for r in results:
                        try:
                            if hasattr(r, "release"):
                                r.release()
                        except Exception:
                            pass
        else:
            timeout = aiohttp.ClientTimeout(total=PROXY_CONCURRENCY_TIMEOUT)
            async with aiohttp.ClientSession(timeout=timeout) as session:
                for _ in range(max(1, PROXY_CONCURRENCY_TRIALS)):
                    tasks = [_one_request_http(session) for _ in range(level)]
                    results = await asyncio.gather(*tasks, return_exceptions=True)
                    for r in results:
                        total += 1
                        if r is True:
                            ok += 1

        return (ok / total) if total else 0.0

    max_ok = 1
    for lvl in levels:
        try:
            rate = await _probe_level(lvl)
        except Exception:
            rate = 0.0
        if rate >= PROXY_CONCURRENCY_MIN_SUCCESS:
            max_ok = lvl
        else:
            break

    safe = max(1, max_ok - max(0, PROXY_CONCURRENCY_MARGIN))
    return max_ok, safe


