async def add_user_proxy(user_id, proxy_str):
    """Add proxy to user's list"""
    # Get current proxies (from DB or file)
    proxies = await get_user_proxies(user_id)
    
    # Check if proxy already exists
    for p in proxies:
        if p.get("raw") == proxy_str:
            return False, "Proxy already exists"
    
    # Parse and validate proxy
    proxy_data = parse_proxy(proxy_str)
    if not proxy_data.get("host") or not proxy_data.get("port"):
        return False, "Invalid proxy format"
    
    proxies.append(proxy_data)
    success = await save_user_proxies(user_id, proxies)
