# ==================== USER CARDS MANAGEMENT ====================

async def get_user_cards(user_id):
    """Get user's card queue"""
    db_result = await db_get_user_cards(user_id)
    if db_result is not None:
        # If DB returned empty but we have a non-empty local backup (from a prior DB save failure),
        # prefer the backup so checks still work.
        if db_result:
            return db_result
        filepath = get_user_file(user_id, "cards.txt")
        if os.path.exists(filepath) and os.path.getsize(filepath) > 0:
            try:
                async with aiofiles.open(filepath, 'r', encoding='utf-8') as f:
                    lines = await f.readlines()
                file_cards = [line.strip() for line in lines if line.strip() and '|' in line]
                if file_cards:
                    return file_cards
            except Exception:
                pass
        return []

    # If DB errored, fall back to local file (helps when DB is temporarily down)
    filepath = get_user_file(user_id, "cards.txt")
    if not os.path.exists(filepath):
        return []
    async with aiofiles.open(filepath, 'r', encoding='utf-8') as f:
        lines = await f.readlines()
    return [line.strip() for line in lines if line.strip() and '|' in line]


async def add_user_cards(user_id, cards_text, auto_dedup=True):
    """Add cards to user's queue with automatic deduplication"""
    # Extract and normalize cards from any text (supports | / : spaces, and "gibberish")
    cleaned_cards, stats = clean_cards_from_text(cards_text or "", validate_luhn=False, dedupe=True)
    if not cleaned_cards:
        return 0, 0  # (added, duplicates_removed)

    # Get existing cards for dedup vs queue
    existing_cards = await get_user_cards(user_id)
    existing_set = set(existing_cards)

    if auto_dedup:
        truly_new = [c for c in cleaned_cards if c not in existing_set]
        dupes_from_existing = len(cleaned_cards) - len(truly_new)
        dupes_within_text = int(stats.get("duplicates", 0) or 0)
        total_dupes = dupes_from_existing + dupes_within_text

        final_cards = existing_cards + truly_new
        ok = await save_user_cards(user_id, final_cards)
        if not ok:
            return 0, total_dupes
        return len(truly_new), total_dupes

    # No dedup requested: append extracted cards as-is
    final_cards = existing_cards + cleaned_cards
    ok = await save_user_cards(user_id, final_cards)
    if not ok:
        return 0, 0
    return len(cleaned_cards), 0


async def save_user_cards(user_id, cards):
    """Save list of cards - uses database when available, skips slow file I/O"""
    if USE_DATABASE:
        ok = await db_save_user_cards(user_id, cards)
        if ok:
            # Best-effort cleanup of any stale local backup.
            try:
                filepath = get_user_file(user_id, "cards.txt")
                if os.path.exists(filepath):
                    os.remove(filepath)
            except Exception:
                pass
            return True
        # DB save failed (timeout/transient). Fall back to file so queue still works.
        print(f"[DB] Warning: failed to save cards for user {user_id}, falling back to file storage")
    # File storage (primary when no DB, backup when DB fails)
    filepath = get_user_file(user_id, "cards.txt")
    async with aiofiles.open(filepath, 'w', encoding='utf-8') as f:
        await f.write("\n".join(cards))  # Write all at once, not line by line
    return True


async def clear_user_cards(user_id):
    """Clear user's card queue - uses fast DELETE"""
    if USE_DATABASE:
        await db_clear_user_cards(user_id)  # Fast direct DELETE
    # Always clear local backup too (prevents stale queue reappearing when DB is empty).
    filepath = get_user_file(user_id, "cards.txt")
    async with aiofiles.open(filepath, 'w', encoding='utf-8') as f:
        await f.write("")


async def save_user_result(user_id, result_type, data):
    """Save result to user's result file"""
    # Always keep file logs for local deployments, but protect against concurrent writes.
    filepath = get_user_file(user_id, f"{result_type}.txt")
    try:
        global _RESULT_FILE_LOCKS
        _RESULT_FILE_LOCKS
    except NameError:
        _RESULT_FILE_LOCKS = defaultdict(asyncio.Lock)
    lock = _RESULT_FILE_LOCKS[filepath]
    async with lock:
        async with aiofiles.open(filepath, 'a', encoding='utf-8') as f:
            await f.write(data + "\n")


