@bot.message_handler(commands=['approve'])
async def cmd_approve(message):
    user_id = message.from_user.id
    # Allow owner AND admins
    if not await is_admin(user_id):
        return
    
    parts = message.text.split()
    if len(parts) < 2:
        await bot.reply_to(message, "Usage: /approve <user_id>")
        return
    
    try:
        target_id = int(parts[1])
        await add_approved_user(target_id)
        await remove_pending_user(target_id)
        approver = "Owner" if user_id == OWNER_ID else "Admin"
        await bot.reply_to(message, f"✅ User {target_id} approved by {approver}!")
        await safe_send_message(target_id, "✅ *Your registration has been approved!*\n\nUse /start to begin.", parse_mode='Markdown')
        # Notify owner if an admin approved
        if user_id != OWNER_ID:
            await safe_send_message(OWNER_ID, f"📢 Admin `{user_id}` approved user `{target_id}`", parse_mode='Markdown')
    except ValueError:
        await bot.reply_to(message, "Invalid user ID")


@bot.message_handler(commands=['approveall'])
async def cmd_approveall(message):
    """Approve ALL pending registration requests at once"""
    user_id = message.from_user.id
    # Allow owner AND admins
    if not await is_admin(user_id):
        return
    
    pending = await get_pending_users()
    users = pending.get("users", {})
    
    if not users:
        await bot.reply_to(message, "✅ No pending registrations to approve.")
        return
    
    approved_count = 0
    for uid_str in list(users.keys()):
        try:
            uid = int(uid_str)
            await add_approved_user(uid)
            await remove_pending_user(uid)
            approved_count += 1
            # Notify each user
            await safe_send_message(uid, f"✅ {bold_sans('APPROVED')}\n\nYour registration has been approved!\nUse /start to begin", parse_mode='Markdown')
        except:
            continue
    
    approver = "Owner" if user_id == OWNER_ID else "Admin"
    await bot.reply_to(message, f"👑 {bold_sans('ALL APPROVED')}\n\n✅ Approved: *{approved_count}* users\nBy: {approver}", parse_mode='Markdown')
    
    # Notify owner if an admin approved all
    if user_id != OWNER_ID:
        await safe_send_message(OWNER_ID, f"📢 Admin `{user_id}` approved all {approved_count} pending users", parse_mode='Markdown')


