@bot.message_handler(commands=['checkproxies'])
async def cmd_checkproxies(message):
    """ULTRA-FAST parallel proxy checker - 200+ concurrent checks"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    proxies = await get_user_proxies(user_id)
    
    if not proxies:
        await bot.reply_to(message, "No proxies to check.")
        return
    
    status_msg = await bot.reply_to(message, f"⚡ Ultra-fast checking {len(proxies)} proxies...")
    start_time = time.time()
    
    # Fast but safer: lower parallelism reduces false "dead" from burst timeouts
    BATCH_SIZE = 75
    live_proxies = []
    dead_proxies = []
    
    async def check_single(p):
        raw = p.get("raw", "")
        alive, reason = await check_proxy_alive(raw, timeout=10)
        if not alive and (reason or "").lower() in ["timeout", "connection failed"]:
            alive, reason = await check_proxy_alive(raw, timeout=15)
        return (p, alive, reason)
    
    # Process in batches of 200
    for batch_start in range(0, len(proxies), BATCH_SIZE):
        batch = proxies[batch_start:batch_start + BATCH_SIZE]
        
        # Update progress
        progress = min(batch_start + BATCH_SIZE, len(proxies))
        try:
            await bot.edit_message_text(
                f"⚡ Checking... {progress}/{len(proxies)} ({int(progress/len(proxies)*100)}%)\n✅ Live: {len(live_proxies)} | ❌ Dead: {len(dead_proxies)}",
                chat_id=chat_id, message_id=status_msg.message_id
            )
        except: pass
        
        # Check entire batch in parallel
        tasks = [check_single(p) for p in batch]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple):
                p, alive, reason = result
                if alive:
                    live_proxies.append(p)
                else:
                    dead_proxies.append({**p, "reason": reason})
    
    elapsed = time.time() - start_time
    speed = len(proxies) / elapsed if elapsed > 0 else 0
    
    # Auto-remove dead proxies
    save_failed = False
    if dead_proxies:
        save_success = await save_user_proxies(user_id, live_proxies)
        if not save_success:
            save_failed = True
    
    if save_failed:
        result_text = f"""
❌ *Database Save Failed*

Proxy cleanup completed but could not save changes.
Please try again.
"""
    else:
        result_text = f"""
⚡ *Ultra-Fast Proxy Check Complete*
━━━━━━━━━━━━━━━━━━━━━━
⏱ Time: {elapsed:.1f}s ({speed:.0f} proxies/sec)
✅ Live: *{len(live_proxies)}* (kept)
❌ Dead: *{len(dead_proxies)}* (auto-removed)
━━━━━━━━━━━━━━━━━━━━━━
"""
    try:
        await bot.edit_message_text(result_text, chat_id=chat_id, message_id=status_msg.message_id, parse_mode='Markdown')
    except:
        await bot.send_message(chat_id, result_text, parse_mode='Markdown')


