@bot.message_handler(commands=['verifyproxies'])
async def cmd_verifyproxies(message):
    """Verify all user proxies for rotating detection"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    proxies = await get_user_proxies(user_id)
    if not proxies:
        await bot.reply_to(message, "📭 No proxies to verify.")
        return
    
    # Build worklist:
    # - proxies whose rotating status cache is missing/expired
    # - rotating proxies missing a stored safe_concurrency (one-time probe)
    to_verify_rotation = []
    to_probe_concurrency = []

    now_ts = time.time()
    for p in proxies:
        cache_key = get_proxy_cache_key(p)
        if cache_key:
            cached = verified_rotating_cache.get(cache_key)
            if not cached or (now_ts - cached.get("verified_at", 0) > 86400):
                to_verify_rotation.append(p)
        else:
            # No cache key, still attempt verification
            to_verify_rotation.append(p)

    # We'll probe concurrency only for proxies detected as rotating and lacking stored limits.
    # This is persistent (saved to DB/file), so we don't need to repeat later.
    for p in proxies:
        if p.get("safe_concurrency"):
            continue
        if is_rotating_proxy(p):
            to_probe_concurrency.append(p)
    
    if not to_verify_rotation and not to_probe_concurrency:
        await bot.reply_to(message, "✅ All proxies already verified (including concurrency limits)!")
        return
    
    status_msg = await bot.reply_to(
        message,
        f"⏳ Verifying {len(to_verify_rotation)} proxies + probing {len(to_probe_concurrency)} rotating concurrency limits..."
    )
    
    # Verify in parallel batches
    rotating_found = 0
    static_found = 0
    probed = 0
    
    for i in range(0, len(to_verify_rotation), 10):
        batch = to_verify_rotation[i:i+10]
        tasks = [verify_and_cache_rotating(p) for p in batch]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if result is True:
                rotating_found += 1
            else:
                static_found += 1

    # Persist rotation flags from verify step (verify_and_cache_rotating mutates proxy dicts)
    try:
        await save_user_proxies(user_id, proxies)
    except Exception:
        pass

    # Probe per-proxy safe concurrency (sequential small batches to avoid long stalls)
    # Only does work for proxies that are alive and rotating; saves results permanently.
    # This intentionally runs with low parallelism to avoid overwhelming the provider during testing.
    for i in range(0, len(to_probe_concurrency), 2):
        batch = to_probe_concurrency[i:i+2]
        for p in batch:
            try:
                alive, _ = await check_proxy_alive(p.get("raw", ""), timeout=8)
                if not alive:
                    continue
                max_ok, safe = await measure_proxy_max_concurrency(p, max_probe=PROXY_CONCURRENCY_MAX_PROBE)
                p["max_concurrency"] = int(max_ok)
                p["safe_concurrency"] = int(safe)
                p["concurrency_tested_at"] = int(time.time())
                p["concurrency_test_url"] = PROXY_CONCURRENCY_TEST_URL
                probed += 1
            except Exception:
                continue

    # Persist updated proxy data (safe_concurrency, etc.)
    if probed > 0:
        await save_user_proxies(user_id, proxies)
    
    result_msg = f"""
✅ *Verification Complete*
━━━━━━━━━━━━━━━━━━━
• 🔄 Rotating found: `{rotating_found}`
• 🔒 Static found: `{static_found}`

🔧 Concurrency probed: `{probed}` (saved permanently)
Rotating cache is 24h, but concurrency limits are kept.
"""
    try:
        await bot.edit_message_text(result_msg, chat_id=message.chat.id, message_id=status_msg.message_id, parse_mode='Markdown')
    except:
        await bot.send_message(message.chat.id, result_msg, parse_mode='Markdown')


@bot.message_handler(commands=['proxyhealth', 'proxyclean'])
async def cmd_proxyhealth(message):
    """ULTRA-FAST proxy health check with auto-remove dead proxies"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    proxies = await get_user_proxies(user_id)
    
    if not proxies:
        await bot.reply_to(message, "📭 No proxies to check. Use /addproxy first.")
        return
    
    # Send initial status message
    status_msg = await bot.send_message(chat_id, f"⚡ Ultra-fast checking {len(proxies)} proxies...", parse_mode='Markdown')
    start_time = time.time()
    
    live_proxies = []
    dead_proxies = []
    
    # Fast but safer: lower parallelism reduces false "dead" from burst timeouts
    BATCH_SIZE = 75
    
    async def check_single(p):
        raw = p.get("raw", "")
        alive, reason = await check_proxy_alive(raw, timeout=10)
        if not alive and (reason or "").lower() in ["timeout", "connection failed"]:
            alive, reason = await check_proxy_alive(raw, timeout=15)
        return (p, alive, reason)
    
    # Process in batches of 200
    for batch_start in range(0, len(proxies), BATCH_SIZE):
        batch = proxies[batch_start:batch_start + BATCH_SIZE]
        
        # Update progress
        progress = min(batch_start + BATCH_SIZE, len(proxies))
        percent = int(progress / len(proxies) * 100)
        bar_filled = int(percent / 10)
        bar = '█' * bar_filled + '░' * (10 - bar_filled)
        try:
            await bot.edit_message_text(f"""
⚡ *Ultra-Fast Proxy Check*
`[{bar}]` {percent}%

✅ Live: *{len(live_proxies)}*
❌ Dead: *{len(dead_proxies)}*
            """, chat_id=chat_id, message_id=status_msg.message_id, parse_mode='Markdown')
        except: pass
        
        # Check entire batch in parallel
        tasks = [check_single(p) for p in batch]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple):
                p, alive, reason = result
                if alive:
                    live_proxies.append(p)
                else:
                    dead_proxies.append({**p, "reason": reason})
    
    elapsed = time.time() - start_time
    speed = len(proxies) / elapsed if elapsed > 0 else 0
    
    # Final result
    save_failed = False
    if dead_proxies:
        # Remove dead proxies
        save_success = await save_user_proxies(user_id, live_proxies)
        if not save_success:
            save_failed = True
        
        dead_list = "\n".join([f"• `{p.get('host', '?')}:{p.get('port', '?')}` - {p.get('reason', 'Dead')}" for p in dead_proxies[:10]])
        if len(dead_proxies) > 10:
            dead_list += f"\n_...and {len(dead_proxies) - 10} more_"
        
        if save_failed:
            result_text = f"""
❌ *Database Save Failed*

Proxy cleanup completed but could not save changes.
Please try again.
"""
        else:
            result_text = f"""
⚡ *Ultra-Fast Cleanup Complete*
━━━━━━━━━━━━━━━━━━━━━━
⏱ Time: {elapsed:.1f}s ({speed:.0f}/sec)
✅ Live: *{len(live_proxies)}* (kept)
❌ Dead: *{len(dead_proxies)}* (removed)
━━━━━━━━━━━━━━━━━━━━━━
🗑 Removed: {dead_list}
        """
    else:
        result_text = f"""
⚡ *All Proxies Healthy*
━━━━━━━━━━━━━━━━━━━━━━
⏱ Time: {elapsed:.1f}s ({speed:.0f}/sec)
✅ All *{len(live_proxies)}* proxies are live!
━━━━━━━━━━━━━━━━━━━━━━
        """
    
    result_buttons = create_inline_keyboard([
        [("📋 View Proxies", "view_proxies"), ("➕ Add More", "add_proxy_info")],
        [("🔙 Main Menu", "menu_back")]
    ])
    
    try:
        await bot.edit_message_text(result_text, chat_id=chat_id, message_id=status_msg.message_id, parse_mode='Markdown', reply_markup=result_buttons)
    except:
        await bot.send_message(chat_id, result_text, parse_mode='Markdown', reply_markup=result_buttons)


async def save_user_proxies(user_id, proxies):
    """Save user's proxy list - skip file I/O when using database"""
    if USE_DATABASE:
        db_success = await db_save_user_proxies(user_id, proxies)
        return db_success  # Skip file I/O when using database
    filepath = get_user_file(user_id, "proxies.json")
    await save_json_file(filepath, {"proxies": proxies})
    return True


