@bot.message_handler(commands=['hqtest'])
async def cmd_hqtest(message):
    """High-Quality proxy analysis with multi-check quality scoring"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    args = message.text.split(maxsplit=1)
    if len(args) < 2:
        usage_text = f"""
{bold_sans("Proxy Analysis")}

► Usage: `/hqtest <proxy>`

{bold_serif("Supported Formats")}
• host:port:user:pass
• user:pass@host:port
• socks5://host:port

{bold_serif("Features")}
• Multi-region testing
• Quality scoring (0-100%)
• Provider detection
        """
        await bot.reply_to(message, usage_text, parse_mode='Markdown')
        return
    
    proxy_str = args[1].strip()
    proxy_data = parse_proxy(proxy_str)
    
    if not proxy_data.get("host") or not proxy_data.get("port"):
        await bot.reply_to(message, f"❌ Invalid proxy format: `{proxy_str}`", parse_mode='Markdown')
        return
    
    # Display formatted proxy (with masked password)
    display_proxy = format_proxy_display(proxy_str, mask_pass=True)
    
    status_msg = await bot.reply_to(message, f"""
{bold_sans("Proxy Analysis")}

► `{display_proxy}`

⏳ Running quality checks...
    """, parse_mode='Markdown')
    
    start_time = time.time()
    
    # Run multiple parallel checks to gather statistics
    NUM_CHECKS = 20
    countries_seen = {}
    successful_checks = 0
    failed_checks = 0
    response_times = []
    ips_seen = set()
    
    async def single_quality_check():
        """Perform a single proxy check and return IP/country info"""
        check_start = time.time()
        try:
            proxy_url = get_proxy_url(proxy_data)
            if not proxy_url:
                return None, None, 0
            
            connector = ProxyConnector.from_url(proxy_url)
            async with aiohttp.ClientSession(connector=connector) as session:
                async with session.get(
                    "http://ip-api.com/json",
                    timeout=aiohttp.ClientTimeout(total=10)
                ) as resp:
                    if resp.status == 200:
                        try:
                            data = await resp.json()
                            country = data.get("country", "Unknown")
                            ip = data.get("query", "Unknown")
                            rt = time.time() - check_start
                            return ip, country, rt
                        except:
                            pass
        except:
            pass
        return None, None, 0
    
    # Run checks in parallel
    tasks = [single_quality_check() for _ in range(NUM_CHECKS)]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    
    for result in results:
        if isinstance(result, tuple):
            ip, country, rt = result
            if ip and country:
                successful_checks += 1
                ips_seen.add(ip)
                countries_seen[country] = countries_seen.get(country, 0) + 1
                response_times.append(rt)
            else:
                failed_checks += 1
        else:
            failed_checks += 1
    
    elapsed = time.time() - start_time
    
    # Calculate quality score
    success_rate = (successful_checks / NUM_CHECKS) * 100 if NUM_CHECKS > 0 else 0
    avg_response = sum(response_times) / len(response_times) if response_times else 0
    ip_diversity = len(ips_seen)
    region_diversity = len(countries_seen)
    
    # Quality formula: success_rate * 0.6 + response_speed * 0.2 + ip_diversity * 0.2
    speed_score = max(0, 100 - (avg_response * 20))  # Faster = higher score
    diversity_bonus = min(30, ip_diversity * 5)  # Bonus for rotating IPs
    quality_score = (success_rate * 0.6) + (speed_score * 0.2) + diversity_bonus
    quality_score = min(100, max(0, quality_score))
    
    # Quality verdict
    if quality_score >= 80:
        verdict = "Excellent proxy quality."
    elif quality_score >= 60:
        verdict = "Good proxy, works well."
    elif quality_score >= 40:
        verdict = "Average quality, may work."
    elif quality_score >= 20:
        verdict = "Poor quality, unreliable."
    else:
        verdict = "Proxy needs a funeral."
    
    # Format country breakdown
    country_lines = []
    sorted_countries = sorted(countries_seen.items(), key=lambda x: -x[1])
    for country, count in sorted_countries[:5]:
        country_lines.append(f"• {country} ({count})")
    
    if not country_lines:
        country_lines.append("• No successful connections")
    
    # Region diversity comment
    if region_diversity > 3:
        region_comment = "Good regional diversity."
    elif region_diversity > 1:
        region_comment = "Some regional rotation."
    else:
        region_comment = "Proxy rarely changes region."
    
    # Provider detection (based on hostname)
    host = proxy_data.get("host", "").lower()
    provider = "Unknown"
    if "pvdata" in host or "pvhub" in host:
        provider = "PVData"
    elif "webshare" in host:
        provider = "Webshare"
    elif "smartproxy" in host:
        provider = "Smartproxy"
    elif "luminati" in host or "brightdata" in host:
        provider = "Bright Data"
    elif "oxylabs" in host:
        provider = "Oxylabs"
    elif "storm" in host:
        provider = "Storm Proxies"
    elif "datacenter" in host or "dc." in host:
        provider = "Datacenter"
    elif "residential" in host or "resi" in host:
        provider = "Residential"
    
    # Build premium result message
    result_text = f"""
{bold_sans("Proxy Analysis")}

► `{display_proxy}`

{bold_serif("Quality")}: {quality_score:.1f}%
{verdict}

{bold_serif("Top Countries")}
{chr(10).join(country_lines)}
{region_comment}

{bold_serif("Stats")}
• Checks: {successful_checks}/{NUM_CHECKS} passed
• IPs Seen: {ip_diversity}
• Avg Response: {avg_response:.2f}s
• Provider: {provider}

{bold_serif("Took Time")}: {elapsed:.2f} sec
    """
    
    try:
        await bot.edit_message_text(result_text, chat_id=chat_id, message_id=status_msg.message_id, parse_mode='Markdown')
    except:
        await bot.send_message(chat_id, result_text, parse_mode='Markdown')


