# Store for pptest processing status
user_pptest_processing = {}
user_pptest_stats = {}

async def auto_detect_paypal_site(url, depth=0):
    """Automatically detect form_id and ajax_url from a PayPal/GiveWP donation page"""
    from urllib.parse import urlparse, urljoin
    import re
    
    try:
        if not url.startswith("http"):
            url = f"https://{url}"
        
        parsed = urlparse(url)
        base_url = f"{parsed.scheme}://{parsed.netloc}"
        ajax_url = f"{base_url}/wp-admin/admin-ajax.php"
        site_name = parsed.netloc.replace("www.", "")
        
        headers = {
            'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
            'accept-language': 'en-US,en;q=0.9',
            'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        }
        
        connector = aiohttp.TCPConnector(limit=10)
        async with aiohttp.ClientSession(connector=connector, max_line_size=32768, max_field_size=32768) as session:
            async with session.get(url, headers=headers, timeout=aiohttp.ClientTimeout(total=30), allow_redirects=True) as response:
                if response.status != 200:
                    return None, f"HTTP {response.status}"
                
                html = await response.text()
                
                # Try to find give-form-id in various formats
                form_id = None
                
                # Pattern 1: name="give-form-id" value="123"
                match = re.search(r'name=["\']give-form-id["\'][^>]*value=["\'](\d+)["\']', html)
                if match:
                    form_id = match.group(1)
                
                # Pattern 2: value="123" name="give-form-id"
                if not form_id:
                    match = re.search(r'value=["\'](\d+)["\'][^>]*name=["\']give-form-id["\']', html)
                    if match:
                        form_id = match.group(1)
                
                # Pattern 3: data-form-id="123"
                if not form_id:
                    match = re.search(r'data-form-id=["\'](\d+)["\']', html)
                    if match:
                        form_id = match.group(1)
                
                # Pattern 4: give_form_id or giveFormId in JS
                if not form_id:
                    match = re.search(r'["\']?(?:give_form_id|giveFormId|formId)["\']?\s*[:=]\s*["\']?(\d+)["\']?', html)
                    if match:
                        form_id = match.group(1)
                
                # Pattern 5: id="give-form-123"
                if not form_id:
                    match = re.search(r'id=["\']give-form-(\d+)["\']', html)
                    if match:
                        form_id = match.group(1)
                
                # Pattern 6: class contains give-form with data attributes
                if not form_id:
                    match = re.search(r'class=["\'][^"\']*give-form[^"\']*["\'][^>]*data-id=["\'](\d+)["\']', html)
                    if match:
                        form_id = match.group(1)
                
                # If no form found and we haven't searched deep yet, look for donation links
                if not form_id and depth < 2:
                    # Check if this is a GiveWP site at all
                    is_givewp = 'give-form' in html.lower() or 'givewp' in html.lower() or 'give_forms' in html.lower()
                    
                    if not is_givewp:
                        # Try common donation paths
                        common_paths = ['/donate', '/donate/', '/donation', '/donation/', '/give', '/give/', '/support', '/contribute']
                        
                        for path in common_paths:
                            try_url = urljoin(base_url, path)
                            log(f"[ADDPP] Trying {try_url}...", "DEBUG")
                            result, err = await auto_detect_paypal_site(try_url, depth + 1)
                            if result:
                                return result, None
                        
                        # Also try to find donation links in the page
                        donate_links = re.findall(r'href=["\']([^"\']*(?:/donat|/give|/support|/contribut)[^"\']*)["\']', html, re.IGNORECASE)
                        for link in donate_links[:3]:
                            full_link = urljoin(base_url, link)
                            if parsed.netloc in full_link:  # Same domain only
                                log(f"[ADDPP] Trying found link: {full_link}...", "DEBUG")
                                result, err = await auto_detect_paypal_site(full_link, depth + 1)
                                if result:
                                    return result, None
                        
                        return None, "Not a GiveWP/PayPal donation site. Provide the donation page URL."
                
                if not form_id:
                    return None, "Could not find GiveWP form ID on page"
                
                # Verify there's a PayPal Commerce integration
                has_paypal = 'paypal-commerce' in html.lower() or 'data-client-token' in html or 'braintree' in html.lower()
                
                if not has_paypal:
                    log(f"[ADDPP] Warning: PayPal Commerce not detected on {url}", "WARNING")
                
                site_data = {
                    "url": url,
                    "ajax_url": ajax_url,
                    "form_id": form_id,
                    "name": site_name
                }
                
                return site_data, None
                
    except asyncio.TimeoutError:
        return None, "Connection timeout"
    except Exception as e:
        return None, str(e)[:50]


@bot.message_handler(commands=['addpp'])
async def cmd_addpp(message):
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    text = message.text.replace('/addpp', '').strip()
    
    if not text:
        await bot.reply_to(message, r"""
💳 *Add PayPal Donation Sites*

⚠️ *Only works with GiveWP donation sites*
\(Charity/nonprofit sites using WordPress GiveWP plugin\)

*Usage:* Just provide the donation page URL
`/addpp https://charity.org/donate/`

The bot will auto\\-detect the form ID\\!

*Tip:* Search Google for "donate GiveWP" to find compatible sites\\.
        """, parse_mode='MarkdownV2')
        return
    
    lines = [l.strip() for l in text.split('\n') if l.strip()]
    
    added = 0
    errors = []
    
    for line in lines:
        parts = line.split('|')
        
        # Check if it's just a URL (no pipes or only 1 part)
        if len(parts) == 1 or (len(parts) == 2 and not parts[1]):
            # Auto-detect mode
            url = parts[0].strip()
            await bot.reply_to(message, f"🔄 Scanning {url}...")
            
            site_data, error = await auto_detect_paypal_site(url)
            
            if site_data:
                success, result = await add_user_paypal_site(user_id, site_data)
                if success:
                    added += 1
                    await bot.send_message(message.chat.id, f"✅ Found: {site_data['name']}\n📋 Form ID: {site_data['form_id']}")
                else:
                    errors.append(f"{url}: {result}")
            else:
                errors.append(f"{url}: {error}")
        
        elif len(parts) >= 4:
            # Manual format
            site_data = {
                "url": parts[0].strip(),
                "ajax_url": parts[1].strip(),
                "form_id": parts[2].strip(),
                "name": parts[3].strip()
            }
            success, result = await add_user_paypal_site(user_id, site_data)
            if success:
                added += 1
            else:
                errors.append(f"{site_data['name']}: {result}")
        else:
            errors.append(f"Invalid format: {line[:30]}...")
    
    if added > 0 or errors:
        msg = f"✅ Added {added} PayPal sites!"
        if errors:
            msg += f"\n\n⚠️ Errors:\n" + "\n".join(errors[:5])
        await bot.send_message(message.chat.id, msg)


