async def get_user_woo_sites(user_id):
    """Get user's WooCommerce sites"""
    db_result = await db_get_user_woo_sites(user_id)
    if db_result is not None:
        return db_result if db_result else WooCommerceGateRotator.GATES
    # If USE_DATABASE is True but DB returned None (error), return defaults
    if USE_DATABASE:
        print(f"[DB] Warning: DB error for user {user_id} woo sites, returning defaults")
        return WooCommerceGateRotator.GATES
    filepath = get_user_file(user_id, "woo_sites.json")
    if not os.path.exists(filepath):
        return WooCommerceGateRotator.GATES
    try:
        data = await load_json_file(filepath)
        sites = data.get("sites", [])
        return sites if sites else WooCommerceGateRotator.GATES
    except:
        return WooCommerceGateRotator.GATES

async def add_user_woo_site(user_id, url, name):
    """Add a WooCommerce site"""
    sites = await db_get_user_woo_sites(user_id)
    if sites is None:
        sites = []
            
    # Check duplicates
    for s in sites:
        if s['url'] == url:
            return False, "Site already exists"
            
    sites.append({"url": url, "name": name})
    await save_user_woo_sites(user_id, sites)
    return True, "Added"

async def remove_user_woo_site(user_id, index):
    """Remove a WooCommerce site"""
    sites = await db_get_user_woo_sites(user_id)
    if sites is None:
        return False, "No custom sites found"
        
    if index < 0 or index >= len(sites):
        return False, "Invalid index"
            
    removed = sites.pop(index)
    await save_user_woo_sites(user_id, sites)
    return True, removed['name']


async def save_user_woo_sites(user_id, sites):
    """Save user's WooCommerce sites list - skip file I/O when using database"""
    if USE_DATABASE:
        await db_save_user_woo_sites(user_id, sites)
        return  # Skip file I/O when using database
    filepath = get_user_file(user_id, "woo_sites.json")
    await save_json_file(filepath, {"sites": sites})

async def clear_user_woo_sites(user_id):
    """Clear all WooCommerce sites"""
    await save_user_woo_sites(user_id, [])

