@bot.message_handler(commands=['addsh'])
async def cmd_addsh(message):
    """Add Shopify sites (validated on add)"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    text = message.text.replace('/addsh', '').strip()
    
    if not text:
        await bot.reply_to(message, r"""
🛒 *Add Shopify Sites*

*Method 1:* Command
`/addsh site1.com site2.com`

*Method 2:* Multiple lines
```
/addsh store1.myshopify.com
store2.com
store3.myshopify.com
```

*Method 3:* 📁 Upload TXT file
Send any `.txt` file containing URLs!
Name it `sites.txt` or `shopify.txt` for best detection.

⚡ Sites added instantly! Dead sites skipped during checking.
        """, parse_mode='Markdown')
        return
    
    # Parse sites
    cleaned = text.replace('\n', ' ').replace(',', ' ').replace('|', ' ').replace(';', ' ')
    sites = [s.strip() for s in cleaned.split() if s.strip() and len(s.strip()) > 4]
    sites = [s for s in sites if s.lower() not in ['http', 'https', 'www', 'com', 'net', 'org']]
    
    if not sites:
        await bot.reply_to(message, "❌ No valid sites found!")
        return
    
    # Use a user proxy (if available) to validate sites, since many stores block direct DC IPs.
    proxies = await get_user_proxies(user_id)
    proxy_data = random.choice(proxies) if proxies else None

    # Snapshot existing sites once (DB mode uses cache; this avoids repeated reads per-site).
    existing_sites = await get_user_shopify_sites(user_id)
    existing_set = set(existing_sites or [])

    ok_added = 0
    dupes = 0
    dead = 0
    blocked = 0
    captcha = 0
    no_products = 0
    fake = 0  # Sites showing fake CHARGED for gen cards
    errors = 0

    # Validate + add sequentially (avoids hammering Shopify / endpoints)
    for site in sites:
        # Normalize via add_user_shopify_site logic (lowercase, https, no trailing slash)
        normalized = site.strip().lower()
        if not normalized.startswith("http"):
            normalized = f"https://{normalized}"
        normalized = normalized.rstrip("/")

        # Detect duplicates early
        if normalized in existing_set:
            dupes += 1
            continue

        is_ok, status, details = await validate_shopify_site_on_add(normalized, proxy_data=proxy_data)
        log(f"[ADDSH] {normalized} => ok={is_ok}, status={status}, details={details}", "INFO")
        if is_ok:
            success, _ = await add_user_shopify_site(user_id, normalized)
            if success:
                ok_added += 1
                existing_set.add(normalized)
                # Mark candidate/verified hint in tracker (non-destructive)
                try:
                    tracker = await get_site_quality_tracker(user_id)
                    st = tracker.get_site_stats(normalized)
                    if st.get("status") != "blacklisted":
                        st["status"] = "candidate"
                        st["last_success"] = datetime.now().isoformat()
                        await tracker.save()
                except Exception:
                    pass
            else:
                dupes += 1
        else:
            # Don't add sites that look dead; warn for blocked/captcha/no_products/fake.
            if status == "dead":
                dead += 1
                continue
            if status == "captcha":
                captcha += 1
                continue
            if status == "no_products":
                no_products += 1
                continue
            if status == "blocked":
                blocked += 1
                continue
            if status == "fake":
                fake += 1
                continue
            errors += 1
    
    await bot.reply_to(message, f"""
🛒 *SITES ADDED* 🛒
━━━━━━━━━━━━━━━━━━━━
✅ Added (validated): *{ok_added}*
📊 Total submitted: *{len(sites)}*
🔁 Duplicates: *{dupes}*
💀 Dead/unreachable: *{dead}*
🚫 Blocked/429: *{blocked}*
🤖 Captcha: *{captcha}*
📦 No products: *{no_products}*
🎭 FAKE (shows charged): *{fake}*
⚠️ Other errors: *{errors}*

💡 Use /mysh to view your sites
_FAKE sites show CHARGED for generated cards = not real_
    """, parse_mode='Markdown')


@bot.message_handler(commands=['validatesh', 'checksh'])
async def cmd_validatesh(message):
    """Validate all saved Shopify sites"""
    global user_temp_data
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    sites = await get_user_shopify_sites(user_id)
    
    if not sites:
        await bot.reply_to(message, "❌ No Shopify sites saved! Use /addsh first.")
        return
    
    wait_msg = await bot.reply_to(message, f"""
🔄 *Validating {len(sites)} saved site(s)...*

⏳ Please wait while I check each site.
This may take a while...
    """, parse_mode='Markdown')
    
    # Get user's proxy
    proxies = await get_user_proxies(user_id)
    proxy_url = None
    if proxies:
        proxy = random.choice(proxies)
        proxy_url = get_proxy_url(proxy)
    
    valid_sites = []
    dead_sites = []
    captcha_sites = []
    blocked_sites = []
    fake_sites = []  # Sites showing fake CHARGED/APPROVED for gen cards
    
    for i, site in enumerate(sites):
        # Update progress
        site_display = site.replace('https://', '').replace('http://', '')[:35]
        try:
            await bot.edit_message_text(
                f"🔄 *Validating... ({i+1}/{len(sites)})*\n\n⏳ Checking: `{site_display}`...\n\n_Testing with generated card - real sites will DECLINE_",
                chat_id=message.chat.id,
                message_id=wait_msg.message_id,
                parse_mode='Markdown'
            )
        except:
            pass
        
        is_valid, status, details = await validate_shopify_site(site, proxy_url)
        
        if is_valid:
            valid_sites.append({"url": site, "details": details})
        elif status == "fake":
            # IMPORTANT: Site shows CHARGED/APPROVED for generated card = FAKE!
            fake_sites.append({"url": site, "details": details})
        elif status in ["dead", "error"]:
            dead_sites.append({"url": site, "details": details})
        elif status == "captcha":
            captcha_sites.append({"url": site, "details": details})
        else:
            blocked_sites.append({"url": site, "details": details})
        
        await asyncio.sleep(0.5)
    
    # Build results
    result_msg = f"""
🛒 *SITE VALIDATION COMPLETE* 🛒
{'━'*20}

📊 Total Sites: *{len(sites)}*
✅ Valid (DECLINED gen card): *{len(valid_sites)}*
🎭 FAKE (shows CHARGED): *{len(fake_sites)}*
💀 Dead/Error: *{len(dead_sites)}*
🤖 Captcha: *{len(captcha_sites)}*
🚫 Blocked: *{len(blocked_sites)}*
"""
    
    if valid_sites:
        result_msg += f"\n✅ *VALID Sites (properly declined gen card):*\n"
        for s in valid_sites[:10]:
            site_short = s['url'].replace('https://', '').replace('http://', '')[:30]
            result_msg += f"  • `{site_short}`\n"
        if len(valid_sites) > 10:
            result_msg += f"  _...and {len(valid_sites) - 10} more_\n"
    
    if fake_sites:
        result_msg += f"\n🎭 *FAKE Sites (showed CHARGED/APPROVED for gen card):*\n"
        for s in fake_sites[:5]:
            site_short = s['url'].replace('https://', '').replace('http://', '')[:30]
            result_msg += f"  • ❌ `{site_short}`\n"
        if len(fake_sites) > 5:
            result_msg += f"  _...and {len(fake_sites) - 5} more_\n"
        result_msg += f"\n⚠️ _FAKE sites return false CHARGED results - they will be auto-removed_\n"
    
    # Offer to remove dead/fake sites
    remove_count = len(dead_sites) + len(captcha_sites) + len(blocked_sites) + len(fake_sites)
    if remove_count > 0:
        result_msg += f"\n⚠️ *{remove_count} problematic sites found.*"
        
        # Store for cleanup button (include fake sites for removal!)
        user_temp_data[f"dead_sites_{user_id}"] = dead_sites + captcha_sites + blocked_sites + fake_sites
        
        buttons = create_inline_keyboard([
            [("🗑 Remove Dead Sites", f"remove_dead_sh_{user_id}"), ("✖ Keep All", f"keep_sh_{user_id}")]
        ])
        
        try:
            await bot.edit_message_text(
                result_msg,
                chat_id=message.chat.id,
                message_id=wait_msg.message_id,
                parse_mode='Markdown',
                reply_markup=buttons
            )
        except:
            await bot.send_message(message.chat.id, result_msg, parse_mode='Markdown', reply_markup=buttons)
    else:
        try:
            await bot.edit_message_text(
                result_msg + "\n\n🎉 All sites are working!",
                chat_id=message.chat.id,
                message_id=wait_msg.message_id,
                parse_mode='Markdown'
            )
        except:
            await bot.send_message(message.chat.id, result_msg + "\n\n🎉 All sites are working!", parse_mode='Markdown')


