    valid_sites = []
    for site in sites:
        if len(site) < 10: continue
        if not site.startswith("http"): site = "https://" + site
        valid_sites.append(site)
    
    if not valid_sites:
        await bot.reply_to(message, "❌ No valid sites found!")
        return
    
    # Send "checking" message
    wait_msg = await bot.reply_to(message, f"🔄 *Validating {len(valid_sites)} site(s)...*", parse_mode='Markdown')
    
    # Get user proxy
    proxies = await get_user_proxies(user_id)
    proxy_url = None
    if proxies:
        proxy = random.choice(proxies)
        proxy_url = get_proxy_url(proxy)
    
    added = 0
    rotator = RazorpayGateRotator()
    
    for i, site in enumerate(valid_sites):
        try:
            await bot.edit_message_text(
                f"🔄 *Validating ({i+1}/{len(valid_sites)})*\nChecking: `{site}`...",
                chat_id=message.chat.id,
                message_id=wait_msg.message_id,
                parse_mode='Markdown',
                disable_web_page_preview=True
            )
        except:
            pass
            
        try:
            # Quick validation: try to extract key
            # Use proxy if available
            _, key_id, _, _, error = await rotator.extract_merchant_data(site, proxy_url)
            
            if key_id:
                success, res = await add_user_razorpay_site(user_id, site)
                if success: added += 1
            else:
                # Failed
                pass
        except Exception as e:
            pass
            
    await bot.edit_message_text(
        f"✅ *Added {added} working Razorpay sites!*",
        chat_id=message.chat.id,
        message_id=wait_msg.message_id,
        parse_mode='Markdown'
    )


