@bot.message_handler(commands=['rzhealth'])
async def cmd_rzhealth(message):
    """Check health of saved Razorpay sites"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    sites = await get_user_razorpay_sites(user_id)
    
    if not sites:
        await bot.reply_to(message, "📭 No Razorpay sites saved.\nUse /addrz to add one!")
        return
    
    wait_msg = await bot.reply_to(message, f"🔍 *Checking {len(sites)} sites...*", parse_mode='Markdown')
    
    results = []
    dead_sites = []
    
    async with aiohttp.ClientSession() as session:
        for site in sites:
            try:
                start_time = time.time()
                async with session.head(site, timeout=aiohttp.ClientTimeout(total=10), allow_redirects=True) as resp:
                    response_time = time.time() - start_time
                    
                    if resp.status < 400:
                        if response_time < 2:
                            results.append(f"✅ `{urlparse(site).netloc}` ({response_time:.1f}s)")
                        else:
                            results.append(f"⚠️ `{urlparse(site).netloc}` (slow: {response_time:.1f}s)")
                    else:
                        results.append(f"❌ `{urlparse(site).netloc}` (HTTP {resp.status})")
                        dead_sites.append(site)
            except asyncio.TimeoutError:
                results.append(f"❌ `{urlparse(site).netloc}` (timeout)")
                dead_sites.append(site)
            except Exception as e:
                results.append(f"❌ `{urlparse(site).netloc}` (error)")
                dead_sites.append(site)
    
    text = f"""
🏥 *Razorpay Site Health*
━━━━━━━━━━━━━━━━━━
{chr(10).join(results)}
━━━━━━━━━━━━━━━━━━
✅ Working: {len(sites) - len(dead_sites)}
❌ Dead: {len(dead_sites)}
    """
    
    if dead_sites:
        text += f"\n\n_Use /removerz to remove dead sites_"
    
    await bot.edit_message_text(text, chat_id=message.chat.id, message_id=wait_msg.message_id, parse_mode='Markdown', disable_web_page_preview=True)


