@bot.message_handler(commands=['shextra'])
async def cmd_shextra(message):
    """Filter sites by price - move expensive ones to extra list"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    parts = message.text.split()
    if len(parts) < 2:
        await bot.reply_to(message, """
🏷️ *Shopify Price Filter*

Usage: `/shextra <max_price>`

Example: `/shextra 5.99`
• Keeps sites with items ≤ $5.99
• Moves sites with items > $5.99 to extra list

Use /myshextra to view moved sites
        """, parse_mode='Markdown')
        return
    
    try:
        max_price = float(parts[1].replace('$', ''))
    except ValueError:
        await bot.reply_to(message, "❌ Invalid price. Use a number like 5.99")
        return
    
    sites = await get_user_shopify_sites(user_id)
    if not sites:
        await bot.reply_to(message, "❌ No Shopify sites to filter. Use /addsh first.")
        return
    
    wait_msg = await bot.reply_to(message, f"🔍 Filtering {len(sites)} sites by price ≤ ${max_price:.2f}...")
    
    keep_sites = []
    extra_sites = []
    no_price_sites = []
    
    for site in sites:
        cached = await get_cached_product(site)
        if cached and 'price' in cached:
            price = float(cached['price'])
            if price <= max_price:
                keep_sites.append((site, price, cached.get('title', 'Unknown')))
            else:
                extra_sites.append((site, price, cached.get('title', 'Unknown')))
        else:
            no_price_sites.append(site)
    
    # Keep sites without price info in main list
    main_sites = [s[0] for s in keep_sites] + no_price_sites
    extra_urls = [s[0] for s in extra_sites]
    
    # Save main sites
    await save_user_shopify_sites(user_id, main_sites)
    
    # Add to extra sites (merge with existing)
    existing_extra = await get_user_extra_shopify_sites(user_id)
    for url in extra_urls:
        if url not in existing_extra:
            existing_extra.append(url)
    await save_user_extra_shopify_sites(user_id, existing_extra)
    
    # Build result message
    result = f"""
▄▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▄
█░ 🏷️ *ᴘʀɪᴄᴇ ғɪʟᴛᴇʀ* 🏷️ ░░░█
▀▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▀

Filter: ≤ *${max_price:.2f}*

✅ *Kept in main:* {len(keep_sites)}
"""
    if keep_sites[:5]:
        for site, price, title in keep_sites[:5]:
            result += f"   • `{site.replace('https://', '')}` - ${price:.2f}\n"
        if len(keep_sites) > 5:
            result += f"   _...and {len(keep_sites) - 5} more_\n"
    
    result += f"\n📦 *Moved to extra:* {len(extra_sites)}"
    if extra_sites[:5]:
        result += "\n"
        for site, price, title in extra_sites[:5]:
            result += f"   • `{site.replace('https://', '')}` - ${price:.2f}\n"
        if len(extra_sites) > 5:
            result += f"   _...and {len(extra_sites) - 5} more_\n"
    
    if no_price_sites:
        result += f"\n⚠️ *No price cached:* {len(no_price_sites)} (kept in main)"
    
    result += f"""

📊 Total extra sites: {len(existing_extra)}
Use /myshextra to view • /moveshextra to restore
"""
    
    try:
        await bot.edit_message_text(result, chat_id=message.chat.id, message_id=wait_msg.message_id, parse_mode='Markdown')
    except:
        await bot.send_message(message.chat.id, result, parse_mode='Markdown')


