@bot.message_handler(commands=['parallelsh'])
async def cmd_parallelsh(message):
    """Set Shopify site-cap override for parallelism (OWNER ONLY, silent).

    By default, Shopify effective parallel is capped by usable site count (safer).
    This command overrides that cap (allows reusing sites concurrently).
    """
    user_id = message.from_user.id

    # OWNER ONLY
    if user_id != OWNER_ID:
        return  # silent for non-owner

    # Best-effort: delete the command message (silent)
    try:
        await bot.delete_message(message.chat.id, message.message_id)
    except Exception:
        pass

    parts = (message.text or "").split()

    # Helper: ephemeral ack to owner
    async def _ack(text):
        try:
            m = await bot.send_message(message.chat.id, text, parse_mode='Markdown')
            await asyncio.sleep(3)
            await bot.delete_message(message.chat.id, m.message_id)
        except Exception:
            pass

    # Show current setting if no argument
    if len(parts) < 2:
        current = "auto (cap = usable sites)" if GLOBAL_SHOPIFY_SITE_PARALLEL_CAP is None else str(GLOBAL_SHOPIFY_SITE_PARALLEL_CAP)
        await _ack(f"⚡ *SHOPIFY SITE-CAP*\nCurrent: *{current}*\n\nUsage: `/parallelsh 1..99999` or `/parallelsh off`")
        return

    arg = parts[1].strip().lower()
    if arg in ("off", "auto", "default", "reset", "none", "0"):
        await set_global_shopify_site_parallel_cap(None)
        await _ack("✅ Shopify site-cap set to *auto* (cap = usable sites).")
        return

    try:
        new_cap = int(arg)
    except ValueError:
        await _ack("❌ Invalid number. Use `/parallelsh 1..99999` or `/parallelsh off`.")
        return

    if new_cap < MIN_SHOPIFY_SITE_PARALLEL_CAP:
        new_cap = MIN_SHOPIFY_SITE_PARALLEL_CAP
    if new_cap > MAX_SHOPIFY_SITE_PARALLEL_CAP:
        new_cap = MAX_SHOPIFY_SITE_PARALLEL_CAP

    await set_global_shopify_site_parallel_cap(new_cap)
    await _ack(f"✅ Shopify site-cap override set to *{GLOBAL_SHOPIFY_SITE_PARALLEL_CAP}*.")


