@bot.message_handler(commands=['shexport'])
async def cmd_shexport(message):
    """Export all Shopify results as a single combined file"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    user_dir = get_user_dir(user_id)
    result_files = {
        "sh_charged.txt": "💎 CHARGED",
        "sh_approved.txt": "✨ APPROVED (3DS)",
        "sh_ccn.txt": "🔶 CCN (Bad CVV)",
        "sh_insufficient.txt": "💸 INSUFFICIENT FUNDS"
    }
    
    # Combine all results into one export file
    export_content = f"""🛒 SHOPIFY EXPORT - {datetime.now().strftime('%Y-%m-%d %H:%M')}
{'━'*40}

"""
    
    total_cards = 0
    for fname, label in result_files.items():
        fpath = os.path.join(user_dir, fname)
        if os.path.exists(fpath) and os.path.getsize(fpath) > 0:
            try:
                async with aiofiles.open(fpath, 'r', encoding='utf-8') as f:
                    content = await f.read()
                    lines = [l.strip() for l in content.split('\n') if l.strip()]
                    total_cards += len(lines)
                    
                    export_content += f"\n{'='*60}\n{label} ({len(lines)} cards)\n{'='*60}\n"
                    export_content += content + "\n"
            except:
                pass
    
    if total_cards == 0:
        await bot.reply_to(message, "📭 No results to export yet. Run /shcheck first.")
        return
    
    # Save to temp file and send
    export_file = os.path.join(user_dir, f"shopify_export_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt")
    async with aiofiles.open(export_file, 'w', encoding='utf-8') as f:
        await f.write(export_content)
    
    try:
        with open(export_file, 'rb') as f:
            await bot.send_document(
                message.chat.id, 
                f, 
                caption=f"📤 *Shopify Export*\n• Total: {total_cards} live cards\n• Generated: {datetime.now().strftime('%Y-%m-%d %H:%M')}",
                parse_mode='Markdown'
            )
    except Exception as e:
        await bot.reply_to(message, f"❌ Export failed: {e}")
    
    # Clean up temp file
    try:
        os.remove(export_file)
    except:
        pass


