@bot.message_handler(commands=['msh'])
async def cmd_msh(message):
    """
    MSH - External Shopify Endpoint Checker
    
    Difference from /shcheck:
    - /shcheck does FULL checkout flow locally:
      1. Add product to cart
      2. Get cart token
      3. Navigate to checkout
      4. Create payment session
      5. Send proposal for shipping
      6. Submit payment
      7. Poll for receipt
      
    - /msh uses EXTERNAL API with pre-extracted endpoints:
      1. Send card + site + proxy to API
      2. Get immediate response
      
    MSH is MUCH FASTER because:
    - No cart/checkout/session creation overhead
    - Uses pre-built Shopify payment endpoints
    - External service handles all the heavy lifting
    - Just one HTTP request per card
    """
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await safe_reply(message, "❌ Use /register first.")
        return
    
    if await count_user_jobs(user_id, gateway="msh") > 0:
        await safe_reply(message, "⚠️ MSH check already running. Use /mshstop to stop it.", parse_mode="Markdown")
        return

    # INSTANT RESPONSE
    await safe_reply(message, "⚡ *Starting MSH Endpoint check...*", parse_mode='Markdown')
    
    # Check if specific site provided
    parts = message.text.split(maxsplit=1)
    specific_site = parts[1].strip() if len(parts) > 1 else None
    
    # Launch in background
    async def _runner(cancel_event: asyncio.Event, job_id: str):
        await process_user_msh_cards(user_id, message.chat.id, specific_site, cancel_event=cancel_event, job_id=job_id)
    await start_check_job(user_id=user_id, chat_id=message.chat.id, gateway="msh", runner=_runner)


