@bot.message_handler(commands=['stcharge'])
async def cmd_stcharge(message):
    """Stripe $1 charge checker"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    
    if not await is_user_approved(user_id):
        await safe_reply(message, "❌ Use /register first.")
        return
    
    cards = await get_user_cards(user_id)
    if not cards:
        await bot.reply_to(message, "❌ No cards! Send cards first.")
        return
    
    # Generate check ID for logging
    check_id = f"STCHARGE_{user_id}_{int(time.time())}"
    
    log(f"[{check_id}] ═══════════ STARTING STRIPE $1 CHARGE ═══════════", "INFO")
    log(f"[{check_id}] 📋 Cards: {len(cards)} | User: {user_id}", "INFO")
    
    await bot.reply_to(message, f"""
💳 {bold_sans("STRIPE $1 CHARGE")} 💳
━━━━━━━━━━━━━━━━━━━
📋 Cards: *{len(cards)}*
💰 Amount: *$1.00*
🏪 Gate: *Stripe*
━━━━━━━━━━━━━━━━━━━
_Processing..._
    """, parse_mode='Markdown')
    
    counter = LiveCounter(len(cards), chat_id, "Stripe Charge")
    await counter.update(force=True)
    
    for card_line in cards:
        parts = card_line.split('|')
        if len(parts) < 4:
            counter.errors += 1
            log(f"[{check_id}] ❌ Invalid format: {card_line[:20]}...", "WARNING")
            continue
        
        cc, mm, yy, cvv = parts[0], parts[1], parts[2], parts[3]
        
        result_type, details = await stripe_charge_check(cc, mm, yy, cvv)
        counter.processed += 1
        
        masked_cc = cc[:6] + 'x' * 6 + cc[-4:] if len(cc) >= 16 else cc
        
        # ===== TERMINAL LOGGING =====
        log(f"[{check_id}] ┌── Card #{counter.processed}/{len(cards)} ──", "INFO")
        log(f"[{check_id}] │ CC: {masked_cc}", "INFO")
        log(f"[{check_id}] │ Response: {details}", "INFO")
        log(f"[{check_id}] │ Result: {result_type.upper()}", "INFO")
        log(f"[{check_id}] └────────────────────", "INFO")
        
        if result_type == 'charged':
            counter.live += 1
            counter.charged += 1
            log(f"[{check_id}] 💎 CHARGED: {masked_cc} | {details}", "SUCCESS")
            await append_to_hit_history(user_id, card_line, "CHARGED", "stripe", source_chat_id=chat_id)
            await safe_send_message(chat_id, f"""
💎 {bold_sans("STRIPE CHARGED")} 💎
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
💰 {details}
🏪 Gate: *Stripe*
━━━━━━━━━━━━━━━━━
            """, parse_mode='Markdown')
        elif result_type == 'approved':
            counter.live += 1
            log(f"[{check_id}] ✨ APPROVED: {masked_cc} | {details}", "SUCCESS")
            await append_to_hit_history(user_id, card_line, "APPROVED", "stripe", source_chat_id=chat_id)
            await safe_send_message(chat_id, f"""
✨ {bold_sans("STRIPE APPROVED")} ✨
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 {details}
━━━━━━━━━━━━━━━━━
            """, parse_mode='Markdown')
        elif result_type == 'ccn':
            counter.live += 1
            log(f"[{check_id}] 🔢 CCN: {masked_cc} | {details}", "SUCCESS")
            await append_to_hit_history(user_id, card_line, "CCN", "stripe", source_chat_id=chat_id)
            await safe_send_message(chat_id, f"""
🔢 {bold_sans("STRIPE CCN")} 🔢
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 {details}
━━━━━━━━━━━━━━━━━
            """, parse_mode='Markdown')
        elif result_type == 'declined':
            counter.declined += 1
        else:
            counter.errors += 1
        
        # Remove card from queue
        try:
            current_cards = await get_user_cards(user_id)
            if card_line in current_cards:
                current_cards.remove(card_line)
                await save_user_cards(user_id, current_cards)
        except:
            pass
        
        await counter.update()
        
        # Progress log every 10 cards
        if counter.processed % 10 == 0:
            log(f"[{check_id}] 📊 Progress: {counter.processed}/{len(cards)} | Live: {counter.live} | Dead: {counter.declined} | Errors: {counter.errors}", "INFO")
    
    log(f"[{check_id}] ═══════════ STRIPE CHARGE COMPLETE ═══════════", "INFO")
    log(f"[{check_id}] 📊 Final: {counter.live} live | {counter.declined} dead | {counter.errors} errors", "INFO")
    await counter.finish()


