@bot.message_handler(commands=['lbcheck'])
async def cmd_lbcheck(message):
    user_id = message.from_user.id
    chat_id = message.chat.id

    if not await is_user_approved(user_id):
        await safe_reply(message, "❌ Use /register first.")
        return

    cards = await get_user_cards(user_id)
    if not cards:
        await bot.reply_to(message, "❌ No cards! Send cards first.")
        return

    check_id = f"LOOTBAR_{user_id}_{int(time.time())}"
    log(f"[{check_id}] ═══════════ STARTING LOOTBAR CHECK ═══════════", "INFO")
    log(f"[{check_id}] 📋 Cards: {len(cards)} | User: {user_id}", "INFO")

    auth_tok = os.environ.get("LOOTBAR_AUTH_TOKEN", "")
    dev_id = os.environ.get("LOOTBAR_DEVICE_ID", "")
    bill_id = os.environ.get("LOOTBAR_BILL_ORDER_ID", "")

    if not auth_tok:
        await safe_reply(message, "❌ LOOTBAR_AUTH_TOKEN not configured.", parse_mode='Markdown')
        return

    async def _runner(cancel_event: asyncio.Event, job_id: str):
        checker = LootbarAdyenChecker(auth_token=auth_tok, device_id=dev_id)
        if bill_id:
            checker._bill_order_id = bill_id

        counter = LiveCounter(len(cards), chat_id, "Lootbar")
        await counter.update(force=True)

        current_cards = list(cards)
        for card_line in current_cards:
            if cancel_event.is_set():
                log(f"[{check_id}] 🛑 Cancelled by user", "INFO")
                break

            parts = card_line.split('|')
            if len(parts) < 3:
                counter.errors += 1
                log(f"[{check_id}] ❌ Invalid format: {card_line[:20]}...", "WARNING")
                counter.processed += 1
                await counter.update()
                continue

            cc, mm, yy = parts[0].strip(), parts[1].strip(), parts[2].strip()
            cvv = parts[3].strip() if len(parts) >= 4 else ""
            masked_cc = cc[:6] + 'x' * 6 + cc[-4:] if len(cc) >= 16 else cc

            result_type, details = await checker.check_card(cc, mm, yy, cvv)
            counter.processed += 1

            log(f"[{check_id}] ┌── Card #{counter.processed}/{len(cards)} ──", "INFO")
            log(f"[{check_id}] │ CC: {masked_cc}", "INFO")
            log(f"[{check_id}] │ Response: {details}", "INFO")
            log(f"[{check_id}] │ Result: {result_type.upper()}", "INFO")
            log(f"[{check_id}] └────────────────────", "INFO")

            if result_type == 'approved':
                counter.live += 1
                log(f"[{check_id}] 💎 CHARGED: {masked_cc} | {details}", "SUCCESS")
                await append_to_hit_history(user_id, card_line, "CHARGED", "lootbar", source_chat_id=chat_id)
                await safe_send_message(chat_id, f"""
💎 {bold_sans("LOOTBAR CHARGED")} 💎
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 {details}
━━━━━━━━━━━━━━━━━
                """, parse_mode='Markdown')
            elif result_type == 'live':
                counter.live += 1
                log(f"[{check_id}] ✅ APPROVED: {masked_cc} | {details}", "SUCCESS")
                await append_to_hit_history(user_id, card_line, "APPROVED", "lootbar", source_chat_id=chat_id)
                await safe_send_message(chat_id, f"""
✅ {bold_sans("LOOTBAR APPROVED")} ✅
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 {details}
━━━━━━━━━━━━━━━━━
                """, parse_mode='Markdown')
            elif result_type == 'ccn':
                counter.live += 1
                log(f"[{check_id}] 🔢 CCN: {masked_cc} | {details}", "SUCCESS")
                await append_to_hit_history(user_id, card_line, "CCN", "lootbar", source_chat_id=chat_id)
                await safe_send_message(chat_id, f"""
🔢 {bold_sans("LOOTBAR CCN")} 🔢
━━━━━━━━━━━━━━━━━
💳 `{card_line}`
📝 {details}
━━━━━━━━━━━━━━━━━
                """, parse_mode='Markdown')
            elif result_type == 'declined':
                counter.declined += 1
            else:
                counter.errors += 1
                if 'order' in details.lower() and ('consumed' in details.lower() or 'failed' in details.lower()):
                    await checker.reset_order()

            try:
                rem = await get_user_cards(user_id)
                if card_line in rem:
                    rem.remove(card_line)
                    await save_user_cards(user_id, rem)
            except:
                pass

            await counter.update()

            if counter.processed % 10 == 0:
                log(f"[{check_id}] 📊 Progress: {counter.processed}/{len(cards)} | Live: {counter.live} | Dead: {counter.declined} | Errors: {counter.errors}", "INFO")

        log(f"[{check_id}] ═══════════ LOOTBAR CHECK COMPLETE ═══════════", "INFO")
        log(f"[{check_id}] 📊 Final: {counter.live} live | {counter.declined} dead | {counter.errors} errors", "INFO")
        await counter.finish()

    await safe_reply(message, f"""
🎮 {bold_sans("LOOTBAR CHECK")} 🎮
━━━━━━━━━━━━━━━━━━━
📋 Cards: *{len(cards)}*
💰 Gate: *Lootbar (Adyen)*
🔍 Mode: *CVV-remove*
━━━━━━━━━━━━━━━━━━━
_Processing..._
    """, parse_mode='Markdown')

    await start_check_job(user_id=user_id, chat_id=chat_id, gateway="lootbar", runner=_runner)


