@bot.message_handler(commands=['hitkey'])
async def cmd_hitkey(message):
    """Retrieve hits using a secret hitkey"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    parts = message.text.split()
    if len(parts) < 2:
        await bot.reply_to(message, """
▄▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▄
█░ 🔑 *ʜɪᴛᴋᴇʏ sʏsᴛᴇᴍ* 🔑 ░░░█
▀▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▀

Usage: `/hitkey XXXXXXXX`

After each batch check, you get a 
secret hitkey to retrieve your hits.
        """, parse_mode='Markdown')
        return
    
    key = parts[1].strip().upper()
    data = await get_hitkey_data(key)
    
    if not data:
        await bot.reply_to(message, "❌ Invalid or expired hitkey.")
        return
    
    # Verify this user owns the hitkey (optional - can be removed for sharing)
    if data.get("user_id") != user_id and user_id != OWNER_ID:
        await bot.reply_to(message, "❌ This hitkey belongs to another user.")
        return
    
    hits = data.get("hits", [])
    if not hits:
        await bot.reply_to(message, "📭 No hits found for this key.")
        return
    
    # Create hits file
    user_dir = get_user_dir(user_id)
    export_content = f"""🔑 HITKEY: {key}
📅 Created: {data.get('created', 'Unknown')}
────────────────────────────

"""
    export_content += "\n".join(hits)
    
    export_file = os.path.join(user_dir, f"hitkey_{key}.txt")
    async with aiofiles.open(export_file, 'w', encoding='utf-8') as f:
        await f.write(export_content)
    
    try:
        with open(export_file, 'rb') as f:
            await bot.send_document(
                message.chat.id,
                f,
                caption=f"🔑 *Hitkey: {key}*\n💎 {len(hits)} hits found",
                parse_mode='Markdown'
            )
    except Exception as e:
        await bot.reply_to(message, f"❌ Failed: {e}")
    
    try:
        os.remove(export_file)
    except:
        pass


