@bot.message_handler(commands=['shquality'])
async def cmd_shquality(message):
    """Show site quality stats - which sites work reliably"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    tracker = await get_site_quality_tracker(user_id)
    sites = tracker.data.get("sites", {})
    
    if not sites:
        await bot.reply_to(message, "📊 No site quality data yet. Run /shcheck first to build quality data.")
        return
    
    text = """
▄▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▄
█░ 📊 *sɪᴛᴇ ǫᴜᴀʟɪᴛʏ* 📊 ░░░█
▀▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▀

"""
    
    verified = []
    blacklisted = []
    candidates = []
    
    for site_key, stats in sites.items():
        status = stats.get("status", "candidate")
        attempts = stats.get("attempts", 0)
        timing_err = stats.get("timing_errors", 0)
        card_ok = stats.get("card_results", 0)
        
        site_short = site_key[:25] + "..." if len(site_key) > 25 else site_key
        
        if status == "verified":
            verified.append(f"  ✅ `{site_short}` ({card_ok} ok, {timing_err} err)")
        elif status == "blacklisted":
            blacklisted.append(f"  🚫 `{site_short}` ({timing_err} timing errors)")
        else:
            error_rate = (timing_err / attempts * 100) if attempts > 0 else 0
            candidates.append(f"  ⏳ `{site_short}` ({error_rate:.0f}% err rate)")
    
    if verified:
        text += "*✅ VERIFIED (reliable):*\n" + "\n".join(verified) + "\n\n"
    if blacklisted:
        text += "*🚫 BLACKLISTED (broken):*\n" + "\n".join(blacklisted) + "\n\n"
    if candidates:
        text += "*⏳ TESTING:*\n" + "\n".join(candidates) + "\n\n"
    
    text += "_Use /shclearblacklist to reset blacklisted sites_"
    
    await bot.reply_to(message, text, parse_mode='Markdown')


@bot.message_handler(commands=['shclearblacklist'])
async def cmd_shclearblacklist(message):
    """Clear all blacklisted sites so they can be tested again"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    tracker = await get_site_quality_tracker(user_id)
    sites = tracker.data.get("sites", {})
    
    cleared = 0
    for site_key, stats in sites.items():
        if stats.get("status") == "blacklisted":
            stats["status"] = "candidate"
            stats["consecutive_timing"] = 0
            stats["timing_errors"] = 0
            cleared += 1
    
    await tracker.save()
    
    if cleared > 0:
        await bot.reply_to(message, f"✅ Cleared {cleared} blacklisted sites! They will be tested again on next /shcheck.")
    else:
        await bot.reply_to(message, "No blacklisted sites to clear.")


