async def get_global_shopify_stats():
    """Get global Shopify statistics across all users"""
    stats = {
        "charged": 0,
        "approved": 0,
        "ccn": 0,
        "insufficient": 0,
        "total": 0,
        "user_hits": {}  # {user_id: total_hits}
    }

    # Prefer DB (Railway/cloud). This fixes missing stats/exports when local files are gone.
    if USE_DATABASE:
        try:
            async with db_pool.acquire(timeout=10) as conn:
                rows = await conn.fetch(
                    """
                    SELECT user_id, result, COUNT(*)::int AS cnt
                    FROM hits
                    WHERE gateway = 'shopify'
                    GROUP BY user_id, result
                    """
                )
            for r in rows:
                uid = int(r["user_id"])
                res = (r["result"] or "").upper()
                cnt = int(r["cnt"] or 0)
                if res == "CHARGED":
                    stats["charged"] += cnt
                elif res == "APPROVED":
                    stats["approved"] += cnt
                elif res == "CCN":
                    stats["ccn"] += cnt
                elif res == "INSUFFICIENT":
                    stats["insufficient"] += cnt
                if cnt > 0:
                    stats["user_hits"][uid] = stats["user_hits"].get(uid, 0) + cnt
            stats["total"] = stats["charged"] + stats["approved"] + stats["ccn"] + stats["insufficient"]
            return stats
        except Exception as e:
            log(f"[DB] global shopify stats failed, falling back to file: {e}", "WARNING")
    
    if not os.path.exists(DATA_DIR):
        return stats
    
    result_files = {
        "sh_charged.txt": "charged",
        "sh_approved.txt": "approved",
        "sh_ccn.txt": "ccn",
        "sh_insufficient.txt": "insufficient"
    }
    
    for uid_dir in os.listdir(DATA_DIR):
        try:
            uid = int(uid_dir)
            user_total = 0
            for filename, key in result_files.items():
                filepath = os.path.join(DATA_DIR, uid_dir, filename)
                if os.path.exists(filepath):
                    try:
                        async with aiofiles.open(filepath, 'r', encoding='utf-8') as f:
                            content = await f.read()
                            lines = [l for l in content.strip().split('\n') if l.strip()]
                            count = len(lines)
                            stats[key] += count
                            user_total += count
                    except:
                        pass
            if user_total > 0:
                stats["user_hits"][uid] = user_total
        except:
            continue
    
    stats["total"] = stats["charged"] + stats["approved"] + stats["ccn"] + stats["insufficient"]
    return stats


