@bot.message_handler(commands=['open'])
async def cmd_open(message):
    """Open a TXT file and show contents in message"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    # Must be reply to a document
    if not message.reply_to_message or not message.reply_to_message.document:
        await bot.reply_to(message, """
📂 *Open TXT File*
━━━━━━━━━━━━━━━━━━━

Reply to a .txt file with `/open` to view its contents.

_The file content will be displayed in the chat._
        """, parse_mode='Markdown')
        return
    
    doc = message.reply_to_message.document
    
    # Check file type
    if not doc.file_name.lower().endswith('.txt'):
        await bot.reply_to(message, "❌ Only .txt files supported!")
        return
    
    # Check file size (max 1MB)
    if doc.file_size > 1024 * 1024:
        await bot.reply_to(message, "❌ File too large! Max 1MB.")
        return
    
    try:
        # Download file
        file_info = await bot.get_file(doc.file_id)
        downloaded = await bot.download_file(file_info.file_path)
        content = downloaded.decode('utf-8', errors='ignore')
        
        # Count lines
        lines = content.split('\n')
        line_count = len([l for l in lines if l.strip()])
        
        # Send content (split if needed)
        header = f"📂 *File:* `{doc.file_name}`\n📊 *Lines:* {line_count}\n━━━━━━━━━━━━━━━━━━━\n\n"
        
        full_text = header + f"```\n{content[:3500]}\n```"
        
        if len(content) > 3500:
            full_text += f"\n\n_...truncated ({len(content) - 3500} chars more)_"
        
        await bot.reply_to(message, full_text, parse_mode='Markdown')
        
    except Exception as e:
        log(f"Open file error: {e}", "ERROR")
        await bot.reply_to(message, f"❌ Failed to open file: {e}")


