# ==================== DOCUMENT HANDLER (for TXT files) ====================

def is_proxy_line(line: str) -> bool:
    """Check if a line looks like a valid proxy format, not a CC or URL"""
    import re
    line = line.strip()
    if not line:
        return False
    
    # REJECT CC-like patterns first (cards have | separator)
    if '|' in line:
        return False
    
    # Reject if first segment is all digits and 13-19 chars (likely a CC number)
    first_part = line.split(':')[0].split('/')[0]
    if first_part.replace(' ', '').isdigit() and len(first_part.replace(' ', '')) >= 13:
        return False
    
    # Reject if it looks like CC format: long number followed by slashes
    if '/' in line and line.count('/') >= 3:
        parts = line.split('/')
        if parts[0].replace(' ', '').isdigit() and len(parts[0].replace(' ', '')) >= 13:
            return False
    
    # REJECT URL-like patterns (Shopify/WooCommerce sites)
    line_lower = line.lower()
    url_indicators = ['.myshopify.com', 'shopify.com', '.com/', '.org/', '.net/', 
                      '/products/', '/cart/', '/checkout/', '/collections/',
                      'woocommerce', '/shop/', '/store/']
    if any(ind in line_lower for ind in url_indicators):
        return False
    
    # Reject if it's clearly a website URL (not a proxy URL)
    if line_lower.startswith('http://') or line_lower.startswith('https://'):
        # Check if it's a proxy URL (socks or ends with port only)
        if not any(x in line_lower for x in ['socks', ':8080', ':3128', ':1080', ':8888']):
            # Likely a website URL, not a proxy
            if any(ext in line_lower for ext in ['.com', '.org', '.net', '.io', '.shop', '.store']):
                return False
    
    # Check for common proxy patterns:
    # ip:port, ip:port:user:pass, user:pass@ip:port, protocol://ip:port
    
    # Pattern 1: IP:PORT format - IP must have dots (4 octets) with valid port
    ip_port_pattern = r'^(\d{1,3}\.){3}\d{1,3}:\d{1,5}(:\S+:\S+)?$'
    if re.match(ip_port_pattern, line):
        # Validate port is in range
        port = line.split(':')[1]
        if port.isdigit() and 1 <= int(port) <= 65535:
            return True
    
    # Pattern 2: SOCKS proxy protocol
    if line_lower.startswith(('socks4://', 'socks5://')):
        return True
    
    # Pattern 3: user:pass@host:port - must have @ and host with dot
    if '@' in line and ':' in line.split('@')[-1]:
        host_after_at = line.split('@')[-1].split(':')[0]
        port_after = line.split('@')[-1].split(':')[1] if ':' in line.split('@')[-1] else ''
        if '.' in host_after_at and port_after.isdigit():
            return True
    
    # Pattern 4: ip:port:user:pass format (4 parts, first is IP)
    parts = line.split(':')
    if len(parts) == 4:
        host_part = parts[0]
        port_part = parts[1]
        # Must be IP format (4 octets)
        if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', host_part):
            if port_part.isdigit() and 1 <= int(port_part) <= 65535:
                return True
    
    # Pattern 5: Simple ip:port (2 parts only)
    if len(parts) == 2:
        host_part = parts[0]
        port_part = parts[1]
        # Must be IP format for simple proxy
        if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', host_part):
            if port_part.isdigit() and 1 <= int(port_part) <= 65535:
                return True
    
    return False


@bot.message_handler(content_types=['document'])
async def handle_document(message):
    """Handle TXT file uploads - detects cards, sites, OR proxies automatically"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register to request access.")
        return
    
    # Check if it's a text file
    doc = message.document
    if not doc.file_name.lower().endswith('.txt'):
        await bot.reply_to(message, "❌ Please send a .txt file containing cards, sites, or proxies.")
        return
    
    try:
        # Download the file
        file_info = await bot.get_file(doc.file_id)
        downloaded = await bot.download_file(file_info.file_path)
        
        # Decode content
        content = downloaded.decode('utf-8', errors='ignore')
        
        # Parse lines from content
        lines = [l.strip() for l in content.split('\n') if l.strip()]
        
        # Check if user replied to this with /addproxy command
        reply_text = ""
        if message.reply_to_message and message.reply_to_message.text:
            reply_text = message.reply_to_message.text.strip().lower()
        
        # Detect file type: cards vs sites vs proxies
        # IMPROVED DETECTION: Priority order with better validation
        
        filename_lower = doc.file_name.lower()
        
        # Step 1: Check for CARDS first (most specific pattern)
        card_count = 0
        for line in lines:
            line_clean = line.strip()
            # Card format: 16 digits followed by separators (| or /)
            # Pattern: NUMBER|MM|YY|CVV or NUMBER/MM/YY/CVV
            if '|' in line_clean:
                parts = line_clean.split('|')
                if len(parts) >= 4 and parts[0].replace(' ', '').isdigit() and len(parts[0].replace(' ', '')) >= 13:
                    card_count += 1
            elif line_clean.count('/') >= 3:
                parts = line_clean.split('/')
                if len(parts) >= 4 and parts[0].replace(' ', '').isdigit() and len(parts[0].replace(' ', '')) >= 13:
                    card_count += 1
        
        # Step 2: Check for PROXIES (strict IP:PORT pattern, not URLs)
        proxy_count = 0
        for line in lines:
            line_clean = line.strip()
            # Skip if line looks like a URL (has http/https or common TLDs in path)
            if 'http://' in line_clean.lower() or 'https://' in line_clean.lower():
                if '.com' in line_clean or '.org' in line_clean or '.net' in line_clean or '.shop' in line_clean:
                    continue  # This is a URL, not a proxy
            if is_proxy_line(line_clean):
                proxy_count += 1
        
        # Step 3: Check for URLs/domains (Shopify sites)
        extracted_urls = extract_shopify_urls_from_text(content)
        url_count = len(extracted_urls)
        
        # Step 4: Filename hints (strong indicators)
        filename_hints_proxy = any(x in filename_lower for x in ['proxy', 'proxies', 'socks', 'http_proxy', 'rotating'])
        filename_hints_sites = any(x in filename_lower for x in ['site', 'shop', 'store', 'shopify', 'url', 'link', 'domain', 'woo'])
        filename_hints_cards = any(x in filename_lower for x in ['card', 'cc', 'cvv', 'combo', 'fullz', 'bin'])
        
        # Step 5: Decision logic with clear priority
        # Priority: Filename hints > Content analysis
        
        # If filename explicitly says proxy AND content has proxies
        is_proxy_file = filename_hints_proxy and proxy_count > 0
        
        # If filename explicitly says sites/shop AND content has URLs
        is_sites_file = filename_hints_sites and url_count > 0
        
        # If filename explicitly says cards AND content has cards
        is_cards_file = filename_hints_cards and card_count > 0
        
        # Fallback: If no filename hints, use content analysis with thresholds
        if not is_proxy_file and not is_sites_file and not is_cards_file:
            # Cards take priority if they are clearly cards (has | separator with 4 parts)
            if card_count > 0 and card_count >= max(proxy_count, url_count) * 0.5:
                is_cards_file = True
            # Sites take priority if URLs are clear and more than proxies
            elif url_count > 0 and url_count > proxy_count:
                is_sites_file = True
            # Proxies only if clearly more proxies than anything else
            elif proxy_count > 0 and proxy_count > card_count and proxy_count > url_count:
                is_proxy_file = True
            # Last resort: whatever has content
            elif card_count > 0:
                is_cards_file = True
            elif url_count > 0:
                is_sites_file = True
            elif proxy_count > 0:
                is_proxy_file = True
        
        # Log detection for debugging
        log(f"File detection: {doc.file_name} - cards={card_count}, proxies={proxy_count}, urls={url_count}", "DEBUG")
        log(f"File hints: proxy={filename_hints_proxy}, sites={filename_hints_sites}, cards={filename_hints_cards}", "DEBUG")
        log(f"Decision: is_cards={is_cards_file}, is_sites={is_sites_file}, is_proxy={is_proxy_file}", "DEBUG")
        
        if is_proxy_file and proxy_count > 0:
            # Process as PROXIES file
            await process_proxies_file(message, user_id, chat_id, doc, lines, proxy_count)
        elif is_sites_file and url_count > 0:
            # Process as SITES file
            await process_sites_file(message, user_id, chat_id, doc, extracted_urls)
        elif is_cards_file and card_count > 0:
            # Process as CARDS file
            await process_cards_file(message, user_id, chat_id, doc, lines, card_count)
        elif card_count > 0:
            # Fallback to cards if any exist
            await process_cards_file(message, user_id, chat_id, doc, lines, card_count)
        else:
            # Neither cards nor sites nor proxies found
            await bot.reply_to(message, """
❌ *Could not detect file type*

No valid cards, sites, or proxies found in file.

*For cards:* Format should be `CC|MM|YY|CVV` or `CC/MM/YY/CVV`
*For sites:* Include URLs like `store.myshopify.com` or `https://shop.com`
*For proxies:* Format like `ip:port` or `ip:port:user:pass`

💡 Tip: Name your file `proxies.txt`, `sites.txt`, etc. for auto-detection.
            """, parse_mode='Markdown')
        
    except Exception as e:
        log(f"Document handler error: {e}", "ERROR")
        await bot.reply_to(message, f"❌ Failed to process file: {e}")


