# ==================== TEXT HANDLER (for cards) ====================

@bot.message_handler(func=lambda message: message.text and not message.text.startswith('/'))
async def handle_text(message):
    """Handle non-command text (card input)"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        return
    
    text = message.text

    if not text:
        return

    # Only treat as cards if we can actually extract at least one valid CC pattern.
    if extract_cc_from_text(text, validate_luhn=False):
        added, dupes = await add_user_cards(user_id, text)
        if added > 0 or dupes > 0:
            # Get total queue size
            total_cards = await get_user_cards(user_id)
            queue_size = len(total_cards)
            
            dedup_msg = f"\n🔄 Duplicates removed: *{dupes}*" if dupes > 0 else ""
            
            msg = f"""✅ {bold_sans("CARDS ADDED")}

➕ Added: *{added}* cards{dedup_msg}
📋 Queue: *{queue_size}* total

_Select gateway to start:_"""
            # Card action buttons
            card_buttons = create_inline_keyboard([
                [("🛒 Shopify", "start_shcheck"), ("💳 PayPal", "start_ppcheck")],
                [("⚡ Razorpay", "start_rzcheck"), ("📋 View Queue", "view_queue")],
                [("🗑 Clear Queue", "clear_queue")]
            ])
            await bot.send_message(message.chat.id, msg, parse_mode='Markdown', reply_markup=card_buttons)
        else:
            await bot.reply_to(message, "No valid cards found.\nFormat: `CC|MM|YY|CVV` or `CC/MM/YY/CVV`", parse_mode='Markdown')


