class PlaywrightAutomation:
    """Playwright-powered web automation utilities"""
    
    def __init__(self):
        self.browserless_api_key = "2SnMWeeEB7voHxK22f5ee7ff5e5d665176f02d0b9a566358d"
        self.browserless_endpoint = f"wss://production-sfo.browserless.io?token={self.browserless_api_key}&timeout=60000"
    
    async def take_screenshot(self, url: str, full_page: bool = False) -> tuple:
        """Take a screenshot of a website and return as bytes"""
        async with async_playwright() as p:
            try:
                browser = await p.chromium.connect_over_cdp(self.browserless_endpoint)
                context = await browser.new_context(
                    viewport={"width": 1920, "height": 1080},
                    user_agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
                )
                page = await context.new_page()
                
                await page.goto(url, wait_until="domcontentloaded", timeout=30000)
                await page.wait_for_timeout(2000)  # Wait for page to settle
                
                screenshot = await page.screenshot(full_page=full_page, type="png")
                
                # Get page title
                title = await page.title()
                
                await browser.close()
                return screenshot, title, None
                
            except Exception as e:
                return None, None, str(e)
    
    async def scrape_page_info(self, url: str) -> dict:
        """Scrape comprehensive info from a webpage"""
        async with async_playwright() as p:
            try:
                browser = await p.chromium.connect_over_cdp(self.browserless_endpoint)
                context = await browser.new_context(
                    viewport={"width": 1920, "height": 1080},
                    user_agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
                )
                page = await context.new_page()
                
                # Track network requests
                requests_made = []
                async def log_request(request):
                    requests_made.append({
                        "url": request.url[:100],
                        "method": request.method,
                        "type": request.resource_type
                    })
                page.on("request", log_request)
                
                response = await page.goto(url, wait_until="domcontentloaded", timeout=30000)
                await page.wait_for_timeout(2000)
                
                # Extract comprehensive page data
                page_data = await page.evaluate("""
                    () => {
                        const getMeta = (name) => {
                            const el = document.querySelector(`meta[name="${name}"], meta[property="${name}"]`);
                            return el ? el.content : null;
                        };
                        
                        const links = Array.from(document.querySelectorAll('a[href]')).slice(0, 20).map(a => ({
                            text: a.innerText.trim().substring(0, 50),
                            href: a.href
                        }));
                        
                        const images = document.querySelectorAll('img').length;
                        const scripts = document.querySelectorAll('script').length;
                        const stylesheets = document.querySelectorAll('link[rel="stylesheet"]').length;
                        const forms = document.querySelectorAll('form').length;
                        const inputs = document.querySelectorAll('input').length;
                        const buttons = document.querySelectorAll('button').length;
                        
                        // Detect technologies
                        const tech = [];
                        if (window.jQuery) tech.push('jQuery');
                        if (window.React) tech.push('React');
                        if (window.Vue) tech.push('Vue');
                        if (window.angular) tech.push('Angular');
                        if (window.Shopify) tech.push('Shopify');
                        if (window.Stripe) tech.push('Stripe');
                        if (window.PayPal) tech.push('PayPal');
                        if (window.Razorpay) tech.push('Razorpay');
                        if (window.gtag || window.ga) tech.push('Google Analytics');
                        if (window.fbq) tech.push('Facebook Pixel');
                        
                        return {
                            title: document.title,
                            description: getMeta('description') || getMeta('og:description'),
                            keywords: getMeta('keywords'),
                            author: getMeta('author'),
                            ogImage: getMeta('og:image'),
                            ogTitle: getMeta('og:title'),
                            canonical: document.querySelector('link[rel="canonical"]')?.href,
                            language: document.documentElement.lang,
                            charset: document.characterSet,
                            links: links,
                            stats: { images, scripts, stylesheets, forms, inputs, buttons },
                            technologies: tech,
                            bodyText: document.body.innerText.substring(0, 500)
                        };
                    }
                """)
                
                result = {
                    "url": url,
                    "status_code": response.status if response else None,
                    "headers": dict(response.headers) if response else {},
                    "page_data": page_data,
                    "requests_count": len(requests_made),
                    "error": None
                }
                
                await browser.close()
                return result
                
            except Exception as e:
                return {"url": url, "error": str(e)}
    
    async def check_site_status(self, url: str) -> dict:
        """Check if a site is online and get performance metrics"""
        async with async_playwright() as p:
            try:
                start_time = time.time()
                browser = await p.chromium.connect_over_cdp(self.browserless_endpoint)
                context = await browser.new_context(
                    viewport={"width": 1920, "height": 1080},
                    user_agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
                )
                page = await context.new_page()
                
                response = await page.goto(url, wait_until="domcontentloaded", timeout=30000)
                load_time = time.time() - start_time
                
                # Get performance metrics
                perf_metrics = await page.evaluate("""
                    () => {
                        const timing = performance.timing;
                        const nav = performance.getEntriesByType('navigation')[0];
                        return {
                            domContentLoaded: nav ? nav.domContentLoadedEventEnd : (timing.domContentLoadedEventEnd - timing.navigationStart),
                            loadComplete: nav ? nav.loadEventEnd : (timing.loadEventEnd - timing.navigationStart),
                            domInteractive: nav ? nav.domInteractive : (timing.domInteractive - timing.navigationStart)
                        };
                    }
                """)
                
                # Check for common issues
                content = await page.content()
                issues = []
                if 'cloudflare' in content.lower():
                    issues.append("⚠️ Cloudflare detected")
                if 'captcha' in content.lower():
                    issues.append("⚠️ CAPTCHA detected")
                if 'blocked' in content.lower():
                    issues.append("⚠️ Possible block detected")
                if 'maintenance' in content.lower():
                    issues.append("🔧 Site in maintenance mode")
                
                title = await page.title()
                
                result = {
                    "url": url,
                    "status": "✅ ONLINE" if response and response.status == 200 else f"⚠️ STATUS {response.status if response else 'N/A'}",
                    "status_code": response.status if response else None,
                    "title": title,
                    "load_time": f"{load_time:.2f}s",
                    "performance": perf_metrics,
                    "issues": issues,
                    "ssl": url.startswith("https"),
                    "error": None
                }
                
                await browser.close()
                return result
                
            except Exception as e:
                return {"url": url, "status": "❌ OFFLINE", "error": str(e)}
    
    async def fill_form_demo(self, url: str, form_data: dict) -> dict:
        """Demo: Fill a form on a webpage (for testing)"""
        async with async_playwright() as p:
            try:
                browser = await p.chromium.connect_over_cdp(self.browserless_endpoint)
                context = await browser.new_context(
                    viewport={"width": 1920, "height": 1080},
                    user_agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
                )
                page = await context.new_page()
                
                await page.goto(url, wait_until="domcontentloaded", timeout=30000)
                await page.wait_for_timeout(1000)
                
                filled_fields = []
                for selector, value in form_data.items():
                    try:
                        await page.fill(selector, value, timeout=5000)
                        filled_fields.append(selector)
                    except:
                        pass
                
                # Take screenshot after filling
                screenshot = await page.screenshot(type="png")
                
                await browser.close()
                return {
                    "url": url,
                    "filled_fields": filled_fields,
                    "screenshot": screenshot,
                    "error": None
                }
                
            except Exception as e:
                return {"url": url, "error": str(e)}

# Global instance
pw_automation = PlaywrightAutomation()


@bot.message_handler(commands=['screenshot', 'ss'])
async def cmd_screenshot(message):
    """Take a screenshot of any website"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        await bot.reply_to(message, 
            f"📸 *Screenshot Command*\n\n"
            f"Usage: `/screenshot <url>`\n\n"
            f"Example:\n"
            f"`/screenshot https://google.com`\n"
            f"`/ss https://example.com`",
            parse_mode='Markdown'
        )
        return
    
    url = parts[1].strip()
    if not url.startswith(('http://', 'https://')):
        url = 'https://' + url
    
    status_msg = await bot.reply_to(message, f"📸 *Taking screenshot...*\n`{url}`", parse_mode='Markdown')
    
    try:
        screenshot_bytes, title, error = await pw_automation.take_screenshot(url)
        
        if error:
            await bot.edit_message_text(
                f"❌ *Screenshot Failed*\n\nError: `{error[:200]}`",
                message.chat.id, status_msg.message_id,
                parse_mode='Markdown'
            )
            return
        
        # Send as photo
        photo = io.BytesIO(screenshot_bytes)
        photo.name = "screenshot.png"
        
        caption = f"📸 *Screenshot Captured*\n\n🔗 URL: `{url[:50]}{'...' if len(url) > 50 else ''}`\n📄 Title: {title[:50] if title else 'N/A'}"
        
        await bot.delete_message(message.chat.id, status_msg.message_id)
        await bot.send_photo(message.chat.id, photo, caption=caption, parse_mode='Markdown', reply_to_message_id=message.message_id)
        
    except Exception as e:
        await bot.edit_message_text(
            f"❌ *Error*: `{str(e)[:200]}`",
            message.chat.id, status_msg.message_id,
            parse_mode='Markdown'
        )


@bot.message_handler(commands=['scrape', 'pageinfo'])
async def cmd_scrape(message):
    """Scrape comprehensive info from a website"""
