@bot.message_handler(commands=['multiss', 'bulkscreenshot'])
async def cmd_multiss(message):
    """Take screenshots of multiple URLs"""
    user_id = message.from_user.id
    
    if not await is_user_approved(user_id):
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        await bot.reply_to(message, 
            f"📸 *Bulk Screenshot Command*\n\n"
            f"Usage: `/multiss <url1> <url2> ...`\n\n"
            f"Takes screenshots of multiple sites (max 5)\n\n"
            f"Example:\n"
            f"`/multiss google.com github.com twitter.com`",
            parse_mode='Markdown'
        )
        return
    
    urls = parts[1].strip().split()[:5]  # Max 5 URLs
    
    status_msg = await bot.reply_to(message, f"📸 *Taking {len(urls)} screenshots...*", parse_mode='Markdown')
    
    results = []
    for i, url in enumerate(urls, 1):
        if not url.startswith(('http://', 'https://')):
            url = 'https://' + url
        
        await bot.edit_message_text(
            f"📸 *Taking screenshots... ({i}/{len(urls)})*\n`{url}`",
            message.chat.id, status_msg.message_id,
            parse_mode='Markdown'
        )
        
        screenshot_bytes, title, error = await pw_automation.take_screenshot(url)
        results.append((url, screenshot_bytes, title, error))
    
    await bot.delete_message(message.chat.id, status_msg.message_id)
    
    # Send all screenshots
    for url, screenshot_bytes, title, error in results:
        if error:
            await bot.send_message(message.chat.id, f"❌ Failed: `{url}`\nError: `{error[:100]}`", parse_mode='Markdown')
        else:
            photo = io.BytesIO(screenshot_bytes)
            photo.name = "screenshot.png"
            caption = f"📸 `{url[:50]}`\n📄 {title[:40] if title else 'N/A'}"
            await bot.send_photo(message.chat.id, photo, caption=caption, parse_mode='Markdown')


