    def _log(self, step: str, message: str, status: str = "INFO"):
        """Live logging to terminal"""
        timestamp = datetime.now().strftime("%H:%M:%S")
        icon = {"INFO": "ℹ️", "OK": "✅", "ERROR": "❌", "WAIT": "⏳"}.get(status, "•")
        print(f"[{timestamp}] [{step}] {icon} {message}", flush=True)
    
    def _get_random_fingerprint(self):
        """Get a random realistic browser fingerprint"""
        return random.choice(self.fingerprints)
    
    async def _get_user_proxy(self, user_id: int):
        """Get a random proxy from user's saved proxies"""
        try:
            proxies = await get_user_proxies(user_id)
            if proxies and len(proxies) > 0:
                proxy = random.choice(proxies)
                self._log("PROXY", f"Using user proxy: {proxy.get('ip', 'unknown')}:***", "OK")
                return proxy
            else:
                self._log("PROXY", "No user proxies found!", "ERROR")
                return None
        except Exception as e:
            self._log("PROXY", f"Error getting proxies: {e}", "ERROR")
            return None
    
    def _format_proxy_url(self, proxy_data: dict) -> str:
        """Format proxy data into URL for Playwright"""
        if not proxy_data:
            return None
        
        ip = proxy_data.get('ip', '')
        port = proxy_data.get('port', '')
        username = proxy_data.get('username', '')
        password = proxy_data.get('password', '')
        protocol = proxy_data.get('protocol', 'http').lower()
        
        if username and password:
            return f"{protocol}://{username}:{password}@{ip}:{port}"
        else:
            return f"{protocol}://{ip}:{port}"
    
    async def get_stripe_checkout(self, phone_number: str, email: str, user_id: int = None) -> dict:
        """
        Complete checkout flow and return Stripe URL.
        Uses user's proxy and realistic fingerprint.
        """
        result = {"success": False, "stripe_url": None, "error": None}
        
        self._log("START", f"═══════════════════════════════════════════", "INFO")
        self._log("START", f"DoctorSIM Checkout - Phone: {phone_number[:3]}***{phone_number[-3:]}", "INFO")
        self._log("START", f"Email: {email.split('@')[0][:3]}***@{email.split('@')[1]}", "INFO")
        self._log("START", f"═══════════════════════════════════════════", "INFO")
        
        # Note: Browserless free plan doesn't support third-party proxies
        # Fingerprint spoofing still provides privacy protection
        self._log("PROXY", "Using Browserless cloud (proxy not supported on free tier)", "INFO")
        
        # Get random fingerprint
        fingerprint = self._get_random_fingerprint()
        self._log("FINGERPRINT", f"Using: {fingerprint['platform']} / Chrome", "OK")
        
        async with async_playwright() as p:
            try:
                # Step 0: Connect to browser
                self._log("STEP 0", "Connecting to Browserless...", "WAIT")
                
                browser = await p.chromium.connect_over_cdp(self.browserless_endpoint)
                self._log("STEP 0", "Browser connected!", "OK")
                
                # Create context with realistic fingerprint and anti-detection
                context_options = {
                    "viewport": {"width": fingerprint["screen"]["width"], "height": fingerprint["screen"]["height"]},
                    "user_agent": fingerprint["user_agent"],
                    "locale": fingerprint["language"],
                    "timezone_id": fingerprint["timezone"],
                    "permissions": ["geolocation"],
                    "geolocation": {"latitude": 40.7128, "longitude": -74.0060},  # NYC
                    "color_scheme": "light",
                    "reduced_motion": "no-preference",
                    "has_touch": fingerprint["max_touch_points"] > 0,
                    "is_mobile": False,
                    "device_scale_factor": 1,
                }
                
                context = await browser.new_context(**context_options)
                page = await context.new_page()
                self._log("STEP 0", "Page created with fingerprint", "OK")
                
                # Inject anti-detection scripts to prevent fingerprint leaks
                await page.add_init_script(f'''
                    // Override navigator properties
                    Object.defineProperty(navigator, 'platform', {{get: () => '{fingerprint["platform"]}'}});
                    Object.defineProperty(navigator, 'vendor', {{get: () => '{fingerprint["vendor"]}'}});
                    Object.defineProperty(navigator, 'hardwareConcurrency', {{get: () => {fingerprint["hardware_concurrency"]}}});
                    Object.defineProperty(navigator, 'deviceMemory', {{get: () => {fingerprint["device_memory"]}}});
                    Object.defineProperty(navigator, 'maxTouchPoints', {{get: () => {fingerprint["max_touch_points"]}}});
                    Object.defineProperty(navigator, 'languages', {{get: () => {fingerprint["languages"]}}});
                    
                    // Disable WebRTC IP leak
                    if (window.RTCPeerConnection) {{
                        window.RTCPeerConnection = function() {{
                            return {{}};
                        }};
                    }}
                    if (window.RTCDataChannel) {{
                        window.RTCDataChannel = undefined;
                    }}
                    
                    // Override WebGL renderer info
                    const getParameterProxyHandler = {{
                        apply: function(target, ctx, args) {{
                            const param = args[0];
                            const gl = ctx;
                            if (param === 37445) return '{fingerprint["webgl_vendor"]}';
                            if (param === 37446) return '{fingerprint["renderer"]}';
                            return Reflect.apply(target, ctx, args);
                        }}
                    }};
                    
                    try {{
                        const canvas = document.createElement('canvas');
                        const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
                        if (gl) {{
                            gl.getParameter = new Proxy(gl.getParameter, getParameterProxyHandler);
                        }}
                    }} catch(e) {{}}
                    
                    // Override Bluetooth API
                    if (navigator.bluetooth) {{
                        navigator.bluetooth.getAvailability = () => Promise.resolve(false);
                        navigator.bluetooth.requestDevice = () => Promise.reject(new Error('Bluetooth not available'));
                    }}
                    
                    // Override Battery API
                    if (navigator.getBattery) {{
                        navigator.getBattery = () => Promise.resolve({{
                            charging: true,
                            chargingTime: 0,
                            dischargingTime: Infinity,
                            level: 1.0
                        }});
                    }}
                    
                    // Spoof plugins
                    Object.defineProperty(navigator, 'plugins', {{
                        get: () => [
                            {{name: 'Chrome PDF Plugin', filename: 'internal-pdf-viewer'}},
                            {{name: 'Chrome PDF Viewer', filename: 'mhjfbmdgcfjbbpaeojofohoefgiehjai'}},
                            {{name: 'Native Client', filename: 'internal-nacl-plugin'}}
                        ]
                    }});
                    
                    // Hide automation indicators
                    Object.defineProperty(navigator, 'webdriver', {{get: () => undefined}});
                    delete navigator.__proto__.webdriver;
                    
                    // Canvas fingerprint protection
                    const originalToDataURL = HTMLCanvasElement.prototype.toDataURL;
                    HTMLCanvasElement.prototype.toDataURL = function(type) {{
                        if (type === 'image/png' && this.width === 16 && this.height === 16) {{
                            // Add slight noise to canvas fingerprints
                            const ctx = this.getContext('2d');
                            const imageData = ctx.getImageData(0, 0, this.width, this.height);
                            for (let i = 0; i < imageData.data.length; i += 4) {{
                                imageData.data[i] = imageData.data[i] ^ (Math.random() > 0.99 ? 1 : 0);
                            }}
                            ctx.putImageData(imageData, 0, 0);
                        }}
                        return originalToDataURL.apply(this, arguments);
                    }};
                ''')
                
                self._log("STEP 0", "Anti-detection scripts injected (WebRTC blocked, fingerprint spoofed)", "OK")
                
                # Track Stripe URL
                stripe_url_captured = None
                all_urls_captured = []
                
                def capture_stripe(request):
                    nonlocal stripe_url_captured
                    url = request.url
                    if 'checkout' in url.lower():
                        all_urls_captured.append(url)
                        self._log("CAPTURE", f"Checkout URL: {url[:80]}...", "INFO")
                    if 'checkout.stripe.com' in url or 'checkout.doctorsim.com' in url:
                        stripe_url_captured = url
                        self._log("CAPTURE", f"🎯 STRIPE URL FOUND: {url[:60]}...", "OK")
                
                page.on("request", capture_stripe)
                
                # Step 1: Go to BSNL page
                self._log("STEP 1", "Navigating to DoctorSIM BSNL page...", "WAIT")
                await page.goto("https://www.doctorsim.com/en-us/in/topup-phone/india-bsnl/", 
                               wait_until="domcontentloaded", timeout=45000)
                self._log("STEP 1", f"Page loaded: {page.url[:50]}", "OK")
                await page.wait_for_timeout(5000)
                
                # Step 2: Enter phone number
                self._log("STEP 2", f"Filling phone number: {phone_number}", "WAIT")
                try:
                    await page.fill('#phone', phone_number)
                    self._log("STEP 2", "Phone number filled!", "OK")
                except Exception as e:
                    self._log("STEP 2", f"Phone fill error: {e}", "ERROR")
                    result["error"] = f"Phone fill failed: {e}"
                    await browser.close()
                    return result
                await page.wait_for_timeout(2000)
                
                # Step 3: Click Bundle tab
                self._log("STEP 3", "Looking for Bundle tab...", "WAIT")
                bundle_clicked = await page.evaluate('''
                    () => {
                        let clicked = false;
                        document.querySelectorAll('a.nav-link, button, [role="tab"]').forEach(el => {
                            if (el.innerText.includes('Bundle')) {
                                el.click();
                                clicked = true;
                            }
                        });
                        return clicked;
                    }
                ''')
                self._log("STEP 3", f"Bundle tab clicked: {bundle_clicked}", "OK" if bundle_clicked else "ERROR")
                await page.wait_for_timeout(3000)
                
                # Check if Plan 1999 is visible
                body_text = await page.evaluate("document.body.innerText")
                has_1999 = '1999' in body_text
                has_330 = '330' in body_text
                self._log("STEP 3", f"Plan 1999 visible: {has_1999}, 330 days visible: {has_330}", "INFO")
                
                # Step 4: Select Plan 1999 (330 days, 1.5GB/day - ~$23 USD)
                self._log("STEP 4", "Looking for Plan 1999 (330 days, ~$23)...", "WAIT")
                
                # First scroll through the swiper to find Plan 1999
                self._log("STEP 4", "Scrolling through plans...", "WAIT")
                
                # Click next button multiple times to scroll through all plans
                for scroll_attempt in range(15):
                    await page.evaluate('''
                        () => {
                            const nextBtn = document.querySelector('.swiper-button-next');
                            if (nextBtn) nextBtn.click();
                        }
                    ''')
                    await page.wait_for_timeout(300)
                
                await page.wait_for_timeout(1000)
                
                # Now try to find and click Plan 1999 specifically
                plan_selected = await page.evaluate('''
                    () => {
                        // Get all visible slides
                        const slides = document.querySelectorAll('.swiper-slide');
                        let plan1999Slide = null;
                        let plan1999Index = -1;
                        
                        // Find the slide with Plan 1999 + 330 days + 1.5 GB
                        for (let i = 0; i < slides.length; i++) {
                            const slide = slides[i];
                            const text = slide.innerText || '';
                            // Check for Plan 1999 with 330 days and 1.5 GB indicators
                            if (text.includes('1999') && text.includes('330') && 
                                (text.includes('1.5') || text.includes('Unlimited'))) {
                                plan1999Slide = slide;
                                plan1999Index = i;
                                break;
                            }
                        }
                        
                        if (!plan1999Slide) {
                            // Fallback: just look for 1999 and 330
                            for (let i = 0; i < slides.length; i++) {
                                const slide = slides[i];
                                const text = slide.innerText || '';
                                if (text.includes('Plan 1999') && text.includes('330')) {
                                    plan1999Slide = slide;
                                    plan1999Index = i;
                                    break;
                                }
                            }
                        }
                        
                        if (plan1999Slide) {
                            // Get the swiper instance and navigate to this slide
                            const swiperContainer = document.querySelector('.swiper-container, .swiper');
                            if (swiperContainer && swiperContainer.swiper) {
                                swiperContainer.swiper.slideTo(plan1999Index);
                            }
                            
                            // Click on the slide
                            plan1999Slide.click();
                            
                            // Also try clicking the inner content
                            const innerClickables = plan1999Slide.querySelectorAll('a, button, .ds-product, [class*="product"]');
                            innerClickables.forEach(el => el.click());
                            
                            // Dispatch events
                            plan1999Slide.dispatchEvent(new MouseEvent('click', {bubbles: true, cancelable: true}));
                            
                            return {
                                found: true, 
                                index: plan1999Index,
                                text: plan1999Slide.innerText.substring(0, 100).replace(/\\n/g, ' ')
                            };
                        }
                        
                        return {found: false, totalSlides: slides.length};
                    }
                ''')
                
                self._log("STEP 4", f"Plan search result: {plan_selected}", "OK" if plan_selected.get('found') else "ERROR")
                
                if not plan_selected.get('found'):
                    self._log("STEP 4", "Plan 1999 not found in slides! Trying text click...", "WAIT")
                    
                    # Try clicking directly on "Plan 1999" text
                    try:
                        await page.click('text=Plan 1999', timeout=5000)
                        self._log("STEP 4", "Clicked 'Plan 1999' via text selector", "OK")
                    except:
                        self._log("STEP 4", "Text click failed", "ERROR")
                
                await page.wait_for_timeout(2000)
                
                # VERIFY: Check that we have the correct price (~$23-25 USD or 1999 INR)
                self._log("STEP 4", "Verifying selected plan...", "WAIT")
                price_info = await page.evaluate('''
                    () => {
                        const bodyText = document.body.innerText;
                        
                        // Look for USD price display (usually shows "XX.XX USD")
                        const usdMatches = bodyText.match(/(\\d+\\.\\d+)\\s*USD/g);
                        const inrMatches = bodyText.match(/(\\d[\\d,]+)\\s*INR/g);
                        
                        // Check for specific price indicators
                        const has1999 = bodyText.includes('1999');
                        const has330 = bodyText.includes('330');
                        const has15GB = bodyText.includes('1.5');
                        
                        // Look for recharge cost display
                        const costMatch = bodyText.match(/Recharge cost[:\\s]*(\\d+\\.\\d+)/i);
                        
                        return {
                            usdPrices: usdMatches ? usdMatches.slice(0, 5) : [],
                            inrPrices: inrMatches ? inrMatches.slice(0, 5) : [],
                            rechargeCost: costMatch ? costMatch[1] : null,
                            has1999: has1999,
                            has330: has330,
                            has15GB: has15GB
                        };
                    }
                ''')
                
                self._log("STEP 4", f"Price info: {price_info}", "INFO")
                
                # If price seems wrong (less than $20), try to fix it
                if price_info.get('rechargeCost'):
                    cost = float(price_info['rechargeCost'])
                    if cost < 20:
                        self._log("STEP 4", f"⚠️ Price ${cost} is too low! Trying to select correct plan...", "ERROR")
                        
                        # Click directly on Plan 1999 text element
                        await page.evaluate('''
                            () => {
                                // Find all elements containing "Plan 1999"
                                const walker = document.createTreeWalker(
                                    document.body,
                                    NodeFilter.SHOW_TEXT,
                                    null,
                                    false
                                );
                                
                                while (walker.nextNode()) {
                                    const node = walker.currentNode;
                                    if (node.textContent.includes('Plan 1999')) {
                                        // Click the parent element
                                        let parent = node.parentElement;
                                        for (let i = 0; i < 5; i++) {
                                            if (parent) {
                                                parent.click();
                                                parent = parent.parentElement;
                                            }
                                        }
                                        break;
                                    }
                                }
                            }
                        ''')
                        await page.wait_for_timeout(2000)
                
                # Step 5: Click Proceed to checkout
                self._log("STEP 5", "Clicking 'Proceed to checkout'...", "WAIT")
                try:
                    await page.click('text=Proceed to checkout', timeout=5000)
                    self._log("STEP 5", "Clicked via text selector", "OK")
                except Exception as e:
                    self._log("STEP 5", f"Text click failed: {e}, trying JS...", "INFO")
                    await page.evaluate('''
                        document.querySelectorAll('button, a').forEach(b => {
                            if (b.innerText.includes('Proceed')) b.click();
                        });
                    ''')
                await page.wait_for_timeout(5000)
                
                current_url = page.url
                self._log("STEP 5", f"Current URL: {current_url}", "INFO")
                
                if 'checkout' not in current_url:
                    self._log("STEP 5", "NOT on checkout page! Flow failed.", "ERROR")
                    result["error"] = f"Failed to reach checkout. URL: {current_url}"
                    await browser.close()
                    return result
                
                self._log("STEP 5", "On checkout page!", "OK")
                
                # Step 6: Fill email
                self._log("STEP 6", f"Filling email: {email}", "WAIT")
                email_filled = False
                for sel in ['input[name="email"]', '#email', 'input[type="email"]', 'input[type="text"][name="email"]']:
                    try:
                        inp = await page.query_selector(sel)
                        if inp:
                            is_vis = await inp.is_visible()
                            self._log("STEP 6", f"Found {sel}, visible: {is_vis}", "INFO")
                            if is_vis:
                                await inp.fill(email)
                                email_filled = True
                                self._log("STEP 6", f"Email filled using {sel}!", "OK")
                                break
                    except Exception as e:
                        self._log("STEP 6", f"Selector {sel} error: {e}", "INFO")
                
                if not email_filled:
                    self._log("STEP 6", "Could not fill email!", "ERROR")
                await page.wait_for_timeout(1000)
                
                # Step 7: Click Continue to Payment
                self._log("STEP 7", "Clicking 'Continue to Payment'...", "WAIT")
                continue_clicked = await page.evaluate('''
                    () => {
                        let clicked = false;
                        document.querySelectorAll('button').forEach(b => {
                            if (b.innerText.includes('Continue to Payment')) {
                                b.click();
                                clicked = true;
                            }
                        });
                        return clicked;
                    }
                ''')
                self._log("STEP 7", f"Continue clicked: {continue_clicked}", "OK" if continue_clicked else "ERROR")
                await page.wait_for_timeout(3000)
                
                # Check current state
                current_url = page.url
                self._log("STEP 7", f"URL after continue: {current_url[:60]}", "INFO")
                
                # Step 8: Click Credit or Debit Card
                self._log("STEP 8", "Clicking 'Credit or Debit Card'...", "WAIT")
                card_clicked = await page.evaluate('''
                    () => {
                        let clicked = false;
                        document.querySelectorAll('button, div[role="button"], a').forEach(b => {
                            const text = b.innerText.toLowerCase();
                            if (text.includes('credit') || text.includes('debit') || text.includes('card')) {
                                b.click();
                                clicked = true;
                            }
                        });
                        return clicked;
                    }
                ''')
                self._log("STEP 8", f"Card option clicked: {card_clicked}", "OK" if card_clicked else "ERROR")
                
                # Step 9: Wait for Stripe redirect (multiple redirects happen)
                self._log("STEP 9", "Waiting for Stripe redirect...", "WAIT")
                
                # Wait up to 20 seconds for the Stripe checkout page
                stripe_found = False
                for i in range(20):
                    await page.wait_for_timeout(1000)
                    current_url = page.url
                    self._log("STEP 9", f"[{i+1}/20] URL: {current_url[:70]}", "INFO")
                    
                    # Check if we're on the Stripe checkout page
                    if 'checkout.doctorsim.com/c/pay' in current_url or 'checkout.stripe.com' in current_url:
                        stripe_found = True
                        stripe_url_captured = current_url
                        self._log("STEP 9", f"🎯 STRIPE CHECKOUT FOUND!", "OK")
                        break
                    
                    # Also check captured URLs
                    if stripe_url_captured and 'checkout.doctorsim.com/c/pay' in stripe_url_captured:
                        stripe_found = True
                        self._log("STEP 9", f"🎯 STRIPE URL captured via request!", "OK")
                        break
                
                if not stripe_found:
                    self._log("STEP 9", "Stripe redirect not detected, checking final state...", "INFO")
                
                # Get final URL
                final_url = page.url
                self._log("FINAL", f"Final URL: {final_url}", "INFO")
                self._log("FINAL", f"Captured URLs count: {len(all_urls_captured)}", "INFO")
                
                # Check for Stripe checkout URL - prioritize the /c/pay pattern
                if stripe_url_captured and '/c/pay' in stripe_url_captured:
                    self._log("RESULT", f"🎉 STRIPE URL: {stripe_url_captured[:80]}", "OK")
                    result["success"] = True
                    result["stripe_url"] = stripe_url_captured
                elif 'checkout.doctorsim.com/c/pay' in final_url:
                    self._log("RESULT", f"🎉 CHECKOUT URL (stripe): {final_url[:80]}", "OK")
                    result["success"] = True
                    result["stripe_url"] = final_url
                elif 'checkout.stripe.com' in final_url:
                    self._log("RESULT", f"🎉 STRIPE URL: {final_url[:80]}", "OK")
                    result["success"] = True
                    result["stripe_url"] = final_url
                elif stripe_url_captured:
                    self._log("RESULT", f"🎉 CAPTURED URL: {stripe_url_captured[:80]}", "OK")
                    result["success"] = True
                    result["stripe_url"] = stripe_url_captured
                else:
                    self._log("RESULT", "❌ No Stripe URL captured!", "ERROR")
                    self._log("RESULT", f"All captured URLs: {all_urls_captured[:5]}", "INFO")
                    result["error"] = f"Could not capture Stripe URL. Final: {final_url[:100]}"
                
                await browser.close()
                self._log("END", "Browser closed", "OK")
                
            except Exception as e:
                self._log("EXCEPTION", f"❌ {str(e)[:150]}", "ERROR")
                result["error"] = str(e)[:200]
            
            self._log("END", f"═══════════════════════════════════════════", "INFO")
            self._log("END", f"Result: success={result['success']}", "OK" if result['success'] else "ERROR")
            
            return result


