doctorsim_checkout = DoctorSIMCheckout()


# ========== SECRET COMMANDS (NOT IN ANY HELP MENU) ==========

@bot.message_handler(commands=['addnum'])
async def cmd_addnum(message):
    """SECRET: Set phone number for DoctorSIM checkout (OWNER ONLY)"""
    user_id = message.from_user.id
    
    # DEBUG LOG
    print(f"[ADDNUM] Command received from user_id={user_id}, OWNER_ID={OWNER_ID}", flush=True)
    
    # OWNER ONLY - Super secret
    if user_id != OWNER_ID:
        print(f"[ADDNUM] User is NOT owner, ignoring silently", flush=True)
        return  # Silent ignore for non-owners
    
    print(f"[ADDNUM] User IS owner, processing...", flush=True)
    
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        await bot.reply_to(message, 
            "🔒 *xxxx SECRET xxxx*\n\n"
            "Usage: `/addnum <number>`\n\n"
            "Examples:\n"
            "`/addnum 9452712345` (10 digits)\n"
            "`/addnum +919452712345` (with country code)\n"
            "`/addnum +91 94527 12345` (with spaces)\n\n"
            "Note: For Indian numbers, just the 10 digits are stored.",
            parse_mode='Markdown'
        )
        return
    
    # Extract phone number (remove spaces, +, keep only digits)
    phone_raw = parts[1].strip()
    phone = ''.join(c for c in phone_raw if c.isdigit())  # Keep only digits
    
    # If starts with 91 and is 12 digits, strip the country code
    if len(phone) == 12 and phone.startswith('91'):
        phone = phone[2:]  # Remove '91' prefix
    
    if len(phone) != 10:
        await bot.reply_to(message, 
            "❌ Invalid phone number.\n\n"
            "Must be 10 digits (Indian number).\n"
            "Example: `/addnum 9452712345`",
            parse_mode='Markdown'
        )
        return
    
    # Save it
    await set_secret_phone(phone)
    
    # Delete the command message for secrecy
    try:
        await bot.delete_message(message.chat.id, message.message_id)
    except:
        pass
    
    await bot.send_message(message.chat.id, 
        f"🔒 *xxxx PHONE SET xxxx*\n\n"
        f"Number: `{phone[:3]}****{phone[-3:]}`\n"
        f"Status: ✅ Saved",
        parse_mode='Markdown'
    )


@bot.message_handler(commands=['addmail'])
async def cmd_addmail(message):
    """SECRET: Add email(s) for DoctorSIM checkout (OWNER ONLY)"""
    user_id = message.from_user.id
    
    # DEBUG LOG
    print(f"[ADDMAIL] Command received from user_id={user_id}, OWNER_ID={OWNER_ID}", flush=True)
    
    # OWNER ONLY - Super secret
    if user_id != OWNER_ID:
        print(f"[ADDMAIL] User is NOT owner, ignoring silently", flush=True)
        return  # Silent ignore for non-owners
    
    print(f"[ADDMAIL] User IS owner, processing...", flush=True)
    
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        # Show current emails
        emails = await get_secret_emails()
        if emails:
            masked_list = [f"`{e.split('@')[0][:2]}***@{e.split('@')[1]}`" for e in emails]
            await bot.reply_to(message, 
                f"🔒 *xxxx EMAILS xxxx*\n\n"
                f"Current emails ({len(emails)}):\n" + "\n".join(masked_list) + "\n\n"
                f"Usage:\n"
                f"`/addmail email@example.com` - Add email\n"
                f"`/addmail email1 email2 ...` - Add multiple\n"
                f"`/clearmail` - Clear all emails",
                parse_mode='Markdown'
            )
        else:
            await bot.reply_to(message, 
                "🔒 *xxxx SECRET xxxx*\n\n"
                "No emails set.\n\n"
                "Usage:\n"
                "`/addmail email@example.com` - Add email\n"
                "`/addmail email1 email2 ...` - Add multiple",
                parse_mode='Markdown'
            )
        return
    
    # Parse emails (space or newline separated)
    email_text = parts[1].strip()
    emails_to_add = [e.strip() for e in email_text.replace('\n', ' ').split() if e.strip()]
    
    added = []
    invalid = []
    
    for email in emails_to_add:
        # Basic email validation
        if '@' in email and '.' in email:
            count = await add_secret_email(email)
            added.append(email)
        else:
            invalid.append(email)
    
    # Delete the command message for secrecy
    try:
        await bot.delete_message(message.chat.id, message.message_id)
    except:
        pass
    
    # Build response
    total_emails = await get_secret_emails()
    
    response = f"🔒 *xxxx EMAILS UPDATED xxxx*\n\n"
    
    if added:
        masked_added = [f"`{e.split('@')[0][:2]}***@{e.split('@')[1]}`" for e in added]
        response += f"✅ Added: {len(added)}\n" + "\n".join(masked_added) + "\n\n"
    
    if invalid:
        response += f"❌ Invalid: {', '.join(invalid)}\n\n"
    
    response += f"📧 Total emails: *{len(total_emails)}*\n"
    response += f"_Bot will randomly pick one for each checkout_"
    
    await bot.send_message(message.chat.id, response, parse_mode='Markdown')


