@bot.message_handler(commands=['sendch'])
async def cmd_sendch(message):
    """Generate Stripe checkout URL from DoctorSIM"""
    user_id = message.from_user.id
    username = message.from_user.username
    
    # DEBUG LOG
    print(f"[SENDCH] Command received from user_id={user_id} (@{username})", flush=True)
    
    # Anyone can use this command (approved users)
    is_approved = await is_user_approved(user_id)
    print(f"[SENDCH] User approved: {is_approved}", flush=True)
    
    if not is_approved:
        print(f"[SENDCH] User NOT approved, sending error", flush=True)
        await bot.reply_to(message, "❌ Use /register first.")
        return
    
    # Get secret phone and random email
    phone = await get_secret_phone()
    email = await get_random_secret_email()  # Random from list
    emails_list = await get_secret_emails()
    
    print(f"[SENDCH] Phone set: {bool(phone)}, Emails available: {len(emails_list)}", flush=True)
    if email:
        print(f"[SENDCH] Selected email: {email}", flush=True)
    
    if not phone or not email:
        print(f"[SENDCH] Phone or email not configured!", flush=True)
        # Only owner sees this message
        if user_id == OWNER_ID:
            await bot.reply_to(message, 
                "❌ *Setup Required*\n\n"
                "Use these secret commands first:\n"
                "`/addnum +91 phonenumber`\n"
                "`/addmail email@example.com`\n\n"
                "_You can add multiple emails - bot picks randomly_",
                parse_mode='Markdown'
            )
        else:
            await bot.reply_to(message, "❌ Service not configured. Contact admin.")
        return
    
    # Send status message
    status_msg = await bot.reply_to(message, 
        "💳 *Generating Stripe Checkout...*\n\n"
        "⏳ Please wait, this may take 30-60 seconds...",
        parse_mode='Markdown'
    )
    
    try:
        # Run the checkout automation with user's proxy
        result = await doctorsim_checkout.get_stripe_checkout(phone, email, user_id)
        
        if result["success"] and result["stripe_url"]:
            stripe_url = result["stripe_url"]
            
            # Success message with the URL
            await bot.edit_message_text(
                f"💳 *STRIPE CHECKOUT READY*\n"
                f"{'━' * 30}\n\n"
                f"🔗 *Click to pay:*\n"
                f"`{stripe_url}`\n\n"
                f"📱 Plan: *BSNL 1999 (330 Days)*\n"
                f"✅ Unlimited Voice + Data\n\n"
                f"⚠️ Link expires in ~30 minutes",
                message.chat.id, status_msg.message_id,
                parse_mode='Markdown'
            )
            
            # Notify owner (if user is not owner)
            await notify_owner_sendch(user_id, username, email, True, stripe_url)
        else:
            error_msg = result.get("error", "Unknown error")
            await bot.edit_message_text(
                f"❌ *Checkout Failed*\n\n"
                f"Error: `{error_msg[:150]}`\n\n"
                f"Try again or contact admin.",
                message.chat.id, status_msg.message_id,
                parse_mode='Markdown'
            )
            
            # Notify owner of failure too
            await notify_owner_sendch(user_id, username, email, False)
            
    except Exception as e:
        await bot.edit_message_text(
            f"❌ *Error*: `{str(e)[:150]}`",
            message.chat.id, status_msg.message_id,
            parse_mode='Markdown'
        )
        
        # Notify owner of exception
        await notify_owner_sendch(user_id, username, email, False)


# ==================== BRAINTREE DONATION CHECKERS ====================

@bot.message_handler(commands=['earthjustice'])
async def cmd_earthjustice(message):
    """Check cards on Earthjustice donation site"""
    print(f"[DEBUG] Received /earthjustice command from {message.from_user.id}", flush=True)
    try:
        user_id = message.from_user.id
        
        if not await is_user_approved(user_id):
            print(f"[DEBUG] User {user_id} not approved", flush=True)
            await safe_reply(message, "❌ *Access Denied*\nPlease use /register first.", parse_mode='Markdown')
            return
        
        # Check if already running
        if await count_user_jobs(user_id, gateway="earthjustice") > 0:
            await safe_reply(message, "⚠️ Earthjustice check already running. Use /stop to stop it.", parse_mode="Markdown")
            return
        
        # Get cards
        cards = await get_user_cards(user_id)
        if not cards:
            await safe_reply(message, "⚠️ *No cards found.*\nJust paste cards in format `CC|MM|YY|CVV`", parse_mode='Markdown')
            return
        
        # Instant response
        await safe_reply(message, "🚀 *Starting Earthjustice Braintree check...*", parse_mode='Markdown')
        
        # Launch in background
        async def _runner(cancel_event: asyncio.Event, job_id: str):
            await process_braintree_cards(user_id, message.chat.id, "earthjustice", cards, cancel_event, job_id)
        
        await start_check_job(user_id=user_id, chat_id=message.chat.id, gateway="earthjustice", runner=_runner)
        
    except Exception as e:
        print(f"[ERROR] /earthjustice: {e}", flush=True)
        await safe_reply(message, f"❌ Error: {str(e)}", parse_mode=None)


