@bot.message_handler(commands=['health'])
async def cmd_health(message):
    """Owner-only health page: DB, queues, hit rates, alerts."""
    if message.from_user.id != OWNER_ID or message.chat.type != "private":
        return

    db_ok = False
    db_latency_ms = None
    hits_total = hits_24h = hits_1h = 0
    cards_total = 0
    try:
        if USE_DATABASE and db_pool:
            t0 = time.time()
            async with db_pool.acquire(timeout=5) as conn:
                await conn.fetchval("SELECT 1")
                hits_total = int(await conn.fetchval("SELECT COUNT(*) FROM hits") or 0)
                hits_1h = int(await conn.fetchval("SELECT COUNT(*) FROM hits WHERE created_at >= NOW() - INTERVAL '1 hour'") or 0)
                hits_24h = int(await conn.fetchval("SELECT COUNT(*) FROM hits WHERE created_at >= NOW() - INTERVAL '24 hours'") or 0)
                cards_total = int(await conn.fetchval("SELECT COUNT(*) FROM cards") or 0)
            db_latency_ms = int((time.time() - t0) * 1000)
            db_ok = True
    except Exception as e:
        record_event("db_error", f"health_ping:{str(e)[:120]}")

    # Jobs
    try:
        async with JOBS_LOCK:
            active_users = len(JOBS_BY_USER)
            active_jobs = sum(len(v) for v in JOBS_BY_USER.values())
    except Exception:
        active_users = 0
        active_jobs = 0

    # Window counts
    def _count(kind: str) -> int:
        dq = _EVENT_COUNTS.get(kind) or deque()
        cutoff = time.time() - EVENT_WINDOW_SECONDS
        while dq and dq[0] < cutoff:
            dq.popleft()
        return len(dq)

    tg_429 = _count("tg_429")
    db_err = _count("db_error")
    chk_err = _count("checker_error")

    msg = f"""🩺 *HEALTH*
━━━━━━━━━━━━━━━━━━
• DB: *{'OK' if db_ok else 'DOWN'}*{f" ({db_latency_ms}ms)" if db_latency_ms is not None else ""}
• Active jobs: *{active_jobs}* (users: {active_users})
• Cards queued (DB): *{cards_total}*

📈 *Hits*
• Total: *{hits_total}*
• Last 1h: *{hits_1h}*
• Last 24h: *{hits_24h}*

⚠️ *Last {EVENT_WINDOW_SECONDS}s*
• TG 429: *{tg_429}*
• DB errors: *{db_err}*
• Checker errors: *{chk_err}*
"""
    await safe_reply(message, msg, parse_mode="Markdown")


@bot.message_handler(commands=['errors'])
async def cmd_errors(message):
    """Owner-only: show recent operational events."""
    if message.from_user.id != OWNER_ID or message.chat.type != "private":
        return
    items = list(_EVENT_LOG)[-25:]
    if not items:
        await safe_reply(message, "No events recorded yet.")
        return
    lines = []
    for e in items:
        ts = datetime.fromtimestamp(e["ts"]).strftime("%H:%M:%S")
        lines.append(f"{ts} | {e.get('kind')} | {e.get('msg')}")
    text = "🧾 *RECENT EVENTS*\n━━━━━━━━━━━━━━━━━━\n" + "\n".join(lines)
    if len(text) > 4000:
        buf = io.BytesIO(text.encode("utf-8"))
        buf.name = "events.txt"
        await tg_send_document(message.chat.id, buf, caption="🧾 Recent events", parse_mode="Markdown")
        return
    await safe_reply(message, text, parse_mode="Markdown")


@bot.message_handler(commands=['searchhits'])
async def cmd_searchhits(message):
    """
    Search hits with filters.
    Owner can search all users; normal users search only their own hits.
    Examples:
      /searchhits 424242
      /searchhits gateway=shopify status=CHARGED bin=424242 country=US bank=Chase limit=50
      /searchhits user=1234567890 since=2025-12-01 until=2025-12-17 status=APPROVED
    """
    uid = message.from_user.id
    if not await is_user_approved(uid):
        return
    if not USE_DATABASE:
        await safe_reply(message, "⚠️ Search requires database mode (DATABASE_URL).")
        return

    raw = message.text.split(maxsplit=1)
    args_text = raw[1] if len(raw) > 1 else ""
    kv, free = _parse_kv_tokens(args_text)

    target_user = None
    if uid == OWNER_ID:
        for k in ["user", "uid", "user_id"]:
            if kv.get(k):
                try:
                    target_user = int(kv.get(k))
                except Exception:
                    target_user = None
                break

    gateway = kv.get("gateway")
    status = kv.get("status") or kv.get("result")
    bin6 = kv.get("bin") or kv.get("bin6")
    country = kv.get("country")
    bank = kv.get("bank")
    since = _parse_dt(kv.get("since") or kv.get("from"))
    until = _parse_dt(kv.get("until") or kv.get("to"))
    q = kv.get("q") or free
    try:
        limit = int(kv.get("limit") or "25")
    except Exception:
        limit = 25
    limit = max(1, min(200, limit))

    rows = await db_search_hits(
        requester_id=uid,
        target_user_id=target_user,
        gateway=gateway,
        result=status,
        bin6=bin6,
        bank=bank,
        country=country,
        q=q,
        since=since,
        until=until,
        limit=limit,
    )
    if not rows:
        await safe_reply(message, "📭 No hits found for that search.")
        return

    # Render compact results
    lines = []
    for r in rows:
        ts = r.get("created_at")
        ts_str = ts.strftime("%Y-%m-%d %H:%M") if hasattr(ts, "strftime") else str(ts)
        lines.append(f"{ts_str} | {(r.get('gateway') or '').upper()} | {(r.get('result') or '').upper()} | {r.get('card_data') or ''}")
    text = f"🔎 *SEARCH RESULTS* ({len(rows)})\n━━━━━━━━━━━━━━━━━━\n" + "\n".join(lines)
    if len(text) > 3800:
        buf = io.BytesIO(("\n".join(lines)).encode("utf-8"))
        buf.name = "search_results.txt"
        await tg_send_document(message.chat.id, buf, caption=f"🔎 Search results ({len(rows)})", parse_mode="Markdown")
        return
    await safe_reply(message, text, parse_mode="Markdown")


@bot.message_handler(commands=['exporthits'])
async def cmd_exporthits(message):
    """
    Owner-only export with filters + formats.
    Examples:
      /exporthits since=2025-12-01 until=2025-12-17 format=csv
      /exporthits gateway=shopify status=CHARGED format=json
      /exporthits user=123456 status=APPROVED format=txt
    """
    if message.from_user.id != OWNER_ID or message.chat.type != "private":
        return
    if not USE_DATABASE:
        await safe_reply(message, "⚠️ Export requires database mode (DATABASE_URL).")
        return

    raw = message.text.split(maxsplit=1)
    args_text = raw[1] if len(raw) > 1 else ""
    kv, free = _parse_kv_tokens(args_text)

    target_user = None
    for k in ["user", "uid", "user_id"]:
        if kv.get(k):
            try:
                target_user = int(kv.get(k))
            except Exception:
                target_user = None
            break

    gateway = kv.get("gateway")
    status = kv.get("status") or kv.get("result")
    bin6 = kv.get("bin") or kv.get("bin6")
    country = kv.get("country")
    bank = kv.get("bank")
    since = _parse_dt(kv.get("since") or kv.get("from"))
    until = _parse_dt(kv.get("until") or kv.get("to"))
    q = kv.get("q") or free
    fmt = (kv.get("format") or kv.get("fmt") or "txt").lower()
    if fmt not in ["txt", "csv", "json"]:
        fmt = "txt"
    try:
        limit = int(kv.get("limit") or "50000")
    except Exception:
        limit = 50000
    limit = max(1, min(50000, limit))

    await safe_reply(message, "📤 Building export...", parse_mode=None)
    rows = await db_search_hits(
        requester_id=OWNER_ID,
        target_user_id=target_user,
        gateway=gateway,
        result=status,
        bin6=bin6,
        bank=bank,
        country=country,
        q=q,
        since=since,
        until=until,
        limit=limit,
    )
    if not rows:
        await safe_reply(message, "📭 No hits found for that export.")
        return

    buf, name = await build_export_file(rows, fmt)
    caption = f"📁 *Hits Export*\n• Rows: *{len(rows)}*\n• File: `{name}`"
    await tg_send_document(message.chat.id, buf, caption=caption, parse_mode="Markdown")


